window.__ARXIV_DATA__ = {"papers":[{"id":"2606.02580v1","title":"Thinking in Blender: Staged Executable Inverse Graphics with Vision-Language Models","abstract":"Inverse graphics is a longstanding and highly underconstrained problem that seeks to reconstruct images as editable 3D scenes which can be rendered, relit, and manipulated. In this work, we investigate whether pretrained vision-language models (VLMs) can perform executable inverse graphics directly from a single image by reconstructing a scene as an editable Blender program, without relying on specialized 2D or 3D foundation models, differentiable rendering, or multi-view supervision. We introduce Staged Executable Inverse Graphics (SEIG), an agentic framework that reconstructs a 3D scene from a single image by progressively refining scene factors including geometry, materials, composition, and lighting directly in executable Blender code space. We evaluate our framework across diverse scenes using a range of reconstruction metrics spanning pixel-level, perceptual, and semantic fidelity. Our experiments show that staged reconstruction substantially improves reconstruction fidelity, highlighting the importance of task decomposition for executable inverse graphics with general-purpose VLMs. Finally, we showcase various downstream applications enabled by the reconstructed editable Blender scenes.","authors":["Guangzhao He","Rundong Luo","Wei-Chiu Ma","Hadar Averbuch-Elor"],"published":"2026-06-01T17:59:53Z","updated":"2026-06-01T17:59:53Z","abstract_url":"https://arxiv.org/abs/2606.02580v1","html_url":"https://arxiv.org/html/2606.02580v1","pdf_url":"https://arxiv.org/pdf/2606.02580v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":50340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：Inverse graphics is a longstanding and highly underconstrained problem that seeks to reconstruct images as editable 3D scenes which can be rendered, relit, and manipulated. In this work, we investigate whether pretrained vision-language models (VLMs) can perf...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02578v1","title":"Mitigating Perceptual Judgment Bias in Multimodal LLM-as-a-Judge via Perceptual Perturbation and Reward Modeling","abstract":"Recent multimodal large language models have demonstrated strong reasoning ability, yet their reliability as automated evaluators remains limited by a critical weakness: when visual evidence conflicts with textual cues, MLLM judges tend to reward plausible narratives over perceptually correct answers. We identify and systematically analyze this phenomenon, which we term Perceptual Judgment Bias. Through controlled visual perturbations, existing multimodal judges frequently anchor on the response text instead of their own visual perception, leading to inconsistent and non-verifiable evaluations. To address this issue, we introduce the Perceptually Perturbed Judgment Dataset, which constructs minimally edited counterfactual responses that isolate perceptual errors and enable verifiable supervision. Building on this dataset, we develop a unified training framework that combines a structured GRPO-based reward with a batch-ranking objective, achieving coherent global ordering without explicit pairwise labels. Experiments across diverse MLLM-as-a-Judge benchmarks show that our approach substantially improves perceptual fidelity, ranking coherence, and alignment with human evaluation. Our results establish a scalable and generalizable pathway for training multimodal judges that are perceptually grounded, interpretable, and robust to visual-reasoning conflicts.","authors":["Seojeong Park","Jiho Choi","Junyong Kang","Seonho Lee","Jaeyo Shin","Hyunjung Shim"],"published":"2026-06-01T17:59:46Z","updated":"2026-06-01T17:59:46Z","abstract_url":"https://arxiv.org/abs/2606.02578v1","html_url":"https://arxiv.org/html/2606.02578v1","pdf_url":"https://arxiv.org/pdf/2606.02578v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":134958,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Recent multimodal large language models have demonstrated strong reasoning ability, yet their reliability as automated evaluators remains limited by a critical weakness: when visual evidence conflicts with textual cues, MLLM judges tend to reward plausible na...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02577v1","title":"RoboDream: Compositional World Models for Scalable Robot Data Synthesis","abstract":"Scaling robot learning requires large-scale, diverse demonstrations, yet real-world data collection via teleoperation remains prohibitively expensive and time-consuming. While video diffusion models offer a promising avenue for data scaling, existing generative approaches are often limited to superficial visual augmentation, or suffer from embodiment hallucinations that yield physically infeasible motions. We present a generalizable embodiment-centric world model that achieves scalable data generation by synthesizing photorealistic demonstrations with novel objects, in novel scenes, and from novel viewpoints. Our approach anchors generation to rendered robot motion while conditioning on explicit scene and object priors, effectively decoupling trajectory execution from environment synthesis. This formulation has the potential to unlock two powerful data scaling capabilities: (1) retrieval and rebirth, which repurposes existing trajectories into entirely new contexts without new motion data; and (2) prop-free teleoperation, where operators manipulate empty air and the model hallucinates the target objects and scene afterwards, eliminating reset time. We demonstrate with real-world experiments that our generated data consistently improves downstream policy performance and significantly reduces real-world data requirements across diverse manipulation tasks.","authors":["Junjie Ye","Rong Xue","Basile Van Hoorick","Runhao Li","Harshitha Rajaprakash","Pavel Tokmakov","Muhammad Zubair Irshad","Vitor Guizilini","Yue Wang"],"published":"2026-06-01T17:59:38Z","updated":"2026-06-01T17:59:38Z","abstract_url":"https://arxiv.org/abs/2606.02577v1","html_url":"https://arxiv.org/html/2606.02577v1","pdf_url":"https://arxiv.org/pdf/2606.02577v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"html","source_text_chars":43165,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, diffusion 相关；摘要显示其主要贡献为：Scaling robot learning requires large-scale, diverse demonstrations, yet real-world data collection via teleoperation remains prohibitively expensive and time-consuming. While video diffusion models offer a promising avenue for data scaling, existing generati...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02576v1","title":"ProtoAda: Prototype-Guided Adaptive Adapter Expansion and Geometric Consolidation for Multimodal Continual Instruction Tuning","abstract":"Multimodal Large Language Models (MLLMs) achieve strong performance through instruction tuning, but real-world deployment requires them to continually acquire new vision-language capabilities, making Multimodal Continual Instruction Tuning (MCIT) essential. To reduce inter-task interference and promote collaboration, recent methods often employ sparse architectures like Mixture of LoRA Experts with image-text similarity routing. However, tasks with distinct response structures could share highly similar visual-linguistic semantics and thus be wrongly routed to the same expert; image-text similarity alone is insufficient for reliable task assignment. For example, an expert in a grounding task requiring coordinate prediction may be biased toward producing short textual answers after learning semantically similar VQA tasks. This format-blind task assignment integrates heterogeneous response types into shared parameters, inducing gradient interference and ineffective expert collaboration. To address this problem, we propose ProtoAda, a prototype-guided adaptive tuning framework. ProtoAda introduces format-aware task prototypes to align task assignment and routing with both task semantics and output structure, and further consolidates format-compatible updates in a geometry-aware manner to effectively reuse and progressively refine existing parameters. Extensive experiments on multiple benchmarks demonstrate that ProtoAda achieves superior performance, especially on tasks whose answer structures are easily corrupted by sequential tuning.","authors":["Yu-Cheng Shi","Zhen-Hao Xie","Jun-Tao Tang","Da-Wei Zhou"],"published":"2026-06-01T17:59:13Z","updated":"2026-06-01T17:59:13Z","abstract_url":"https://arxiv.org/abs/2606.02576v1","html_url":"https://arxiv.org/html/2606.02576v1","pdf_url":"https://arxiv.org/pdf/2606.02576v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":71635,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) achieve strong performance through instruction tuning, but real-world deployment requires them to continually acquire new vision-language capabilities, making Multimodal Continual Instruction Tuning (MCIT) essential. T...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02575v1","title":"From Zero to Hero: Training-Free Custom Concept Spawning in World Models","abstract":"Autoregressive world models have emerged as a powerful paradigm for interactive video generation, allowing users to navigate dynamically generated environments through actions. These models are typically conditioned on a text prompt and/or a single reference frame, from which the entire world is generated. Yet the moment the user navigates beyond what is visible in that frame, the unseen regions are populated by the base model's priors, with no mechanism for the user to specify what should appear and where. This is a fundamental limitation for applications such as gaming, interactive storytelling, and simulation, where controllable scene composition is essential. We refer to this missing capability as concept spawning; introducing a user-specified visual concept into a world model, analogous to spawning in a game engine. We introduce SPAWN (Swapping Pinned Anchor with Windowed iNjection), a training-free method for concept spawning. SPAWN exploits a structural property of image-to-video backbones: the first slot of the context memory is pinned to the reference frame and acts as a foundational anchor for every generated chunk. By swapping this anchor with an external concept latent over a short injection window and letting the original anchor return, we cause the concept to propagate naturally through the rollout via the model's own memory. SPAWN supports concepts from fine-grained entities such as characters and props to large-scale elements such as buildings and landmarks, and accepts either a concept image or a text description as input. Experiments show that SPAWN integrates concepts with consistent lighting, scale, and perspective while preserving identity and temporal coherence, demonstrating that controllable concept spawning is achievable in existing autoregressive world models without any training.","authors":["Kiymet Akdemir","Pinar Yanardag"],"published":"2026-06-01T17:59:05Z","updated":"2026-06-01T17:59:05Z","abstract_url":"https://arxiv.org/abs/2606.02575v1","html_url":"https://arxiv.org/html/2606.02575v1","pdf_url":"https://arxiv.org/pdf/2606.02575v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":49764,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Autoregressive world models have emerged as a powerful paradigm for interactive video generation, allowing users to navigate dynamically generated environments through actions. These models are typically conditioned on a text prompt and/or a single reference...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02573v1","title":"HumanNOVA: Photorealistic, Universal and Rapid 3D Human Avatar Modeling from a Single Image","abstract":"In this paper, we present HumanNOVA, a photorealistic, universal, and rapid model for generating 3D human avatars from a single RGB image. Achieving both photorealism and generalization is challenging due to the scarcity of diverse, high-quality 3D human data. To address this, we build a scalable data generation pipeline that follows two strategies. The first one is to leverage existing rigged assets and animate them with extensive poses from daily life. The second strategy is to utilize existing multi-camera captures of humans and employ fitting to generate more diverse views for training. These two strategies enable us to scale up to 100k assets, significantly enhancing both the quantity and the diversity of data for robust model training. In terms of the architecture, HumanNOVA adopts a feed-forward, token-conditioned avatar modeling framework that allows fast inference in less than one second and requires no test-time optimization. Given an input image and an estimated simplified human mesh (SMPL) without detailed geometry or appearance, the model first encodes both inputs into compact token representations. These tokens then act as conditioning signals and are fused through cross-attention to construct a triplane-based 3D avatar representation. Extensive experiments on multiple benchmarks demonstrate the superiority of our approach, both quantitatively and qualitatively, as well as its robustness under diverse input image conditions. Project page at https://HumanNOVA.github.io .","authors":["Hezhen Hu","Wangbo Zhao","Lanqing Guo","Hanwen Jiang","Jonathan C. Liu","Zhiwen Fan","Kai Wang","Zhangyang Wang","Georgios Pavlakos"],"published":"2026-06-01T17:58:11Z","updated":"2026-06-01T17:58:11Z","abstract_url":"https://arxiv.org/abs/2606.02573v1","html_url":"https://arxiv.org/html/2606.02573v1","pdf_url":"https://arxiv.org/pdf/2606.02573v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":68856,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：In this paper, we present HumanNOVA, a photorealistic, universal, and rapid model for generating 3D human avatars from a single RGB image. Achieving both photorealism and generalization is challenging due to the scarcity of diverse, high-quality 3D human data...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02569v1","title":"AdaCodec: A Predictive Visual Code for Video MLLMs","abstract":"Video is temporally redundant: adjacent frames usually share most objects, background, and layout. Yet existing video multimodal large language models (video MLLMs) usually encode each sampled frame as an independent RGB image, causing visual tokens to repeat content already present in earlier frames. This suggests a more direct video interface: send a full reference frame only when the scene cannot be predicted well from prior context, and otherwise transmit a compact description of inter-frame changes. We call this interface a \\emph{predictive visual code}, and instantiate it for video MLLMs as \\textbf{AdaCodec}. AdaCodec spends full visual tokens on a reference frame only when its conditional predictive cost is high; otherwise, it encodes inter-frame changes, including motion and prediction residuals, as compact P-tokens. Across all eleven benchmarks, AdaCodec improves over the Qwen3-VL-8B per-frame RGB baseline at a matched visual-token budget. Even at $1/7$ the budget, AdaCodec with 32k tokens surpasses the 224k baseline on all long-video benchmarks; on five general-video benchmarks, it raises the average score while substantially cutting time-to-first-token from 9.26s to 1.62s.","authors":["Haowen Hou","Zhen Huang","Zheming Liang","Qingyi Si","Chenglin Li","Shuai Dong","Kele Shao","Ruilin Li","Dianyi Wang","Nan Duan","Jiaqi Wang"],"published":"2026-06-01T17:56:35Z","updated":"2026-06-01T17:56:35Z","abstract_url":"https://arxiv.org/abs/2606.02569v1","html_url":"https://arxiv.org/html/2606.02569v1","pdf_url":"https://arxiv.org/pdf/2606.02569v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":91068,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Video is temporally redundant: adjacent frames usually share most objects, background, and layout. Yet existing video multimodal large language models (video MLLMs) usually encode each sampled frame as an independent RGB image, causing visual tokens to repeat...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02565v1","title":"Policy-based Foveated Imaging and Perception","abstract":"Ultra-high-resolution image sensors offer the potential to capture fine spatial details critical for many visual perception tasks, but acquiring and processing all pixels at full resolution is often infeasible under realistic bandwidth, latency, and power constraints. Existing approaches address this challenge through acquisition strategies such as spatial or temporal downsampling, which irrevocably discard information before task relevance can be assessed. In this work, we introduce a real-time, predictive, and task-aware foveated imaging system that operates directly at image acquisition time. Leveraging emerging dual-stream sensor architectures, our method dynamically allocates limited pixel bandwidth to task-relevant regions of interest while maintaining a low-resolution global context. We formulate foveated acquisition as a sensor attention policy-learning problem, in which past observations guide actions that determine future measurements, closing the perception-acquisition loop. Through extensive simulation across multiple perception tasks, we demonstrate that our approach achieves high task performance under strict pixel budgets and significantly outperforms relevant baselines operating at the same bandwidth. We further validate our system on a 200-megapixel dual-stream sensor, capturing real-world videos under realistic bandwidth and latency constraints, demonstrating the practical feasibility of task-driven, acquisition-time foveated imaging.","authors":["Howard Xiao","Jan Ackermann","Boyang Deng","Gordon Wetzstein"],"published":"2026-06-01T17:55:05Z","updated":"2026-06-01T17:55:05Z","abstract_url":"https://arxiv.org/abs/2606.02565v1","html_url":"https://arxiv.org/html/2606.02565v1","pdf_url":"https://arxiv.org/pdf/2606.02565v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":79223,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Ultra-high-resolution image sensors offer the potential to capture fine spatial details critical for many visual perception tasks, but acquiring and processing all pixels at full resolution is often infeasible under realistic bandwidth, latency, and power con...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02564v1","title":"VLMs are Good Teachers for Video Reasoning via Adaptive Test-Time Optimization","abstract":"The recent \"Reasoning with Video\" paradigm utilizes Video Generation Models (VGMs) to generate temporally coherent visual trajectories to complete reasoning tasks. Although state-of-the-art VGMs excel at visual quality, they often struggle to understand and follow task-specific rules, leading to logical failures across diverse reasoning scenarios. Existing efforts try to utilize Vision-Language Models (VLMs) as problem pre-solvers to produce or refine textual guidance for the VGM. However, textual descriptions fail to capture intricate spatiotemporal details, and VGMs often struggle to faithfully execute fine-grained or long-tail instructions even with a valid plan. While VLMs struggle as solvers, they possess strong perception capabilities to evaluate process-constraint satisfaction and final-goal achievement. Leveraging this strength, we introduce a paradigm shift that transitions the role of VLMs to \"teachers\". Specifically, a VLM teacher extracts task-specific rules to formulate differentiable rewards, guiding a VGM Reasoner via test-time online optimization of a lightweight LoRA module. This strategy enables adaptive test-time optimization and extends the reasoning capabilities beyond the VGM's intrinsic boundaries. Evaluations on symbolic (VBVR-Bench) and general-purpose (RULER-Bench) video reasoning benchmarks show that the proposed method yields a 16.7-point average performance gain, outperforming the VLM-as-Solver paradigm (+0.4 points) and Best-of-N scaling (+2.2 points) by a large margin at comparable test-time cost. These findings reveal that integrating VLMs as test-time teachers offers a promising paradigm for achieving generalizable video reasoning. Project Page: https://VLM-as-Teacher.github.io/","authors":["Junhao Cheng","Liang Hou","Tianxiong Zhong","Xin Tao","Pengfei Wan","Kun Gai","Jing Liao"],"published":"2026-06-01T17:54:26Z","updated":"2026-06-01T17:54:26Z","abstract_url":"https://arxiv.org/abs/2606.02564v1","html_url":"https://arxiv.org/html/2606.02564v1","pdf_url":"https://arxiv.org/pdf/2606.02564v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":68161,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：The recent \"Reasoning with Video\" paradigm utilizes Video Generation Models (VGMs) to generate temporally coherent visual trajectories to complete reasoning tasks. Although state-of-the-art VGMs excel at visual quality, they often struggle to understand and f...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02553v1","title":"LongLive-RAG: A General Retrieval-Augmented Framework for Long Video Generation","abstract":"Autoregressive (AR) video diffusion enables variable-length synthesis, but long-horizon generation often suffers from accumulated errors and identity drift. For efficiency, existing methods commonly adopt sliding-window attention during generation. This creates an irreversible generation trajectory: once the active window accumulates appearance errors, subsequent generations can only condition on this degraded trajectory and drift further away. We address this limitation by formulating long video generation as a retrieval-augmented generation (RAG) problem. Rather than relying solely on the recent window, we treat previously generated latents as a dynamic, searchable history. We propose LongLive-RAG, a general retrieval framework for AR video generation. At each new block, LongLive-RAG uses a query embedding to retrieve relevant historical latents. This lightweight retrieval step adds only a small overhead relative to generation and lets the generator condition on non-local context instead of only the recent window. To make retrieval more discriminative, we introduce the Window Temporal Delta Loss that suppresses redundant local similarity and encourages embeddings to capture meaningful temporal changes. Together, these components help reduce error accumulation caused by sliding-window attention. Experiments across multiple AR backbones and generation lengths show improved long-video quality and the best average VBench-Long rank. To our knowledge, among open-ended AR long video generation methods, LongLive-RAG is the first to formulate self-generated latent history as content-addressable retrieval memory. Code is available at https://github.com/qixinhu11/LongLive-RAG.","authors":["Qixin Hu","Shuai Yang","Wei Huang","Song Han","Yukang Chen"],"published":"2026-06-01T17:50:49Z","updated":"2026-06-01T17:50:49Z","abstract_url":"https://arxiv.org/abs/2606.02553v1","html_url":"https://arxiv.org/html/2606.02553v1","pdf_url":"https://arxiv.org/pdf/2606.02553v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"html","source_text_chars":65372,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, diffusion 相关；摘要显示其主要贡献为：Autoregressive (AR) video diffusion enables variable-length synthesis, but long-horizon generation often suffers from accumulated errors and identity drift. For efficiency, existing methods commonly adopt sliding-window attention during generation. This creat...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02552v1","title":"Modeling Depth Ambiguity: A Mixture-Density Representation for Flying-Point-Free Depth Estimation","abstract":"Despite advances in depth estimation, flying points remain a persistent failure mode: near object boundaries, depth estimators often predict spurious 3D points in the empty space between foreground and background surfaces. We trace this artifact to a standard modeling choice: assigning each pixel a single depth hypothesis. At boundaries, a pixel can straddle a foreground and a background surface, so its true depth is ambiguous between the two. A model that predicts a single depth cannot keep both possibilities, so training instead pulls the prediction toward an intermediate depth that lies on neither surface. We address this with MDA, a mixture-density representation that lets the model predict multiple depth hypotheses and their associated probabilities for each pixel. Near boundaries, different hypotheses can align with different surfaces, and the decoded depth is selected from one of these hypotheses rather than placed in the empty space between them. Across different backbones, MDA substantially improves boundary reconstruction and largely removes flying-point artifacts even under severe input blur, while adding negligible runtime overhead. The same mixture-density framework naturally extends to transparent objects, where it predicts multiple depth layers at transparent pixels, and to sky regions, where a dedicated component separates the unbounded sky from finite-depth regions, producing flying-point-free skylines. Project Page: https://biansy000.github.io/mda-site/.","authors":["Siyuan Bian","Congrong Xu","Jun Gao"],"published":"2026-06-01T17:50:28Z","updated":"2026-06-01T17:50:28Z","abstract_url":"https://arxiv.org/abs/2606.02552v1","html_url":"https://arxiv.org/html/2606.02552v1","pdf_url":"https://arxiv.org/pdf/2606.02552v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":91281,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Despite advances in depth estimation, flying points remain a persistent failure mode: near object boundaries, depth estimators often predict spurious 3D points in the empty space between foreground and background surfaces. We trace this artifact to a standard...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02551v1","title":"AFUN: Towards an Affordance Foundation Model for Functionality Understanding","abstract":"Affordance understanding bridges visual perception and physical action, serving as an explainable interface for robot manipulation in open and unstructured real-world environments. Yet, building an affordance foundation model that not only understands where and how the interaction should happen, but also generalizes across diverse environments, objects, and tasks, remains a long-standing research challenge. Existing methods typically address only part of this challenge, either localizing task-relevant regions without specifying executable motion, or predicting motion but with limited scalability. In this paper, we present ourmodel, a step towards an affordance foundation model for functionality understanding. From a single RGB-D observation and a language task description, ourmodel predicts a task-conditional functional mask (where to interact) and a 3D post-contact motion curve (how to interact). To support open-world generalization, we build a large-scale standardized data pipeline that converts heterogeneous robot, human, simulation, and real-world scan data into a shared affordance schema with language, masks, and object-centric 3D motion labels. We evaluate ourmodel from three aspects: for affordance segmentation, ourmodel outperforms all baselines by a large margin across 8 test sets from 4 benchmarks, improving mean gIoU/cIoU by +23.9/+26.3; for contact-point prediction, it predicts substantially more accurate points, with a 12.7--61.3% hit-rate gain over the best baseline; and for 3D motion, it achieves the best performance on all three test sets. ourmodel can be deployed for real-world robot manipulation without finetuning for robot embodiment or using task-specific heuristics, demonstrating the ability to adapt to open-world affordance tasks. Project page: https://www.zhaoningwang.com/AFUN","authors":["Zhaoning Wang","Yi Zhong","Jiawei Fu","Henrik I. Christensen","Jun Gao"],"published":"2026-06-01T17:50:16Z","updated":"2026-06-01T17:50:16Z","abstract_url":"https://arxiv.org/abs/2606.02551v1","html_url":"https://arxiv.org/html/2606.02551v1","pdf_url":"https://arxiv.org/pdf/2606.02551v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":92760,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Affordance understanding bridges visual perception and physical action, serving as an explainable interface for robot manipulation in open and unstructured real-world environments. Yet, building an affordance foundation model that not only understands where a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02532v1","title":"Improving Combined Detection and Classification of TEM Defects via Mask-Conditioned Latent Diffusion Augmentation","abstract":"Analyzing microstructural defects in transmission electron microscopy (TEM) images, particularly in irradiated metal alloys, is often limited by the availability of high-quality, labeled data. To address this, we introduce a generative data augmentation approach using a mask-conditioned latent diffusion model (LDM) for synthesizing realistic TEM images with controllable, automatically labeled multi-class defect masks. Without requiring manual annotations for generation, our method enables the creation of synthetic image-mask pairs by sampling distributions learned from experimental masks. These generated data were used to augment small experimental datasets of varying sizes (10, 50, and 100 labeled experimental images) to train a Mask Regional Convolutional Neural Network (R-CNN) model for defect detection and classification. Our results show that generative augmentation yields small overall model performance improvements, with up to a 0.02 gain in the harmonic mean of detection and classification F1 scores. However, we also find that the relative contributions to detection and classification improvement depend on the specific train/test data split. These findings highlight the potential of targeted generative models to enhance deep learning performance in data-scarce microscopy-based image quantification tasks.","authors":["Ni Li","Nuohao Liu","Ryan Jacobs","Ajay Annamareddy","Maciej P. Polak","Kevin Field","Izabela Szlufarska","Dane Morgan"],"published":"2026-06-01T17:38:47Z","updated":"2026-06-01T17:38:47Z","abstract_url":"https://arxiv.org/abs/2606.02532v1","html_url":"https://arxiv.org/html/2606.02532v1","pdf_url":"https://arxiv.org/pdf/2606.02532v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":50380,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Analyzing microstructural defects in transmission electron microscopy (TEM) images, particularly in irradiated metal alloys, is often limited by the availability of high-quality, labeled data. To address this, we introduce a generative data augmentation appro...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02526v1","title":"Why Not Hyperparameter-Friendly Optimisation? A Monotonic Adaptive Norm Rescaling Approach For Long-Tailed Recognition","abstract":"Long-tailed recognition poses a significant challenge for deep learning. The two-stage decoupling paradigm, which separates representation learning from classifier retraining, offers a promising solution. During the classifier retraining stage, adaptive norm rescaling is a popular technique. It adjusts the per-class weight norms via parameter regularization, which inevitably introduces hyperparameters. However, many studies report that long-tailed recognition is sensitive to these hyperparameters, as their setup significantly impacts performance. In this paper, we first provide a class-conditional distribution perspective to support norm rescaling methods. Furthermore, we propose a simple but effective approach called Self-Adaptive Monotonic Normalization (SAMN). SAMN avoids the need for parameter regularization. It directly enforces monotonicity on per-class weight norms using the Pool Adjacent Violators Algorithm, making the method hyperparameter-friendly. SAMN is a universal strategy that integrates seamlessly with other methods for enhanced performance. Experiments on benchmark datasets demonstrate that our method significantly boosts long-tailed recognition performance, often achieving state-of-the-art results.","authors":["Shuo Zhang","Chenqi Li","Tingting Zhu"],"published":"2026-06-01T17:34:38Z","updated":"2026-06-01T17:34:38Z","abstract_url":"https://arxiv.org/abs/2606.02526v1","html_url":"https://arxiv.org/html/2606.02526v1","pdf_url":"https://arxiv.org/pdf/2606.02526v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64514,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Long-tailed recognition poses a significant challenge for deep learning. The two-stage decoupling paradigm, which separates representation learning from classifier retraining, offers a promising solution. During the classifier retraining stage, adaptive norm...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02523v1","title":"FigSIM: A Dataset for Fine-grained Suicide Severity and Figurative Language in Suicide Memes","abstract":"Suicide memes are memes used to express suicide-related thoughts or comment on suicide-related issues. Suicide memes are increasingly common on social media, yet remain poorly understood and potentially harmful. There is an urgent need to better understand their characteristics and to develop appropriate content moderation strategies that limits users' exposure to potentially harmful content. Currently, the absence of annotated datasets of suicide memes remains a key barrier to developing and evaluating automated moderation approaches. In this paper, we introduce FigSIM, the first dataset designed for fine-grained analysis of suicide memes. The dataset consists of 1049 memes, each annotated for (1) fine-grained suicide severity levels, (2) figurative phenomena (e.g., metaphors), and (3) suicide-related content (e.g., suicide method depiction). We benchmark 16 unimodal and multimodal models across three tasks: figurative language, suicide severity, and suicide-related content detection. Overall, FigSIM demonstrates that suicide memes pose unique challenges for both modeling and content moderation. Analysis revealed biases, such as underprediction of higher suicide severity levels, especially for figurative memes. The dataset (including splits used for analyses) is publicly available. Content Warning: This paper contains suicide-related content that may be triggering.","authors":["Liuliu Chen","Elise R. Carrotte","Brian E. Chapman","Jo Robinson","Mike Conway"],"published":"2026-06-01T17:32:29Z","updated":"2026-06-01T17:32:29Z","abstract_url":"https://arxiv.org/abs/2606.02523v1","html_url":"https://arxiv.org/html/2606.02523v1","pdf_url":"https://arxiv.org/pdf/2606.02523v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":76961,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Suicide memes are memes used to express suicide-related thoughts or comment on suicide-related issues. Suicide memes are increasingly common on social media, yet remain poorly understood and potentially harmful. There is an urgent need to better understand th...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02522v1","title":"Moment-Video: Diagnosing Temporal Fidelity of Video MLLMs on Momentary Visual Events","abstract":"Video multimodal large language models (MLLMs) have made rapid progress on general and long-form video understanding, yet their ability to preserve brief answer-critical visual evidence remains underexplored. Many practical questions are determined by momentary visual events: localized actions or state transitions that may last only a few frames. Such evidence can be skipped by sparse frame sampling, suppressed by visual-token compression, or diluted by coarse temporal aggregation, causing failures that language-side reasoning cannot reliably recover. We introduce Moment-Video, a benchmark for diagnosing the temporal fidelity of video MLLMs through momentary visual event understanding. Each question is grounded in a localized, visually observable, and sampling-sensitive event, requiring models to notice, count, describe, or reason about transient evidence rather than rely on persistent objects, global scene context, or language priors. Moment-Video contains 1,000 human-verified video-QA pairs across 7 domains and 25 fine-grained subcategories, covering four task types: Temporal Occurrence, Temporal Counting, Action Description, and Temporal Reasoning. We evaluate 33 proprietary and open-source MLLMs on Moment-Video. The best-performing model, Seed-2.0-Pro, achieves only 39.6% overall accuracy, while most open-source models remain below 25%, revealing a substantial gap in momentary visual event understanding. Diagnostic analyses show that denser frame sampling improves some models but does not eliminate the bottleneck, and longer videos introduce stronger temporal-localization challenges. These findings suggest that current video MLLMs still lack temporally faithful representations for capturing, preserving, and using brief but decisive visual evidence.","authors":["Xiaolin Liu","Yilun Zhu","Xiangyu Zhao","Xuehui Wang","Yan Li","Xin Li","Haoyu Cao","Xing Sun","Shaofeng Zhang","Xu Yang","Zhihang Zhong","Xue Yang"],"published":"2026-06-01T17:32:20Z","updated":"2026-06-01T17:32:20Z","abstract_url":"https://arxiv.org/abs/2606.02522v1","html_url":"https://arxiv.org/html/2606.02522v1","pdf_url":"https://arxiv.org/pdf/2606.02522v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"html","source_text_chars":82246,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, multimodal 相关；摘要显示其主要贡献为：Video multimodal large language models (MLLMs) have made rapid progress on general and long-form video understanding, yet their ability to preserve brief answer-critical visual evidence remains underexplored. Many practical questions are determined by momenta...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02510v1","title":"Not All Points Are Equal: Uncertainty-Aware 4D LiDAR Scene Synthesis","abstract":"Constructing faithful 4D worlds from LiDAR-acquired sequences is crucial for embodied AI, yet current generative frameworks apply uniform modeling capacity across all spatial regions. This ignores that perceptual difficulty varies dramatically within a single scan: distant surfaces, occluded boundaries, and small-scale objects carry far higher uncertainty than well-observed structures. We present U4D, a new framework that explicitly leverages spatial uncertainty to guide LiDAR scene generation in a \"hard-to-easy\" schedule. U4D derives per-point uncertainty maps via Shannon Entropy from a pretrained segmentor, then applies an unconditional diffusion stage to synthesize high-entropy areas with precise geometry, followed by a conditional completion stage that fills in the remaining regions using these structures as priors. A MoST (Mixture of Spatio-Temporal) block further maintains cross-frame coherence by dynamically balancing spatial detail and temporal continuity. Extensive experiments on nuScenes and SemanticKITTI demonstrate state-of-the-art scene fidelity, temporal consistency, and downstream performance.","authors":["Xiang Xu","Alan Liang","Youquan Liu","Xian Sun","Linfeng Li","Lingdong Kong","Ziwei Liu","Qingshan Liu"],"published":"2026-06-01T17:24:14Z","updated":"2026-06-01T17:24:14Z","abstract_url":"https://arxiv.org/abs/2606.02510v1","html_url":"https://arxiv.org/html/2606.02510v1","pdf_url":"https://arxiv.org/pdf/2606.02510v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":19205,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Constructing faithful 4D worlds from LiDAR-acquired sequences is crucial for embodied AI, yet current generative frameworks apply uniform modeling capacity across all spatial regions. This ignores that perceptual difficulty varies dramatically within a single...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02506v1","title":"Question-Aware Evidence Ledgers for Video Relational Reasoning","abstract":"The VRR-QA challenge evaluates visual relational reasoning in videos, where answers often depend on implicit spatial relations, event boundaries, target identity, and dialogue context rather than a single salient frame. We present a test-time reasoning pipeline built around a strong GPT-5.5 video QA solver and a set of question-aware evidence ledgers. The initial solver answers each question from a uniform video representation, while routed ledgers are prompted to make the required targets, count units, reference frames, and temporal or spatial scope explicit for counting, spatial, endpoint, viewpoint, and dialogue reasoning. External tools such as open-vocabulary detection, depth cues, pair crops, ASR, and scene-graph ledgers are used only as evidence sources. A conservative gate keeps the current answer unless independent evidence uniquely supports a different option. The final evidence-gated pipeline achieves 92.95% overall accuracy and 93.79% macro accuracy on the challenge test split.","authors":["Yilin Ou","Mengshi Qi","Huadong Ma"],"published":"2026-06-01T17:18:03Z","updated":"2026-06-01T17:18:03Z","abstract_url":"https://arxiv.org/abs/2606.02506v1","html_url":"https://arxiv.org/html/2606.02506v1","pdf_url":"https://arxiv.org/pdf/2606.02506v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":22265,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：The VRR-QA challenge evaluates visual relational reasoning in videos, where answers often depend on implicit spatial relations, event boundaries, target identity, and dialogue context rather than a single salient frame. We present a test-time reasoning pipeli...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02498v1","title":"GloResNet: A lightweight 3D CNN with global topological features for preterm brain injury prediction","abstract":"This study introduces an automated deep learning framework for predicting brain injury (BI) in preterm infants from T2-weighted MRI (dHCP dataset). We propose GloResNet, a lightweight 3D CNN based on ResNet-10, pretrained on MedicalNet to address data scarcity. A global manifold mapping strategy first resamples each 3D volume to 128x128x128 and then applies subject-wise z-score intensity normalization, thereby preserving global topology while standardizing appearance. Training integrates mixup, class weighting, and test-time augmentation for robustness. In 5-fold cross-validation, GloResNet achieved 75.18% average accuracy (peak 81.82%), with specificity 0.81 and sensitivity 0.76. Results demonstrate that a topology-aware lightweight CNN has the capability to effectively predict neonatal BI, offering a non-invasive screening tool. The source code of this paper can be obtained from the GitHub repository: https://github.com/ICL-SUST/GloResNet-Preterm-Brain","authors":["Boyu Yuan","Jiamiao Lu","Weichuan Zhang","Benqing Wu","Tuo Wang","Changshan Wang","Changming Sun","Liang Guo"],"published":"2026-06-01T17:04:43Z","updated":"2026-06-01T17:04:43Z","abstract_url":"https://arxiv.org/abs/2606.02498v1","html_url":"https://arxiv.org/html/2606.02498v1","pdf_url":"https://arxiv.org/pdf/2606.02498v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":70945,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：This study introduces an automated deep learning framework for predicting brain injury (BI) in preterm infants from T2-weighted MRI (dHCP dataset). We propose GloResNet, a lightweight 3D CNN based on ResNet-10, pretrained on MedicalNet to address data scarcit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02491v1","title":"MORPHOS: Autoregressive 4D Generation with Temporal Structured Latents","abstract":"We present MORPHOS, a novel autoregressive framework that generates dynamic 3D assets from videos across diverse representations, including meshes, 3D Gaussians, and radiance fields. Existing methods are typically limited to a single representation, struggle to model topological changes, or fail to maintain temporal consistency over long videos. To address these limitations, we introduce the Temporal Structured Latents (T-SLAT), a unified 4D representation that jointly encodes geometry and appearance along the temporal dimension. Leveraging T-SLAT, MORPHOS autoregressively generates dynamic 3D assets via causal attention, conditioning each frame on its preceding history to ensure temporal consistency while handling evolving topologies. We also propose a temporal-structural augmentation to mitigate error accumulation in autoregressive generation. MORPHOS achieves state-of-the-art performance in appearance and competitive results in geometry across multiple benchmarks, demonstrating superior generalization across various representations and robustness in long-horizon generation.","authors":["Minkyung Kwon","Jinhyeok Choi","Youngjin Shin","Jaeyeong Kim","JongMin Lee","Seungryong Kim"],"published":"2026-06-01T17:01:21Z","updated":"2026-06-01T17:01:21Z","abstract_url":"https://arxiv.org/abs/2606.02491v1","html_url":"https://arxiv.org/html/2606.02491v1","pdf_url":"https://arxiv.org/pdf/2606.02491v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"html","source_text_chars":67317,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation 相关；摘要显示其主要贡献为：We present MORPHOS, a novel autoregressive framework that generates dynamic 3D assets from videos across diverse representations, including meshes, 3D Gaussians, and radiance fields. Existing methods are typically limited to a single representation, struggle...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02482v1","title":"X-Stream: Exploring MLLMs as Multiplexers for Multi-Stream Understanding","abstract":"While video streaming understanding has made significant strides, real-world applications, such as live sports broadcasting, autonomous driving, and multi-screen collaboration, inherently demand continuous, multi-stream interactions. However, existing benchmarks are confined to single-stream paradigms, leaving a critical gap in evaluating online, cross-stream reasoning. To bridge this, we introduce X-Stream, the first benchmark dedicated to multi-stream streaming understanding. Comprising 4,220 rigorously curated QA pairs across 932 videos, X-Stream evaluates 11 subtasks across multi-window, multi-view, and multi-device scenarios. Crucially, our dataset is constructed using a novel dual-verification pipeline that prevents over-reliance on a single stream. Furthermore, we pioneer the conceptualization of multi-modal large language models (MLLMs) as naive multiplexers, systematically evaluating their performance through the lens of Signal Multiplexing Theory. Our extensive online inference experiments reveal a stark reality: state-of-the-art MLLMs struggle significantly with concurrent streams, achieving only about 50% score and exhibiting poor proactive ability. Ultimately, X-Stream exposes the trade-off of current multiplexing schemes, providing both a practical evaluation protocol and empirical guidance for next-generation multi-stream agents.","authors":["Peiwen Sun","Xudong Lu","Huadai Liu","Yang Bo","Dongming Wu","Huankang Guan","Minghong Cai","Jinpeng Chen","Xintong Guo","Shuhan Li","Rui Liu","Xiangyu Yue"],"published":"2026-06-01T16:52:11Z","updated":"2026-06-01T16:52:11Z","abstract_url":"https://arxiv.org/abs/2606.02482v1","html_url":"https://arxiv.org/html/2606.02482v1","pdf_url":"https://arxiv.org/pdf/2606.02482v1.pdf","matched_keywords":["video","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02479v1","title":"Retrieve What's Missing: Coverage-Maximizing Retrieval for Consistent Long Video Generation","abstract":"Maintaining long-term geometric consistency remains challenging for long-horizon autoregressive video generation. Memory-augmented generative models address this by retrieving historical frames, but their effectiveness depends on two key design choices: what 3D-geometric evidence should represent past observations, and how memory frames should be selected from this evidence. Existing methods often rely on camera poses or field-of-view overlap, which are lightweight but too coarse to reason about pixel-wise visibility, or use explicit 3D reconstruction, which provides fine-grained evidence but is costly to maintain over long rollouts. We propose Coverage-Maximizing Retrieval-Augmented Generation (COVRAG), a depth-based memory retrieval framework that uses pretrained 3D priors to construct a target-view coverage map as lightweight 3D memory evidence. For frame selection, COVRAG maximizes residual coverage gain, iteratively retrieving frames that explain target-view regions not covered by the current context or previously selected memories. To improve scalability in long-video generation, we introduce sliding-window depth caching for efficient geometry estimation. Experiments on RealEstate10K and DL3DV10K show that COVRAG improves long-horizon geometric consistency while maintaining low latency compared to baselines.","authors":["Minseok Joo","Dogyun Park","Taehoon Lee","Kyujin Lee","Hyunwoo J. Kim"],"published":"2026-06-01T16:49:58Z","updated":"2026-06-01T16:49:58Z","abstract_url":"https://arxiv.org/abs/2606.02479v1","html_url":"https://arxiv.org/html/2606.02479v1","pdf_url":"https://arxiv.org/pdf/2606.02479v1.pdf","matched_keywords":["video","retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02463v1","title":"MASER: Modality-Adaptive Specialist Routing for Embodied 3D Spatial Intelligence","abstract":"In 3D environments, Embodied Agents answer spatially relevant questions through reasoning from a mixture of modalities including natural language, RGB images, point clouds, depth maps and camera poses. Existing Vision-Language models (VLMs) are fine-tuned over a single modality. This completely ignores the question semantics which may favor a different modality than the finetuned modality. To address this, we propose MASER (Modality-Adaptive SpEcialist Routing), a lightweight framework that trains five different modality adapters of a shared VLM backbone and learns a neural routing policy that selects the best adapter based on the question during inference. We encode each question with a frozen sentence transformer and pass the embedding through a small Multi-layer Perceptron (MLP) trained on oracle adapter-accuracy labels. We evaluate our methodology over the Open3D-VQA benchmark and our evaluations show that no single modality is universally optimal -- point-cloud answers are best in 51.5% of cases. MASER routes with 51.3% oracle agreement, outperforming a Random-Forest ablation (43.5%), with only a single adapter call per question.","authors":["Hilton Raj","Vishnuram AV"],"published":"2026-06-01T16:36:21Z","updated":"2026-06-01T16:36:21Z","abstract_url":"https://arxiv.org/abs/2606.02463v1","html_url":"https://arxiv.org/html/2606.02463v1","pdf_url":"https://arxiv.org/pdf/2606.02463v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02459v1","title":"Active Exploring like a Pigeon: Reinforcing Spatial Reasoning via Agentic Vision-Language Models","abstract":"Enabling Vision-Language Models (VLMs) to perform spatial reasoning remains challenging. Existing approaches treat VLMs as passive observers, which is difficult for real-world applications. Moreover, reinforcement learning methods rely on sparse rewards, limiting their effectiveness for complex reasoning tasks. Inspired by pigeons' building and exploiting cognitive maps for navigation, we propose a novel agentic pipeline for spatial reasoning. First, we introduce a new \\emph{dynamic cognitive map} parameterizing scene layout as object positions and orientations, serving as persistent memory for new observations. Second, we propose a novel \\emph{Spatial Assertion Codes (SAC)}, Python expressions programmatically describing spatial relationships. By collaborating with the dynamic cognitive map, SAC enables verification of intermediate reasoning steps, providing dense reward signals. We optimize the model via supervised and reinforcement finetuning. Experiments on the MindCube benchmark demonstrate state-of-the-art performance with \\emph{80.5\\%} overall accuracy, outperforming the best current method by \\emph{29.5} accuracy points (a relative improvement of \\emph{53.2\\%}) on the challenging \\textsc{Rotation} subset. Our code and data are open-sourced at https://github.com/dw-dengwei/active-spatial-reasoning.git.","authors":["Wei Deng","Xianlin Zhang","Mengshi Qi"],"published":"2026-06-01T16:30:56Z","updated":"2026-06-01T16:30:56Z","abstract_url":"https://arxiv.org/abs/2606.02459v1","html_url":"https://arxiv.org/html/2606.02459v1","pdf_url":"https://arxiv.org/pdf/2606.02459v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02453v1","title":"Initialization is Half the Battle: Generating Diverse Images from a Guidance Potential Posterior","abstract":"Despite the remarkable fidelity of generative models, they frequently suffer from mode collapse. Existing strategies for enhancing diversity predominantly focus on intervening during the generation trajectory. We identify a critical oversight that the standard Gaussian initialization often causes trajectories to collapse into dominant modes because it is agnostic to the guidance potential landscape. In this work, we formulate selecting the initial noise from a guidance potential posterior, which effectively re-weights the prior towards diversity-rich regions. To sample from this distribution efficiently, we introduce Diversity-inducing Initialization (DivIn), which leverages Langevin dynamics to actively navigate the initialization landscape, steering initial noise away from collapsing regions while anchoring them to the valid data manifold. Our method serves as an inference-time diversity enhancement compatible with both diffusion and flow matching models. Extensive experiments show that DivIn exhibits a superior performance in both class-to-image and text-to-image scenarios. Furthermore, we highlight that as DivIn is orthogonal to trajectory-based methods, combining them significantly expands the diversity-quality Pareto frontier beyond what either achieves in isolation.","authors":["Xiang Li","Dianbo Liu","Kenji Kawaguchi"],"published":"2026-06-01T16:25:10Z","updated":"2026-06-01T16:25:10Z","abstract_url":"https://arxiv.org/abs/2606.02453v1","html_url":"https://arxiv.org/html/2606.02453v1","pdf_url":"https://arxiv.org/pdf/2606.02453v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02450v1","title":"Reason-Then-Retrieve for CoVR-R with Structured Edit Prompts and Dense-Sparse Fusion","abstract":"CoVR-R studies reason-aware composed video retrieval: given a reference video and an edit instruction, the system must retrieve the target video that satisfies the edit. The main difficulty is that the target is not described directly; it must be inferred from fine-grained changes in object identity, action order, final state, hand interaction, and scene transition. We build a zero-shot reason-then-retrieve pipeline around Qwen3.5-27B. For each gallery video, the model generates a retrieval-oriented structured description and a dense embedding by pooling generated-token hidden states with token-dependent weights. For each query, the model first performs edit reasoning over the reference video and instruction, then generates a target-video description whose hidden states serve as the query embedding. We complement dense retrieval with a TF-IDF branch over the generated texts and fuse the two rankings with split-specific weights. On validation, the current best submission reaches 80.81 at R@1, 94.86 at R@5, 97.11 at R@10, and 98.59 at R@50. On the blind test split, it reaches 89.73 at R@1, 95.79 at R@5, 96.63 at R@10, and 97.98 at R@50.","authors":["DongQing Liu","MengShi Qi","HongWei Ji"],"published":"2026-06-01T16:21:01Z","updated":"2026-06-01T16:21:01Z","abstract_url":"https://arxiv.org/abs/2606.02450v1","html_url":"https://arxiv.org/html/2606.02450v1","pdf_url":"https://arxiv.org/pdf/2606.02450v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02449v1","title":"HLL: Can Agents Cross Humanity's Last Line of Verification?","abstract":"Multimodal agents are increasingly expected to operate interfaces on behalf of users, raising a central deployment question: can they truly substitute for humans in workflows that services deliberately protect against automation? CAPTCHA verification makes this question concrete. It is not merely a visual puzzle, but a human-verification boundary placed before account creation, content access, form submission, and other protected actions. We introduce \\textbf{Humanity's Last Line of Verification (HLL)}, a controlled benchmark that uses interactive CAPTCHA verification to evaluate whether agents can cross this boundary through grounded, human-like interaction rather than recognition alone. HLL covers diverse CAPTCHA interactions and exposes agents to controlled realism stressors, including cluttered webpages, harder task variants, and trace-conditioned validation of the solving process. We evaluate eight frontier multimodal agents in a closed-loop GUI environment. The results show that current agents remain brittle at this human-substitution boundary: performance varies sharply across verification types, degrades under realistic interface conditions, and drops further when correct answers must be supported by valid action traces. By exposing gaps in localization, action calibration, state tracking, and process consistency, HLL provides a concrete testbed for measuring how close multimodal agents are to acting as human substitutes in protected real-world workflows. Our code is available at https://github.com/XinhaoS0101/HLL","authors":["Xinhao Song","Su Su","Sirui Song","Hongliang Wu","Wen Shen","Zhihua Wei","Gongshen Liu","Linfeng Zhang","Dongrui Liu"],"published":"2026-06-01T16:20:45Z","updated":"2026-06-01T16:20:45Z","abstract_url":"https://arxiv.org/abs/2606.02449v1","html_url":"https://arxiv.org/html/2606.02449v1","pdf_url":"https://arxiv.org/pdf/2606.02449v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02443v1","title":"PaSBench-Video: A Streaming Video Benchmark for Proactive Safety Warning","abstract":"Between the first visible sign of danger and the moment an accident occurs, there is often a window where intervention remains possible. Video-capable multimodal large language models (MLLMs) could serve as always-on safety monitors that issue warnings during this window. Yet current benchmarks do not test this ability: they rely on static inputs, ignore timing precision, and omit false-positive measurement on safe scenes. We present PaSBench-Video, a 740-video benchmark with 481 risk and 259 no-risk videos across four domains: driving, healthcare, daily life, and industrial production. Risk videos are annotated with frame-level risk onset and accident boundaries. A model must observe the video causally and produce a warning that is both temporally calibrated and content-correct. Testing 13 MLLMs, we find that no model exceeds 20.0% on our strictest metric, and recall is tightly coupled with false-positive rate, with Pearson correlation 0.64: higher detection comes only at the cost of triggering warnings on the majority of safe clips. Performance splits sharply by domain: models achieve moderate recall at low false-positive rates in daily life, where risks are inherently anomalous, yet fire indiscriminately in driving, where routine and hazardous scenes look alike. These results indicate that current models rely on scene-level activity cues rather than reasoning about emerging harm.","authors":["Yusong Zhao","Yuejin Xie","Youliang Yuan","Junjie Hu","Jitian Guo","Yujiu Yang","Pinjia He"],"published":"2026-06-01T16:14:01Z","updated":"2026-06-01T16:14:01Z","abstract_url":"https://arxiv.org/abs/2606.02443v1","html_url":"https://arxiv.org/html/2606.02443v1","pdf_url":"https://arxiv.org/pdf/2606.02443v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02441v1","title":"Spatial-Temporal Decoupled Reference Conditioning for Identity-Preserving Text-to-Video Generation","abstract":"Identity-preserving video generation (IPVG) aims to synthesize high-fidelity videos that follow text prompts while faithfully preserving a reference identity. Despite recent progress, existing IPVG methods still struggle to balance high-level semantic control and low-level identity fidelity. To bridge this gap, we propose ST-DRC, an effective Spatial-Temporal Decoupled Reference Conditioning framework for identity-preserving text-to-video generation. At the framework level, ST-DRC performs latent in-context feature injection by encoding the reference image with the video VAE and concatenating it with noisy video latents, enabling rich low-level identity details to be accessed without additional adapters. To separate identity-aware reference retrieval from appearance copying, we introduce TASS-RoPE, a Temporal-Adjacent Spatial-Shifted RoPE scheme that places reference tokens near the video sequence in time but shifts them in space, allowing reference information to flow through spatio-temporal attention while suppressing pixel-level copy-paste shortcuts. To further prevent shortcut learning and strengthen the otherwise diluted identity supervision in the diffusion objective, we combine appearance-invariant reference augmentation with face-guided identity objectives, encouraging the model to preserve identity under variations in color, pose, and layout. At inference time, we introduce a three-stream reference classifier-free guidance strategy that independently controls text adherence and reference fidelity. Experiments demonstrate that ST-DRC achieves strong identity preservation, prompt alignment, temporal consistency, and video quality with a lightweight design built on LTX-2.3. Our method ranks among the top submissions in the facial identity-preserving video generation track, validating the effectiveness of spatial-temporal decoupled reference conditioning.","authors":["Yuheng Chen","Teng Hu","Yuji Wang","Qingdong He","Lizhuang Ma","Jiangning Zhang"],"published":"2026-06-01T16:12:18Z","updated":"2026-06-01T16:12:18Z","abstract_url":"https://arxiv.org/abs/2606.02441v1","html_url":"https://arxiv.org/html/2606.02441v1","pdf_url":"https://arxiv.org/pdf/2606.02441v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02436v1","title":"Geometry-Aware Implicit Memory for Video World Models","abstract":"Video world models aim to simulate controllable visual environments, but long-horizon rollouts depend on what the model remembers after observations leave its native context window. Explicit memories retain frames or online 3D reconstructions, which can suffer from heuristic retrieval errors, redundant appearance storage, or reconstruction artifacts. Implicit memories compress history into a compact state, but existing designs are not explicitly constrained to encode cross-view scene geometry. We propose GIM-World, a geometry-aware implicit memory framework for video world models. A lightweight transformer encoder compresses variable-length history into fixed-size memory tokens, a camera-queryable geometry head distills 3D scene structure from a frozen foundation model into the memory during training, and an information-guided pruning rule keeps encoding cost bounded as history grows. The geometry teacher is discarded at inference, leaving a lightweight memory module. Experiments on MIND show that GIM-World better preserves long-horizon geometric and visual consistency than both explicit- and implicit-memory baselines.","authors":["Zhengxuan Wei","Xu Guo","Xinghui Li","Xunzhi Xiang","Min Wei","Yiran Zhu","Qiulin Wang","Xintao Wang","Pengfei Wan","Xiangwang Hou","Qi Fan"],"published":"2026-06-01T16:08:43Z","updated":"2026-06-01T16:08:43Z","abstract_url":"https://arxiv.org/abs/2606.02436v1","html_url":"https://arxiv.org/html/2606.02436v1","pdf_url":"https://arxiv.org/pdf/2606.02436v1.pdf","matched_keywords":["video","retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02406v1","title":"Edge Prediction for Roof Wireframe Reconstruction with Transformers","abstract":"This paper presents a competitive solution to the S23DR Challenge 2026, which aims to reconstruct 3D house roof wireframe models from sparse SfM point clouds and ground-level semantic segmentations and depth maps. Our proposed method utilizes an end-to-end Transformer encoder-decoder architecture inspired by DETR. To effectively process the geometric and semantic data, the sparse SfM point cloud input is dynamically subsampled based on semantic priority and augmented with Gestalt and ADE20k class features. To further increase segmentation context, we fuse the point features with additional Gestalt feature encodings which are obtained by projecting the points into latent feature maps produced by a frozen autoencoder. Learned query embeddings are then decoded directly into 3D wireframe edges via cross-attention mechanisms. Evaluated on the \"HoHo 22k\" dataset, our approach significantly outperforms both handcrafted and learned baselines, achieving a Hybrid Structure Score (HSS) of 0.6476 and securing the second-highest position on the challenge's private leaderboard.","authors":["Gustav Hanning","Ludvig Dillén","Jonathan Astermark","Johanna Lidholm","Viktor Larsson"],"published":"2026-06-01T15:51:30Z","updated":"2026-06-01T15:51:30Z","abstract_url":"https://arxiv.org/abs/2606.02406v1","html_url":"https://arxiv.org/html/2606.02406v1","pdf_url":"https://arxiv.org/pdf/2606.02406v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02402v1","title":"Explainable Forensics of Manipulated Segments in Untrimmed Long Videos","abstract":"The rapid advancement of AI-driven video generation has transformed content creation, while simultaneously increasing the risk of misinformation through localized manipulations in long-form videos. Existing video forensic methods predominantly operate on short, independent clips, and thus fail to capture realistic scenarios where AI-generated content is sparsely embedded within otherwise authentic footage. To bridge this gap, we formulate the task of Temporal AI-Generated Segment Localization and Explanation, which targets authenticity detection, temporal localization, and interpretable analysis of manipulated segments in untrimmed long videos. We further introduce TASLE, a large-scale benchmark comprising 12,472 untrimmed videos with diverse manipulation patterns and rich annotation signals, including temporal boundaries, authenticity labels, and segment-level rationales. In addition, we propose MSLoc, a coarse-to-fine forensic baseline that combines a boundary-sensitive proposal generation module for efficient long-video scanning with an MLLM-based refinement module for precise boundary localization and interpretable reasoning. Experiments validate the effectiveness of the proposed baseline, highlighting the importance of segment-level explainable forensics for long-form AI-generated video analysis. Our dataset and code are publicly available at https://debby-0527.github.io/TASLE.","authors":["Yue Feng","Jingjing Li","Qijia Lu","Wei Ji","Jingrou Zhang","Fei Shen","Xiao Li","Yizhen Jia","Qiang Chen","Limin Wang","Wentong Li","Jie Qin"],"published":"2026-06-01T15:48:38Z","updated":"2026-06-01T15:48:38Z","abstract_url":"https://arxiv.org/abs/2606.02402v1","html_url":"https://arxiv.org/html/2606.02402v1","pdf_url":"https://arxiv.org/pdf/2606.02402v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02366v1","title":"PRIMA: Boosting Animal Mesh Recovery with Biological Priors and Test-Time Adaptation","abstract":"We present PRIMA (*PRI*ors for *M*esh *A*daptation), a framework for robust 3D quadruped mesh recovery under severe species and pose imbalance. Existing animal reconstruction methods often regress toward mean shapes and poses due to limited 3D supervision and long-tailed species distributions, resulting in poor generalization to underrepresented animals and rare articulations. PRIMA addresses this challenge through three key contributions. First, we incorporate BioCLIP embeddings as biological priors to inject semantic and morphological knowledge into the reconstruction process, enabling more accurate and generalizable shape prediction across diverse quadrupeds. Second, we introduce a test-time adaptation (TTA) strategy that refines SMAL predictions using 2D reprojection constraints together with auxiliary keypoint guidance, improving pose and shape estimation while enabling the generation of high-quality pseudo-3D annotations from existing 2D datasets. Third, leveraging this TTA framework, we construct Quadruped3D, a large-scale pseudo-3D dataset that covers diverse species and pose variations to systematically improve model performance. Extensive experiments on Animal3D, CtrlAni3D, Quadruped2D, and Animal Kingdom demonstrate that PRIMA achieves state-of-the-art results, with particularly strong improvements on underrepresented species and challenging poses. Our results highlight the importance of biological priors and adaptation-driven data expansion for scalable and generalizable animal mesh recovery. Code is available at https://github.com/AdaptiveMotorControlLab/PRIMA.","authors":["Xiaohang Yu","Ti Wang","Mackenzie Weygandt Mathis"],"published":"2026-06-01T15:13:47Z","updated":"2026-06-01T15:13:47Z","abstract_url":"https://arxiv.org/abs/2606.02366v1","html_url":"https://arxiv.org/html/2606.02366v1","pdf_url":"https://arxiv.org/pdf/2606.02366v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02357v1","title":"Do Multimodal Agents Really Benefit from Tool Use? A Systematic Study of Capability Gains","abstract":"Tool-augmented multimodal agents show strong benchmark gains, often taken as evidence that agents have learned to use tools. We argue that this interpretation can be premature: a tool-call trace alone does not show whether the tool supplied answer-critical information. We study two representative ``thinking with images'' agents, Thyme and DeepEyesV2, across real-world understanding, OCR, chart understanding, and mathematical reasoning. Each agent is compared with its Tool-Free counterpart and with a Pure-Text Reasoner trained from the same source pool without tool-calling trajectories. Tool access yields little consistent aggregate improvement, does not reliably reduce generated-token cost, and leaves only a small tool-only solved set: 93% of DeepEyesV2's tool-solved problems and 96% of Thyme's are also solved by at least one non-tool setting. Mechanism ablations further show that the full tool-use loop does not consistently outperform either the tool-call format or the returned execution result alone. In the settings we study, the analyzed agents appear to learn tool-calling patterns more reliably than tool-contributed capabilities, suggesting that evaluation should distinguish tool availability from whether tools actually expand what agents can solve.","authors":["Garvin Guo","Donglei Yu","Yu Chen","Xiang Wang","Shuai Li","Xinpei Zhao","Huaxing Liu","Qinghao Wang","Minpeng Liao"],"published":"2026-06-01T15:04:25Z","updated":"2026-06-01T15:04:25Z","abstract_url":"https://arxiv.org/abs/2606.02357v1","html_url":"https://arxiv.org/html/2606.02357v1","pdf_url":"https://arxiv.org/pdf/2606.02357v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02352v1","title":"Multi-modal Video Representation Alignment for Robust Self-supervised Driver Distraction Detection","abstract":"Robust self-supervised learning of multi-modal video representations is critical for real-world applications such as driver distraction detection, where multiple sensors provide complementary but noisy signals. Conventional contrastive objectives, such as InfoNCE, assume all negatives are equally informative and all positives are reliable. However, this assumption is frequently violated in multi-modal data due to viewpoint changes, occlusions, or semantic overlap across modalities. In this work, we propose a novel framework for multi-modal global alignment that addresses these challenges by jointly modeling faulty negatives and unreliable or faulty positives. We introduce soft targets derived from cycle-consistency scores to relax the hard-negative assumption, and a weighting mechanism based on similarity distributions to mitigate the impact of noisy or faulty positives. Our approach extends traditional pairwise alignment to a principled global multi-modal setting, aggregating alignment information across all modality pairs. We evaluate our method on the Drive&Act dataset, demonstrating that it consistently outperforms both pairwise and existing global alignment baselines across RGB, IR, Depth, and Skeleton modalities. Cross-view ablation studies further show strong generalization to unseen camera perspectives, highlighting the robustness of our representations. Overall, our framework provides a scalable and effective solution for self-supervised global multi-modal representation learning, enabling reliable driver distraction detection and pioneering in real-world multi-modal video understanding. Our code will be published on GitHub.","authors":["David J. Lerch","Livien Majer","Zeyun Zhong","Manuel Martin","Frederik Diederichs","Rainer Stiefelhagen"],"published":"2026-06-01T15:01:17Z","updated":"2026-06-01T15:01:17Z","abstract_url":"https://arxiv.org/abs/2606.02352v1","html_url":"https://arxiv.org/html/2606.02352v1","pdf_url":"https://arxiv.org/pdf/2606.02352v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02350v1","title":"TROPHIES: Temporal Reconstruction of Places, Humans, and Cameras from Multi-view Videos","abstract":"Reconstructing humans and their surrounding environments in a globally consistent 4D space is essential for comprehensive perception. However, prior works typically assume single-view inputs or decouple humans, scenes, and cameras, making them unable to recover coherent geometry, stable motion, and physically aligned trajectories. These limitations motivate us to introduce a new task: unified human-scene-camera reconstruction from multi-view videos, which aims to jointly estimate dynamic humans, static scenes, and camera poses in one global coordinate frame. We propose TROPHIES--Temporal Reconstruction of Places, Humans, and Cameras from Multi-view Videos-a unified framework tailored for this task. TROPHIES features a Human Branch that models humans through temporal and spatial reasoning, and a Scene Branch that reconstructs static geometry with human-aware attention. A global alignment and optimization module couples both branches by enforcing scale consistency, contact priors, and cross-view temporal coherence. Experiments on EgoHuman and EgoExo4D demonstrate that TROPHIES achieves globally aligned, physically plausible 4D reconstructions and consistently outperforms existing paradigms in both global fidelity and human-scene consistency.","authors":["Jinpeng Liu","Yukang Xu","Yutong Li","Xingyu Liu"],"published":"2026-06-01T15:00:18Z","updated":"2026-06-01T15:00:18Z","abstract_url":"https://arxiv.org/abs/2606.02350v1","html_url":"https://arxiv.org/html/2606.02350v1","pdf_url":"https://arxiv.org/pdf/2606.02350v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02346v1","title":"VEDAL: Variational Error-Driven Asynchronous Learning for 3D Gaussian Splatting Pruning","abstract":"3D Gaussian Splatting (3DGS) achieves remarkable novel view synthesis quality with real-time rendering, yet suffers from excessive memory consumption due to millions of Gaussian primitives. Existing pruning methods rely on heuristic importance scores or synchronous batch updates, leading to suboptimal compression and training instability. We propose VEDAL, a principled framework that formulates Gaussian pruning as variational free energy minimization. Our approach introduces (1) a prediction-error gating mechanism that asynchronously activates pruning based on per-Gaussian reconstruction uncertainty, and (2) a variational uncertainty head that models pruning decisions as latent variables with learnable priors. The free energy objective naturally balances reconstruction fidelity against model complexity through an information-theoretic lens. Extensive experiments on Mip-NeRF 360, Tanks&Temples, and Deep Blending demonstrate that VEDAL achieves 5.2x compression with only 0.31 dB PSNR drop, outperforming PUP 3D-GS by +0.05 dB at a higher compression ratio and LightGaussian by +0.35 dB at comparable quality, while maintaining real-time rendering at 185 FPS.","authors":["Aoduo Li","Jiancheng Li","Huan Ye","Hongjian Xu","Shiting Wu","Xiujun Zhang","Zimeng Li","Xuhang Chen"],"published":"2026-06-01T14:56:50Z","updated":"2026-06-01T14:56:50Z","abstract_url":"https://arxiv.org/abs/2606.02346v1","html_url":"https://arxiv.org/html/2606.02346v1","pdf_url":"https://arxiv.org/pdf/2606.02346v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02342v1","title":"Detecting Pen-In-Air States from Video: A Proof-of-Concept Toward Complementary Handwriting Analysis","abstract":"Dynamic aspects of handwriting are critical for assessing developmental disorders such as dysgraphia and are typically captured using digitizing tablets. However, tablet-based sensing restricts analysis of Pen-Up behavior to a short proximity range above the writing surface, potentially missing high-lift in-air movements. As a proof of concept, we investigate whether top-view video can provide a complementary source of information for inferring pen-contact states without relying on tablet proximity sensing. We propose an interpretable hybrid pipeline combining pen-tip tracking using a YOLO-based detector with kinematic feature extraction and machine learning classification. A pilot dataset of diverse handwriting videos was manually annotated at the frame level and evaluation used a Leave-One-Video-Out (LOVO) protocol. The method achieved reliable event-level detection of Pen-Up segments, with an F_2 score up to 0.805, consistent with the emphasis on recall in a screening-oriented setting. These results support the feasibility of video-based Pen-Up detection as a low-cost and non-intrusive complement to digitizing tablets, and provide a foundation for future large-scale studies.","authors":["Lauren Sismeiro","Remy Plastre","Binbin Xu","Frederic Puyjarinet","Gerard Dray"],"published":"2026-06-01T14:50:27Z","updated":"2026-06-01T14:50:27Z","abstract_url":"https://arxiv.org/abs/2606.02342v1","html_url":"https://arxiv.org/html/2606.02342v1","pdf_url":"https://arxiv.org/pdf/2606.02342v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02339v1","title":"Entropy Minimization without Model Collapse: Mitigating Prediction Bias in Medical Imaging","abstract":"Entropy minimization (EM) is the dominant objective for test-time adaptation, yet its failure mode, model collapse, remains poorly understood. In this work, we show that distribution shifts can cause feature clusters corresponding to distinct classes in the model's representation space to merge, while the decision boundary remains fixed. This induces a systematic skew in the predicted class distribution, referred to as prediction bias. Prediction bias refers to a shift in the predicted class distribution, with some classes overrepresented and others suppressed. We show that entropy minimization amplifies this prediction bias by tightening the existing clusters, reinforcing the incorrect groupings until all predictions collapse to a trivial solution. Next, to demonstrate the significance of prediction bias and mitigate it, we further propose Distribution Shift Bias Reduction (DSBR), a bias-correcting objective that specifically targets this failure mode by equalizing the contribution of each predicted class to the unsupervised entropy minimization loss. To study this failure mode, we design suitable adaptation settings using four medical-imaging datasets and additionally evaluate on ImageNet-C. We find that DSBR consistently stabilizes test-time adaptation, prevents model collapse, and matches or outperforms state-of-the-art methods. Moreover, DSBR operates solely at test-time.","authors":["Tim Nielen","Sameer Ambekar","Johannes Kiechle","Daniel M. Lang","Julia A. Schnabel"],"published":"2026-06-01T14:48:16Z","updated":"2026-06-01T14:48:16Z","abstract_url":"https://arxiv.org/abs/2606.02339v1","html_url":"https://arxiv.org/html/2606.02339v1","pdf_url":"https://arxiv.org/pdf/2606.02339v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02331v1","title":"Hallucination-Aware Diffusion Sampling for Inverse Problems via Robust Prior Updates","abstract":"Diffusion-based inverse problem solvers can produce realistic reconstructions, but realism alone does not ensure that the recovered details are supported by the measurement. We study this failure as measurement-conditioned hallucination: visually meaningful content that is either implausible or inconsistent with the measured instance. Our analysis separates Bayes-rule-based diffusion inverse solvers into a prior update and a measurement-conditioning step, showing that hallucinated content can enter through the prior-side proposal before the measurement correction is applied. Motivated by this view, we propose Robust Prior Update (RPU), a solver-level module that probes the local stability of the diffusion prior update, re-anchors the resulting displacement at the current iterate, and leaves the measurement update unchanged. We instantiate RPU in DPS and evaluate it on FFHQ and ImageNet inverse problems using automatic metrics and human faithfulness studies. On FFHQ, RPU improves PSNR and LPIPS over DPS across box inpainting, Gaussian deblurring, and motion deblurring. In human judgments, RPU receives 91.9% of blind non-tie majority preferences and 91.1% of ground-truth-assisted non-tie preferences on FFHQ box inpainting, while the ImageNet Gaussian reader study is tie-heavy but favors RPU among non-tie cases. These results support a targeted claim: robustifying the prior update can improve instance faithfulness in diffusion inverse solvers, especially when the prior shapes weakly constrained content.","authors":["Pengfei Jin","Yiqi Tian","Kailong Fan","Bingjie Qi","Quanzheng Li"],"published":"2026-06-01T14:41:46Z","updated":"2026-06-01T14:41:46Z","abstract_url":"https://arxiv.org/abs/2606.02331v1","html_url":"https://arxiv.org/html/2606.02331v1","pdf_url":"https://arxiv.org/pdf/2606.02331v1.pdf","matched_keywords":["instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02321v1","title":"Training-Free Composed Video Retrieval via Visual Representation-Guided Video-LLM Reasoning","abstract":"Recent advances in large vision-language models have expanded video retrieval from simple text-based search to more flexible scenarios, where users may specify the desired result through both visual examples and textual instructions. In the CVPR 2026 Reason-Aware Composed Video Retrieval Challenge, the system is required to retrieve a target video according to a reference video and a modification instruction. To address this task, we develop Visual Representation-Guided Video-LLM Reasoning for Training-Free Composed Video Retrieval. Our framework first uses frozen DINOv3 models to obtain a compact set of visually relevant candidates, and then applies large vision-language models to evaluate whether each candidate satisfies the modification instruction. A final reasoning-based refinement is further performed on the top candidates to improve the first-ranked prediction. Without training, our system achieves 48.78 Recall@1 and 51.48 Recall@5 on the test set. Future work may further improve retrieval accuracy through stronger video-LLMs and detailed integration between visual representations and language reasoning.","authors":["Yang Liu","Qianqian Xu","Peisong Wen","Siran Dai","Qingming Huang"],"published":"2026-06-01T14:35:23Z","updated":"2026-06-01T14:35:23Z","abstract_url":"https://arxiv.org/abs/2606.02321v1","html_url":"https://arxiv.org/html/2606.02321v1","pdf_url":"https://arxiv.org/pdf/2606.02321v1.pdf","matched_keywords":["video","retrieval","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02310v1","title":"Deep Learning for Remote Sensing to Improve Flood Inundation Mapping","abstract":"Flooding is the most pervasive natural disaster worldwide. Timely and accurate flood inundation mapping are essential for informing disaster risk management. Optical satellite missions provide high-resolution, multispectral observations critical for flood detection and inundation mapping. However, their operational utility is severely constrained by cloud cover during extreme precipitation events. Conventional cloud-removal techniques based on temporal compositing or interpolation often fail to capture inundation dynamics. In this study, we introduce a cloud-removal framework for flood imagery based on Denoising Diffusion Probabilistic Models, leveraging the Masked Diffusion Transformer architecture. The proposed approach exploits self-attention mechanisms to capture wider spatial context and employs masked token modeling to explicitly learn the reconstruction of cloud-obscured regions. Trained on multispectral Sentinel-2B flood scenes with realistic cloud patterns, the model generates cloud-free image realizations that preserve both visual fidelity and hydrological consistency. Reconstruction performance is evaluated using standard image quality metrics alongside flood-specific hydrological measures, demonstrating improved continuity of water bodies and preservation of spectral signatures critical for water detection indices. The results indicate that diffusion-based generative modeling offers a robust and physically consistent alternative for cloud removal in optical flood monitoring, enabling more reliable, continuous observations to support disaster risk management and flood-related decision making.","authors":["Yogesh Bhattarai","Vijay Chaudhary","Wai Lim Kim","Sanjib Sharma"],"published":"2026-06-01T14:28:48Z","updated":"2026-06-01T14:28:48Z","abstract_url":"https://arxiv.org/abs/2606.02310v1","html_url":"https://arxiv.org/html/2606.02310v1","pdf_url":"https://arxiv.org/pdf/2606.02310v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02303v1","title":"Cross-Domain Dead Tree Detection via Knowledge Distillation in Aerial Imagery","abstract":"Detecting dead trees in aerial imagery is vital for assessing forest health, especially as tree mortality increases globally due to climate change, but domain variability and scarce labeled data often limit model generalization. This study advances the TreeMort-1T-UNet (Tree Mortality 1-Task U-Net) model, initially trained on Finnish aerial imagery (source domain), by applying knowledge distillation (KD) to adapt it to various target domains, including Polish, German, and Estonian datasets representing diverse forest types. We assess four KD variants: Basic, Self, Feature-level, and Ensemble, against a fine-tuning baseline, using Mean Tree IoU, Instance F1-score, Instance Precision, and Mean Centroid Error as key metrics, alongside representational analyses (e.g., cosine similarity, CKA, SSIM, t-SNE, and linear probing) for domain invariance. Feature-level KD outperforms others, yielding a Mean Tree IoU of 0.106, Instance F1-score of 0.63, Instance Precision of 0.55, and Mean Centroid Error of 3.039 on the Polish dataset, with robust precision across other target domains (e.g., 0.15 on Finnish, 0.67 on Polish, 0.60 on German, 0.59 on Estonian). It excels in low-data scenarios with fewer false positives and shows superior representational invariance (e.g., higher deep-layer CKA/SSIM, better domain mixing in t-SNE, and linear probing AUC of 0.95), making it ideal for precision-critical forestry applications. Additional ablation studies confirm that key components like feature alignment enhance its performance balance across metrics. Our findings demonstrate KD's potential to enhance transfer learning in remote sensing, offering a scalable, domain-robust tool for ecological monitoring and sustainable forest management.","authors":["Anis Ur Rahman","Mete Ahishali","Einari Heinaro","Samuli Junttila"],"published":"2026-06-01T14:24:20Z","updated":"2026-06-01T14:24:20Z","abstract_url":"https://arxiv.org/abs/2606.02303v1","html_url":"https://arxiv.org/html/2606.02303v1","pdf_url":"https://arxiv.org/pdf/2606.02303v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02301v1","title":"Quantitative Movement Testing: Measuring Patient Movements from a Single Smartphone Video","abstract":"Chronic pain diminishes quality of life by decreasing functional ability, yet objectively measuring this functional impact remains challenging in real-world settings. While optical motion capture provides high precision for assessing altered movement quality, it is costly and restricted to laboratory environments. We aimed to develop and validate Quantitative Movement Testing (QMT), a computer vision pipeline extracting 3D kinematic biomarkers from standard monocular smartphone video, balancing clinical accessibility with biomechanical accuracy. We validated the QMT pipeline, utilising deep learning-based 3D pose-estimation, against gold-standard optical motion capture in healthy controls (N=13). Following leave-one-subject-out calibration to correct systematic bias, we deployed QMT in two prospective clinical cohorts to assess real-world utility: a pre- and post-intervention trial for fibromyalgia patients, and a 30-day longitudinal at-home monitoring study of chronic sciatica patients and healthy controls. In laboratory validation, QMT extracted clinical kinematic metrics with high agreement to optical motion capture, yielding strong correlations (r > 0.85) and low mean absolute errors. QMT demonstrated high test-retest reliability (r > 0.86) in fibromyalgia patients and successfully tracked day-to-day movement fluctuations in chronic sciatica. While real-world home settings introduced higher measurement variance than lab settings, QMT found group-level differences between healthy controls and sciatica patients based entirely on remote recordings. Monocular 3D pose estimation offers a scalable alternative to traditional assessments. QMT provides an objective, accessible biomarker for tracking disease progression and treatment response in clinical trials, though further research is needed to optimise reliability in home environments.","authors":["Pranav Mahajan","Amanda Wall","Eleonora Maria Camerone","Julie Stebbins","Eoin Kelleher","Shuangyi Tong","Annina Schmid","Katja Wiech","Anushka Irani","Ben Seymour"],"published":"2026-06-01T14:23:17Z","updated":"2026-06-01T14:23:17Z","abstract_url":"https://arxiv.org/abs/2606.02301v1","html_url":"https://arxiv.org/html/2606.02301v1","pdf_url":"https://arxiv.org/pdf/2606.02301v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02292v1","title":"Neural Acquisition & Representation of Subsurface Scattering","abstract":"We present a method to acquire and estimate the sub-surface scattering properties of light transport at a highly detailed level by learning the pixel footprint response at each point on the object surface. The reconstruction leverages 3D scanning techniques as input to a U-Net CNN. A stereo projector-camera setup using phase-shifted profilometry (PSP) patterns efficiently captures the data for a variety of scattering objects. Reconstructing dense pixel footprints allows for relighting with arbitrary high-resolution projector patterns. The final output is a relit color image. Qualitative and quantitative comparison against illuminated real-world captured images demonstrate that the predicted footprints are almost identical to the actual responses. The same model is trained for multiple views across multiple objects such that the learned representations can be used to generalize to unseen sub-surface scattering materials as well.","authors":["Arjun Majumdar","Raphael Braun","Hendrik Lensch"],"published":"2026-06-01T14:14:38Z","updated":"2026-06-01T14:14:38Z","abstract_url":"https://arxiv.org/abs/2606.02292v1","html_url":"https://arxiv.org/html/2606.02292v1","pdf_url":"https://arxiv.org/pdf/2606.02292v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02276v1","title":"Cross-modal linkage risk in clinical vision-language models","abstract":"Vision-language models (VLMs) trained on paired chest radiographs and radiology reports learn a shared embedding space that can preserve instance-level image-report correspondence. This poses a privacy risk in settings where radiographs and reports are deliberately kept separate after acquisition, such as image-only data sharing or access-controlled reports, because a de-identified image may be re-linked to its original narrative report through cosine similarity alone. We formalized this as image-to-report retrieval and used public paired cohorts, in which the true pairing is known by design, as ground-truth benchmarks to audit the risk rather than as the privacy scenario. Evaluating VLMs of increasing clinical specialization on 406,241 paired examples from 126,804 patients across MIMIC-CXR (43,793 held-out pairs) and external CheXpert Plus (29,296 pairs), we found that re-linkage rose systematically with specialization: the strongest VLM retrieved the correct report at 15 times chance at a candidate pool of N = 100, 50 times chance at N = 10,000, and well above chance at full-database scale. The signal persisted under pathology-matched hard negatives that removed disease-label shortcuts, indicating correspondence beyond broad diagnostic categories. To reduce it without retraining, we froze both encoders and applied differentially private optimization only to the projection heads defining the alignment layer (epsilon = 0.34, delta = 6x10-6). This reduced Recall@1 by 61.8% at N = 10,000 on MIMIC-CXR and transferred to CheXpert Plus without retraining, while image-side utility was largely preserved: macro AUROC for linear-probe classification across 14 labels shifted only from 79.63% to 79.43%. Targeted DP finetuning of the shared alignment layer can substantially reduce cross-modal re-linkage without materially degrading the image representations that make these models clinically useful.","authors":["Soroosh Tayebi Arasteh","Mahshad Lotfinia","Sven Nebelung","Daniel Truhn"],"published":"2026-06-01T14:01:46Z","updated":"2026-06-01T14:01:46Z","abstract_url":"https://arxiv.org/abs/2606.02276v1","html_url":"https://arxiv.org/html/2606.02276v1","pdf_url":"https://arxiv.org/pdf/2606.02276v1.pdf","matched_keywords":["retrieval","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02268v1","title":"From Extrinsic to Intrinsic: Geodesic-Guided Representation Learning for 3D Geometric Data","abstract":"Geometric analysis fundamentally distinguishes between \\textit{extrinsic} and \\textit{intrinsic} perspectives. The dominant paradigm in current 3D representation learning relies on either extrinsic spatial structures or high-level semantics, struggling to capture the essence of shape identity and underlying manifold topology. To bridge this gap, we introduce a novel 3D representation learning paradigm, namely \\textbf{PRISM}, for \\textbf{P}re-training, which learns isometric embeddings by \\textbf{R}ecovering the \\textbf{I}ntrinsic \\textbf{S}urface geodesic \\textbf{M}etric. PRISM incorporates a topology-enforcing objective that explicitly constrains the structure of latent space, alongside a specialized two-stage training recipe mitigating sample imbalance inherent in the distribution of geodesic distances. Experiments demonstrate that our approach shows satisfactory accuracy, robustness, and high efficiency in geodesic distance prediction and achieves superior performance across diverse downstream tasks, including shape recognition, surface parameterization, and non-rigid correspondence. The code will be publicly available at https://github.com/AidenZhao/PRISM.","authors":["Yuming Zhao","Junhui Hou","Qijian Zhang","Jia Qin","Ying He"],"published":"2026-06-01T13:54:26Z","updated":"2026-06-01T13:54:26Z","abstract_url":"https://arxiv.org/abs/2606.02268v1","html_url":"https://arxiv.org/html/2606.02268v1","pdf_url":"https://arxiv.org/pdf/2606.02268v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02242v1","title":"Towards Resolving Optimization Conflicts Between Image- and Text-Based Person Re-Identification","abstract":"The joint optimization of image-based (I2I) and text-based (T2I) person re-identification (ReID) is hindered by modality discrepancies and conflicting training objectives, leading to suboptimal shared representations. While I2I ReID focuses on identity-level invariance across images of the same person, T2I ReID is driven by instance-specific textual descriptions tied to unique visual traits. This paper explores the fundamental difference between two ReID tasks and their optimization processes for effective training. Since I2I and T2I ReID are often studied separately, the loss functions optimized for one retrieval setting may negatively affect the representation quality required by the other. Motivated by these findings, we propose a decoupled two-stage training pipeline for learning a shared representation across image and text modalities. The pipeline is based on a single vision encoder that supports both I2I and T2I retrieval while avoiding cross-task interference during training. We provide extensive experiments across multiple configurations, varying domain mixing procedures, learning strategies, and task objectives. We observed that I2I ReID pre-training positively impacts the generalization ability to T2I data. Besides, we find that incorporating textual supervision during the vision encoder training stage enhances both I2I and T2I performance. We believe our insights provide a meaningful step toward unified ReID systems and cross-modal retrieval overall.","authors":["Karina Kvanchiani","Timur Mamedov"],"published":"2026-06-01T13:37:55Z","updated":"2026-06-01T13:37:55Z","abstract_url":"https://arxiv.org/abs/2606.02242v1","html_url":"https://arxiv.org/html/2606.02242v1","pdf_url":"https://arxiv.org/pdf/2606.02242v1.pdf","matched_keywords":["retrieval","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02221v1","title":"CORE-MTL: Rethinking Gradient Balancing via Causal Orthogonal Representations","abstract":"Multi-task learning (MTL) aims to construct a joint model for multiple tasks by sharing a common representation across domains. To achieve this goal, existing optimization-centric methods either balance task gradients or modify the shared architecture. However, as these approaches remain agnostic to the content of the shared representation, they fail to disentangle task-relevant structure from spurious context, leading to negative transfer and poor generalization. To overcome this limitation, we propose Causal Orthogonal Representations for Multi-Task Learning (CORE-MTL), a causally motivated representation-centric framework that encourages a structured semantic-residual factorization of the shared representation, concentrating task-relevant structure in the semantic stream while relegating nuisance variation to the residual stream. We instantiate this framework in the visual domain by leveraging physical priors for structured scenes and statistical constraints for attributes. Theoretically, our method enjoys a tighter out-of-distribution generalization bound than optimization-centric methods and reduces task gradient interference without explicit gradient projection or reweighting. Empirically, CORE-MTL consistently outperforms existing methods on visual multi-task benchmarks in both in-distribution and out-of-distribution settings. Code is publicly available at https://github.com/Hope-Rita/CORE-MTL.","authors":["Chengfeng Wu","Tao Zou","Yanru Wu","Jingge Wang"],"published":"2026-06-01T13:20:58Z","updated":"2026-06-01T13:20:58Z","abstract_url":"https://arxiv.org/abs/2606.02221v1","html_url":"https://arxiv.org/html/2606.02221v1","pdf_url":"https://arxiv.org/pdf/2606.02221v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02219v1","title":"Symmetry-Aware 9D Pose Estimation with Sim(3)-Consistent Feature and Spherical Inception Convolution","abstract":"Object pose estimation is a fundamental problem for an agent system to perceive or manipulate objects in images or videos. However, current instance-level methods struggle with generalization to unseen objects. Category-level methods seek to address this, but remain constrained by the complexities of learning in the non-linear Sim(3) space and intra-class variations. To address these challenges, We propose an effective method for category-level object pose estimation with two key innovations: (1) A translation/size estimator, featuring a semantic-guided symmetry-aware module that leverages robust generalization capabilities of a large vision model (LVM) to infer symmetry points, resulting in accurate translation and size without shape priors. This result serves as a precomputed cue for rotation estimation, thereby reducing the difficulty of learning in the non-linear Sim(3) space and laying a robust foundation for tackling the inherently more challenging rotation estimation. (2) A feature fusion module, based on our proposed spherical large-kernel inception convolution, fuses semantic features from the LVM with systematically computed geometric features to extract essential pose features from intra-class variations by modeling long-range dependencies without excessive computational cost. Built on these innovations, we achieve SOTA on benchmarks and real-world scenes, while developing a robust robotic picking system capable of handling diverse objects. Our code will be available at the project page: {\\hypersetup{urlcolor=blue}https://panfei-cheng.github.io/SSH-Pose}.","authors":["Panfei Cheng","Hongshan Yu","Wenrui Chen","Xiaojun Tang","Jian Liu","Naveed Akhtar"],"published":"2026-06-01T13:20:04Z","updated":"2026-06-01T13:20:04Z","abstract_url":"https://arxiv.org/abs/2606.02219v1","html_url":"https://arxiv.org/html/2606.02219v1","pdf_url":"https://arxiv.org/pdf/2606.02219v1.pdf","matched_keywords":["video","agent","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02178v1","title":"Order within Chaos: Capturing Intrinsic Energy Anomalies for AI-Manipulated Image Forgery Localization","abstract":"Recent advancements in generative AI have led to image editing models capable of producing realistic forgeries that evade traditional image forgery localization methods, as these approaches depend on physical noise absent in synthetic data. To address this challenge, we theoretically demonstrate that the diffusion process inherently suppresses local high-frequency variance, creating a statistical energy gap that is distinguishable from the natural entropy of optical imaging. Guided by this insight, we propose FLAME, a unified framework that utilizes a LAD map to capture these intrinsic anomalies, coupled with a parameter-efficient adapter for SAM to achieve precise, pixel-level forgery localization. Furthermore, to bridge the lag between forensic benchmarks and evolving generative models, we introduce EditStream, an automated pipeline for continuous, instruction-based training data synthesis. Extensive experiments demonstrate that FLAME establishes a new state-of-the-art, significantly outperforming previous methods on AI-generated forgery datasets while effectively generalizing to unseen generative architectures. Our code is available at https://github.com/phoenixnir/FLAME.","authors":["Yiming Wang","Baiqi Wu","Qingming Li","Jiahao Chen","Tong Zhang","Shouling Ji"],"published":"2026-06-01T12:36:04Z","updated":"2026-06-01T12:36:04Z","abstract_url":"https://arxiv.org/abs/2606.02178v1","html_url":"https://arxiv.org/html/2606.02178v1","pdf_url":"https://arxiv.org/pdf/2606.02178v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02172v1","title":"Closing the Alignment-Maturity Gap in Federated Prototype Learning","abstract":"Learning discriminative visual representations from distributed, heterogeneous data is a fundamental challenge in Federated Learning (FL). Prototype-based methods address statistical heterogeneity by sharing class-level representations across clients but create a distance-dependent gradient pressure that is particularly severe during early training rounds: alignment pressure applied to immature global prototypes, aggregated from noisy local representations, generates large gradients that suppress the emergence of local discriminative structure. The result is a poorly organized embedding space and degraded recognition performance, particularly under severe non-IID conditions. We propose FedSAP, a framework that stabilises federated representation learning through two complementary mechanisms: a deterministic alignment curriculum that delays global alignment until local representations become stable and a geometry-driven proxy separation loss that enforces inter-class structure on the unit hypersphere using the existing prototype bank without introducing additional parameters or communication overhead. Together, these mechanisms produce compact, well-separated class clusters without altering the underlying communication protocol between federation's participants. Experiments across three benchmarks and varying degrees of heterogeneity show gains of up to 4 percentage points over the prototype-based baselines evaluated, with improvements most pronounced under high heterogeneity. The representational nature of our framework further enables a straightforward extension to semi-supervised settings, where unlabelled data is incorporated with minimal modification, underscoring the generality of scheduled alignment as a design principle.","authors":["Mario Casado-Diez","Alejandro Dopico-Castro","Verónica Bolón-Canedo","Bertha Guijarro-Berdiñas"],"published":"2026-06-01T12:30:53Z","updated":"2026-06-01T12:30:53Z","abstract_url":"https://arxiv.org/abs/2606.02172v1","html_url":"https://arxiv.org/html/2606.02172v1","pdf_url":"https://arxiv.org/pdf/2606.02172v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02162v1","title":"Multimodal Approaches for Visually-Rich Document Type Classification: A Comparative Analysis","abstract":"Document type classification in visually rich documents remains challenging, as relevant information is distributed across textual, visual, and layout modalities. To capture this complexity, current approaches rely on diverse multimodal modeling strategies, resulting in heterogeneous architectures that complicate systematic comparison. This variability is also reflected in existing comparative studies, which often rely on heterogeneous evaluation setups, further complicating systematic comparison and making it difficult to assess progress. To address these limitations, this work provides a structured analysis of multimodal design strategies across transformer- and LLM-based architectures, combined with a controlled empirical comparison within a unified experimental framework. Specifically, four representative models (LayoutLMv3, Donut, Qwen3-VL-32B-Instruct, and Qwen3-32B) are evaluated on the RVL-CDIP benchmark to systematically analyze the contributions of text, image, and layout information for document type classification, with a particular focus on contrasting OCR-dependent and OCR-free approaches. The results show that specialized multimodal Transformers outperform LLM-based approaches on visually rich and layout-intensive documents. Image information contributes most strongly to reliable classification, while OCR-derived text provides useful but secondary support. These findings highlight that multimodal processing remains essential for documents with pronounced layout structure. Overall, the study provides a systematic basis for comparing multimodal architectures and offers practical guidance for selecting effective feature combinations and model designs for document type classification.","authors":["Catyana Heyne","Jürgen Frikel","Filippo Riccio"],"published":"2026-06-01T12:24:26Z","updated":"2026-06-01T12:24:26Z","abstract_url":"https://arxiv.org/abs/2606.02162v1","html_url":"https://arxiv.org/html/2606.02162v1","pdf_url":"https://arxiv.org/pdf/2606.02162v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02161v1","title":"InfoMerge: Information-aware Token Compression for Efficient Video Large Language Models","abstract":"Video Large Language Models (Video-LLMs) achieve strong performance in video understanding, but their excessive visual tokens bring substantial computational overhead. Existing training-free compression methods improve inference efficiency by reducing visual tokens, yet they often rely on local adjacent-frame similarity for temporal redundancy estimation or allocate token budgets mainly according to segment length. Such designs are sensitive to frame-level noise and fail to capture the non-uniform information distribution of real-world videos. To address these challenges, we propose InfoMerge, a training-free visual token compression method that improves token utilization through robust redundancy estimation and content-aware budget allocation. Specifically, we propose the Temporal Fingerprint Difference: a segment-level second-order temporal redundancy estimation strategy, which models the temporal similarity structure of tokens at the same spatial positions within each segment. We further introduce Content-Aware Budget Allocation (CABA), which dynamically allocates segment-level token budgets based on segment uniqueness and spectral-entropy-based representational richness. By reducing repeated preservation of redundant static regions and allocating more tokens to informative segments, InfoMerge makes better use of the limited token budget while maintaining strong performance. Extensive experiments show that InfoMerge achieves strong efficiency--accuracy trade-offs across multiple benchmarks and backbones, with more pronounced advantages under aggressive compression. On LLaVA-OneVision-7B, InfoMerge retains 98.8\\% of the original average performance while reducing 85\\% of visual tokens and achieving a 4.24-fold speedup in the prefill stage.","authors":["Xinxin Liu","Shiwei Gan","Xiao Liu","Yafeng Yin","Lei Xie","Sanglu Lu"],"published":"2026-06-01T12:24:24Z","updated":"2026-06-01T12:24:24Z","abstract_url":"https://arxiv.org/abs/2606.02161v1","html_url":"https://arxiv.org/html/2606.02161v1","pdf_url":"https://arxiv.org/pdf/2606.02161v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02156v1","title":"Predicting the risk of colorectal anastomotic leak based on preoperative mapping of the blood supply of the bowel","abstract":"Anastomotic leak remains one of the most serious complications following colorectal cancer surgery, substantially affecting patient outcomes, recovery trajectories, and healthcare costs. Despite advances in imaging technology, current preoperative assessment relies only on clinical assessment, a process that is subjective, error-prone, and highly dependent on individual expertise. To date, no validated CT-based method exists to predict anastomotic leak risk prior to surgery. This protocol paper outlines a comprehensive framework for developing and validating an AI-driven system for preoperative risk assessment using pre- and post-contrast CT imaging. The study describes the stages of data collection, ethical handling, and preprocessing of patient data in accordance with GDPR, image preprocessing, and the exploration of deep learning architectures designed to generate clinically interpretable outputs. Two integrated tools constitute the main deliverables of this workflow: 1) a risk assessment module, which quantifies the likelihood of leakage by analyzing vascular and tissue features in CT scans, and 2) a Content-Based Medical Image Retrieval (CBMIR) module, which identifies and displays similar historical cases to support evidence-based surgical decision making. The protocol paper requires close collaboration between hospitals and universities; this protocol demonstrates that such a system is technically feasible and clinically implementable within existing healthcare infrastructures. By following the proposed methodological stages and regulatory principles, other institutions can reproduce this workflow to develop analogous decision-support tools. Ultimately, this interdisciplinary framework aims to enhance surgical planning, reduce leak incidence, and contribute to a broader paradigm shift toward explainable, data-driven precision surgery.","authors":["Zahra Tabatabaei","Jon Sporring","Mark Bremholm Ellebæk","Alaa El-Hussuna"],"published":"2026-06-01T12:20:43Z","updated":"2026-06-01T12:20:43Z","abstract_url":"https://arxiv.org/abs/2606.02156v1","html_url":"https://arxiv.org/html/2606.02156v1","pdf_url":"https://arxiv.org/pdf/2606.02156v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02153v1","title":"Ultra Diffusion Poser: Diffusion-Based Human Motion Tracking From Sparse Inertial Sensors and Ranging-Based Between-Sensor Distances","abstract":"Methods using inertial measurement units (IMUs) provide a wearable alternative to camera-based motion capture. To mitigate drift from inertial signals, recent sparse inertial pose estimators integrate inter-sensor distances measured by ultra-wideband (UWB) ranging. So far, UWB distances have only been used as an additional input feature, ignoring the physical constraints they impose on sensor positions. However, these distances can also be used to reconstruct the underlying 3D sensor layout, which in turn provides more informative input for pose reconstruction. We propose Ultra Diffusion Poser, a diffusion model that explicitly models these geometric constraints. It includes a Spatial Layout Module that analytically reconstructs the 3D sensor positions from UWB measurements. These sensor positions are used alongside IMU signals and UWB distances as a conditioning signal during diffusion. Still, network predictions can violate inter-sensor distance measurements. To address this, we introduce UWB-Diffusion Guidance, which encourages alignment between predicted poses and measured distances during diffusion sampling. Together, these contributions enable our model to achieve state-of-the-art performance, reducing joint position error by up to 22% over prior work.","authors":["Dominik Hollidt","Tommaso Bendinelli","Christian Holz"],"published":"2026-06-01T12:20:31Z","updated":"2026-06-01T12:20:31Z","abstract_url":"https://arxiv.org/abs/2606.02153v1","html_url":"https://arxiv.org/html/2606.02153v1","pdf_url":"https://arxiv.org/pdf/2606.02153v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02129v1","title":"Equilibrated Diffusion: Frequency-aware Textual Embedding for Equilibrated Image Customization","abstract":"Image customization learns target subjects from reference concept images and generates conditioned images per text prompts, mainly modifying styles or backgrounds. Prevailing methods adopt fine-tuning to pack diverse concept attributes into a unified latent embedding, yet entangled attributes hinder elimination of irrelevant disturbances from style and background. To address this issue, we propose Equilibrated Diffusion, a frequency-driven approach that disentangles tangled concept features for balanced customization and consistent text-visual matching. Unlike conventional methods learning full concepts with shared embeddings and unified tuning, our work utilizes the inherent link between image frequency components and semantics: low frequencies represent subject content and high frequencies correspond to styles. We decompose concepts in frequency space and optimize each embedding independently. This separate optimization enables the denoiser to capture style detached from subject identity and generalize better to unseen stylistic prompts. Merging multi-frequency embeddings preserves the model's original spatial customization ability. We further deploy mask-guided diffusion to restrict irrelevant background changes and boost text alignment. Residual Reference Attention (RRA) is inserted into spatial attention to retain subject structure and identity consistency. Experiments prove Equilibrated Diffusion exceeds mainstream baselines on subject fidelity and text adherence, verifying our method's superiority.","authors":["Liyuan Ma","Xueji Fang","Guo-Jun Qi"],"published":"2026-06-01T11:57:10Z","updated":"2026-06-01T11:57:10Z","abstract_url":"https://arxiv.org/abs/2606.02129v1","html_url":"https://arxiv.org/html/2606.02129v1","pdf_url":"https://arxiv.org/pdf/2606.02129v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02120v1","title":"Understanding-Enhanced Model Collaboration for Long-Tailed Egocentric Mistake Detection","abstract":"In this report, we address the problem of determining whether a user performs an action incorrectly from egocentric video data. To this end, we propose an Understanding-Enhanced Model Collaboration Method (UE-MCM) that combines efficient coarse-grained video understanding with accurate fine-grained action reasoning. Specifically, UE-MCM contains a small model branch and a large model branch. The large model branch focuses on whether the fine-grained action itself is executed incorrectly, while the small model branch jointly takes the coarse-grained video and fine-grained segment as input to identify actions that may be locally correct but inconsistent with the overall workflow. The small model branch is built on a CLIP4CLIP video encoder initialized from a CLIP model enhanced by Diffusion Contrastive Reconstruction, and the large model branch uses the Qwen3-VL Embedding model to extract high-capacity representations from fine-grained action segments. The small-branch prediction and the large-branch prediction are then adaptively fused by a lightweight collaboration gate. To handle the long-tailed distribution of mistake instances, we optimize the classifiers with complementary objectives, including reweighted cross-entropy, AUC-oriented learning, and label-aware adjustment. The resulting system balances speed and accuracy, making it effective for detecting subtle, rare, and ambiguous mistakes in egocentric instructional videos.","authors":["Boyu Han","Qianqian Xu","Shilong Bao","Zhiyong Yang","Ruochen Cui","Qingming Huang"],"published":"2026-06-01T11:50:16Z","updated":"2026-06-01T11:50:16Z","abstract_url":"https://arxiv.org/abs/2606.02120v1","html_url":"https://arxiv.org/html/2606.02120v1","pdf_url":"https://arxiv.org/pdf/2606.02120v1.pdf","matched_keywords":["video","representation","instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02111v1","title":"Jailbreaking Multimodal Large Language Models using Multi-Clip Video","abstract":"As multimodal large language models (MLLMs) have advanced to process video inputs, concerns have emerged about their potential for malicious misuse. Prior jailbreak studies have shown that safety alignment in MLLMs can be bypassed through visual inputs, yet it remains unclear which properties of video inputs induce this vulnerability. To address this gap, we introduce Multi-Clip Video (MCV) SafetyBench, a dataset of 2,920 videos designed to evaluate how the diversity of video inputs affects the vulnerability of MLLMs. Each video consists of multiple short clips depicting diverse contexts related to a harmful query. Experiments on eight representative video MLLMs show that attack success consistently increases with the number of clips. Our results further indicate that the video modality is (1) more vulnerable than the image modality, (2) more vulnerable to dynamic videos than to static videos, and (3) more vulnerable when videos contain more diverse contexts. Building on these findings, we propose a defense strategy that leverages the relative robustness of the image modality.","authors":["Choongwon Kang","Seungjong Sun","Hyunmin Jun","Jang Hyun Kim"],"published":"2026-06-01T11:43:53Z","updated":"2026-06-01T11:43:53Z","abstract_url":"https://arxiv.org/abs/2606.02111v1","html_url":"https://arxiv.org/html/2606.02111v1","pdf_url":"https://arxiv.org/pdf/2606.02111v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02105v1","title":"Multimodal Action Diffusion for Robust End-to-End Autonomous Driving","abstract":"End-to-End Autonomous Driving (E2E-AD) systems have largely converged on predicting intermediate trajectory waypoints, delegating final control to hand-crafted controllers with GPS access. Direct control-signal prediction (outputting throttle, steer and brake in an end-to-end fashion) remains underexplored, and critically, the role of action multimodality in such systems is not well understood. We argue that moving beyond deterministic, single-action outputs is not merely a modelling choice, but a key driver of driving performance, representational quality, and training stability. To validate this, we introduce the Action Diffusion Transformer (ADT), an anchor-free diffusion transformer trained with a MSE objective that natively models the multimodal distribution of plausible driving actions. Rather than committing to a single deterministic command, ADT generates K action candidates and selects the most suitable one at inference via Nearest Neighbour Matching (NNM). Beyond strong benchmark numbers, we show that action multimodality yields measurable benefits in learned representations and behavioral consistency, effects that deterministic architectures cannot replicate. ADT surpasses previous state-of-the-art on the challenging closed-loop Bench2Drive benchmark while achieving ten times lower latency, demonstrating that expressive, multimodal action modelling is both practically efficient and conceptually essential for robust end-to-end driving.","authors":["Jorge Daniel Rodríguez-Vidal","Diego Porres","Gabriel Villalonga Pineda","Antonio M. López Peña"],"published":"2026-06-01T11:35:35Z","updated":"2026-06-01T11:35:35Z","abstract_url":"https://arxiv.org/abs/2606.02105v1","html_url":"https://arxiv.org/html/2606.02105v1","pdf_url":"https://arxiv.org/pdf/2606.02105v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02096v1","title":"WebSpline: Structure-Informed Splines for Real-Time 3D Gaussians from Monocular Videos","abstract":"Dynamic scene reconstruction from monocular videos remains highly challenging, as existing methods often struggle to balance global structural coherence and local fine-grained details under limited multi-view cues. To address this challenge, we propose WebSpline, a novel dynamic 3D Gaussian framework that enables structurally coherent and high-fidelity reconstruction from monocular videos with fast rendering. The core of WebSpline is the Structure-Informed Spline (SIS) representation, which models each dynamic Gaussian trajectory using a learnable cubic Hermite spline whose motion is structurally organized with an auxiliary Structural Proxy Graph (SPG). The proposed framework is optimized in two stages: (i) in the first stage, the SPG is initialized from 2D point tracks and refined with temporal rigidity regularization to establish structural coherence for moving objects across the sequence; and (ii) in the second stage, the SIS representation is initialized from the refined SPG and optimized under both spatial and structural neighborhood constraints. At inference, Gaussian motion is obtained solely by evaluating the learned SIS, enabling fast rendering. Extensive experiments on the challenging monocular dynamic scene benchmarks, iPhone and NVIDIA, demonstrate that our WebSpline achieves state-of-the-art rendering quality while rendering over 10 times faster than WorldTree, the second-best method on the iPhone dataset.","authors":["Jongmin Park","Jeonghwan Yun","Minh-Quan Viet Bui","Munchurl Kim"],"published":"2026-06-01T11:28:17Z","updated":"2026-06-01T11:28:17Z","abstract_url":"https://arxiv.org/abs/2606.02096v1","html_url":"https://arxiv.org/html/2606.02096v1","pdf_url":"https://arxiv.org/pdf/2606.02096v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02090v1","title":"FocusDiT: Masking Queries in Diffusion Transformers for Fine-grained Image Generation","abstract":"Diffusion transformer (DiT) has been widely adopted in the generative diffusion field, advancing the denoising of query tokens through attention and Feed-Forward (\\text{FFN}) layers. FFN actually acts as the key-value vocabulary for decoding visual contents where the value embeds the visual semantical knowledge. We present that focusing on critical query tokens corresponding to more complex details and encouraging the model to improve these tokens is essential for fine-grained visual generation. To this end, we propose FocusDiT, which applies a Masking scheme to focus on critical query tokens that are exclusively fed into FFN. The masked queries can retrieve visual tokens from the FFN vocabularies, and use them to decode their visual details. Extensive text-to-image experiments validate the effectiveness of token masking in enhancing generative performance.","authors":["Xueji Fang","Liyuan Ma","Jianhao Zeng","Jinjin Cao","Mingyuan Zhou","Guo-Jun Qi"],"published":"2026-06-01T11:18:11Z","updated":"2026-06-01T11:18:11Z","abstract_url":"https://arxiv.org/abs/2606.02090v1","html_url":"https://arxiv.org/html/2606.02090v1","pdf_url":"https://arxiv.org/pdf/2606.02090v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02080v1","title":"Agentic-J: An AI Agent for Biological Microscopy Image Analysis","abstract":"Biological image analysis increasingly demands integration across heterogeneous tools, programming environments, and domain knowledge that few researchers can command simultaneously. We present Agentic-J, a containerised, multi-agent AI assistant, primarily for ImageJ/Fiji that enables biologists to specify analysis tasks in natural language, from nuclei segmentation and cell tracking to multi-condition quantification. The agent generates executable scripts organised into a documented project structure, so every analysis decision is traceable and the workflow can be reproduced or shared. The specialised sub-agents handle plugin management, code generation, debugging, quality assurance, and statistical reporting. In this paper we introduce the system's design, demonstrate real biological microscopy image analysis workflows, and detailed the technical implementation.","authors":["Lukas Johanns","Marilin Moor","Davide Panzeri","Yu Zhou","Xinyi Chen","Nora F. K. Pauly","Zixuan Pan","Matthias Gunzer","Andreas Müller","Yiyu Shi","Hedi Peterson","Jianxu Chen"],"published":"2026-06-01T11:10:28Z","updated":"2026-06-01T11:10:28Z","abstract_url":"https://arxiv.org/abs/2606.02080v1","html_url":"https://arxiv.org/html/2606.02080v1","pdf_url":"https://arxiv.org/pdf/2606.02080v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02068v1","title":"Fast and Lightweight Novel View Synthesis with Differentiable Multiplane Image","abstract":"Recently, novel view synthesis has witnessed remarkable progress, with mainstream methods such as Neural Radiance Fields (NeRF) and 3D Gaussian Splatting (3DGS) delivering impressive results. However, these approaches often struggle to balance rendering speed and model size, and their optimization-based training can be highly time-consuming. Furthermore, they typically rely on dense observations, often failing to produce satisfactory results under sparse-view conditions. Although feed-forward reconstruction significantly reduces the optimization time of 3DGS, its pixel-aligned formulation generates millions of Gaussians from a single image, severely limiting its practical deployment on mobile devices. To address these limitations, we revisit the Multiplane Image(MPI) representation, which represents scenes using a compact set of planar layers for efficient novel view synthesis. Leveraging recent advances in visual foundation models, we utilize predicted point maps for reliable geometric initialization, followed by differentiable optimization. To address the issues of holes and artifacts in sparsely initialized MPI, we introduce one-step diffusion, which participates in both the differentiable optimization of MPI and the postprocessing of rendering results. Compared with a representative GS-based method, our approach is 30.7% faster and uses only 14.8% of its model size, while achieving competitive synthesis quality on front-view scenarios","authors":["Kaidi Zhang","Guanxu Zhu"],"published":"2026-06-01T10:57:53Z","updated":"2026-06-01T10:57:53Z","abstract_url":"https://arxiv.org/abs/2606.02068v1","html_url":"https://arxiv.org/html/2606.02068v1","pdf_url":"https://arxiv.org/pdf/2606.02068v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02058v1","title":"TIDES: Time-Derivative Event Simulation via Deformable Reconstruction","abstract":"Event cameras emit asynchronous events in response to environmental appearance changes. The scarcity of real-world event datasets makes simulation essential. However, most simulators infer event timestamps from frame sequences, forcing many threshold crossings to share a small set of discrete times; a failure mode we term timestamp batching that worsens under fast motion and occlusion. We present TIDES, a continuous-time event simulator built on dynamic Gaussian splatting. Because TIDES operates on an explicit 3D scene representation with learnt geometry and motion, it can derive per-pixel intensity dynamics directly from the scene, rather than by differencing rendered frames. This enables accurate threshold-crossing prediction, including multiple crossings per rendering step, without temporal upsampling or frame interpolation. The same 3D scene model reveals where objects partially occlude one another; TIDES uses this to guide adaptive time stepping, concentrating computation only in regions where occlusion dynamics make simple models of brightness change unreliable. Finally, we model finite sensor bandwidth using a tile-level arbiter whose throughput, jitter, and event drops reproduce realistic sensor artifacts. Across paired RGB-event benchmarks, TIDES attains state-of-the-art event-stream fidelity. We also show that events simulated by TIDES transfer more effectively to real downstream tasks than competitors'.","authors":["Christopher Thirgood","Dipon Kumar Ghosh","Simon Hadfield"],"published":"2026-06-01T10:49:13Z","updated":"2026-06-01T10:49:13Z","abstract_url":"https://arxiv.org/abs/2606.02058v1","html_url":"https://arxiv.org/html/2606.02058v1","pdf_url":"https://arxiv.org/pdf/2606.02058v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02042v1","title":"Normality-Preserving Continual Industrial Anomaly Detection via Orthogonal LoRA Banks","abstract":"Continual industrial anomaly detection with diffusion models suffers from historical normality prior drift and catastrophic forgetting. Existing continual diffusion methods preserve previous knowledge through replay or constrained optimization, but they lack an explicit mechanism for isolating and protecting category-specific normality priors during sequential adaptation. Although low-rank adaptation provides modular residual updates, standard LoRA neither freezes historical normality subspaces nor prevents new adapters from interfering with previous ones. To address this issue, we propose a normality-preserving continual anomaly detection framework based on two modules: History Frozen Orthogonal LoRA Bank (HF-OLB) and Hierarchical Novelty Adaptive Bank Growth module (HNABG). HF-OLB freezes both the pre-trained U-Net backbone and the learned LoRA banks, and constrains new task-specific normality residuals to the orthogonal complement of historical LoRA subspaces. HNABG further allocates layer-dependent residual capacity and expands the bank only when the residual normality novelty exceeds the expressive capacity of existing banks. Extensive experiments on MVTec and VisA demonstrate the effectiveness of the proposed method. On the challenging VisA 2x6 setting, our method achieves 83.6/91.8 image and pixel level A-AUROC with 3.8/3.9 FM, improving pixel level A-AUROC over the state of the art by 3.2 points while reducing pixel level FM by 1.3. These results show that our method effectively preserves historical normality priors in long horizon continual category sequences.","authors":["Weibai Fang","Haijun Che","Feiyang Ren","Qiancheng Lao"],"published":"2026-06-01T10:30:42Z","updated":"2026-06-01T10:30:42Z","abstract_url":"https://arxiv.org/abs/2606.02042v1","html_url":"https://arxiv.org/html/2606.02042v1","pdf_url":"https://arxiv.org/pdf/2606.02042v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02031v1","title":"OpenWebRL: Demystifying Online Multi-turn Reinforcement Learning for Visual Web Agents","abstract":"Building capable visual web agents requires long-horizon reasoning, precise grounding, and robust interaction with dynamic real-world websites. Despite rapid progress, the strongest systems remain largely proprietary, while open agents still depend heavily on supervised post-training over large collections of curated web trajectories. This dependence creates a major scalability bottleneck: high-quality demonstrations are expensive to collect, and static datasets offer limited coverage of the diverse, ever-changing open web. Although online RL has shown promise for text-based agents, its potential for training visual web agents directly on live websites remains largely underexplored. In this paper, we introduce OpenWebRL, an open framework for training visual web agents with online multi-turn RL on real websites. OpenWebRL covers the full training pipeline, including scalable live-browser infrastructure, supervised initialization, multimodal context management, trajectory-level success judging, and efficient multi-turn policy optimization. Using this framework, we train OpenWebRL-4B, which establishes a new open-source state of the art on challenging live-web benchmarks. With only 0.4K initialization trajectories and 2.2K open-ended RL training tasks, OpenWebRL-4B achieves 67.0% success on Online-Mind2Web and 64.0% on DeepShop, outperforming prior open agents of similar or larger scale and remaining competitive with proprietary systems including OpenAI CUA and Gemini CUA. Beyond strong benchmark performance, we systematically study the key design choices that make online RL effective for visual web agents, and analyze how RL improves agentic reasoning. Overall, our work offers a practical path toward building more capable, reproducible, and cost-efficient open web agents. We will release our training data, models, and code to support future research.","authors":["Rui Yang","Qianhui Wu","Yuxi Chen","Hao Bai","Wenlin Yao","Hao Cheng","Baolin Peng","Huan Zhang","Tong Zhang","Jianfeng Gao"],"published":"2026-06-01T10:20:10Z","updated":"2026-06-01T10:20:10Z","abstract_url":"https://arxiv.org/abs/2606.02031v1","html_url":"https://arxiv.org/html/2606.02031v1","pdf_url":"https://arxiv.org/pdf/2606.02031v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02021v1","title":"PerBite: A Curated Diagnostic Workflow for Bite-Aware Food Volume Estimation","abstract":"Can a visually plausible food mesh be trusted to estimate the volume of consumed food? \\method investigates this question using selected paired before- and after-consumption states from the MetaFood CVPR 2026 Continuous 3D Reconstruction While Eating Challenge. The submitted workflow follows a curated reconstruction protocol: SAM~3 segments the food and plate regions; Hunyuan3D/SAM~3D generates a dimensionless food mesh; the plate diameter provides the metric scale; the plate geometry is removed in Blender; and the remaining mesh is hole-filled, made watertight, and integrated to estimate volume. MoGe-2 is used only as an auxiliary cue for initial dish-diameter estimation when direct plate measurement is uncertain; it is not the primary scale source for the reported challenge result. \\method ranks first, with an average Chamfer distance of 8.31 across 34 meshes using rigid ICP without scale correction. On 17 before- and after-pairs, it achieves 33.87\\% state-level volume MAPE and zero monotonicity violations, while consumed-volume MAPE remains 53.74\\%. The results show that surface reconstruction, metric scale, controlled mesh cleanup, watertight volume integration, and physical depletion consistency should be evaluated separately for dietary assessment. Source code and evaluation scripts will be available at \\href{https://github.com/GCVCG/PerBite-CVPR-MetaFood-2026}{github.com/GCVCG/PerBite-CVPR-MetaFood-2026}.","authors":["Ahmad AlMughrabi","Farid Al-Areqi","David Fernández Gómez","Umair Haroon","Marc Bolaños","Ricardo Marques","Petia Radeva"],"published":"2026-06-01T10:11:15Z","updated":"2026-06-01T10:11:15Z","abstract_url":"https://arxiv.org/abs/2606.02021v1","html_url":"https://arxiv.org/html/2606.02021v1","pdf_url":"https://arxiv.org/pdf/2606.02021v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02000v1","title":"Towards 3D-Aware Video Diffusion Models: Render-Free Human Motion Control with Mesh Tokenization","abstract":"Diffusion models have shown remarkable success in video generation. However, whether such models are truly aware of the 3D structure underlying visual observations, rather than simply reproducing plausible 2D projections, remains an open question. In this work, we investigate this question through human motion control, a task that requires precise modelling of 3D human geometry, motion, camera viewpoint, and scene context. Unlike prior methods that rely on rendered 2D motion guidance videos, we propose a render-free framework that conditions video generation directly on compressed 3D human mesh tokens. This representation preserves full 3D geometric information while enabling a unified token-based generation pipeline that processes video tokens jointly with motion tokens in a DiT-based architecture. This design requires the model to reason jointly about appearance, 3D structure, and camera viewpoint during video generation. Experimental results demonstrate strong performance on human motion control benchmarks, while reducing artifacts induced by view-dependent 2D guidance and trajectory-pose mismatches during editing. These findings suggest that video diffusion models, when equipped with mesh tokenization, can better capture complex 3D human structures and their interactions with the surrounding environment.","authors":["Jingyun Liang","Min Wei","Shikai Li","Yizeng Han","Hangjie Yuan","Lei Sun","Weihua Chen","Fan Wang"],"published":"2026-06-01T09:56:48Z","updated":"2026-06-01T09:56:48Z","abstract_url":"https://arxiv.org/abs/2606.02000v1","html_url":"https://arxiv.org/html/2606.02000v1","pdf_url":"https://arxiv.org/pdf/2606.02000v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01992v1","title":"A Structured Benchmark for Text-Guided Anomaly Detection: When Language Stops Conditioning the Decision","abstract":"Industrial anomaly detection has historically been a unimodal task. Recent multimodal vision-language models have produced systems that admit textual input alongside the image and are presented as enabling text-guided zero- and few-shot inspection. Yet these methods are evaluated with protocols inherited from unimodal benchmarks that hold the textual condition constant and therefore cannot measure whether language conditions the decision; whether reported gains reflect text guidance or strong pretrained visual features remains open. We introduce Text-Guided Anomaly Detection (TGAD), a structured benchmark that progressively increases the functional role of language across three scenarios: a controlled prompt-sensitivity setting on MVTec AD; a component-tagged extension of MVTec AD that requires the model to restrict its assessment to an instructed part; and the new Assembled Panel Dataset (APD), a realistic industrial setting that requires both defect-type and component-location knowledge. We evaluate one representative model per paradigm: generative large vision-language, training-free discriminative, and embedding-adaptive discriminative. In all three, the textual interface conditions the decision only superficially: prompt content is absorbed unless the object noun is removed (the generative model's I-AUROC drops from 97.4 to 82.6); component-level instructions do not constrain the decision once defects outside the instructed part are admitted as normal (from 90.3 to 66.3); and when both combine on APD, image-level discrimination collapses below the MVTec level, in one case below chance (71.2, 50.5, 31.5). These results suggest that standard benchmarks overstate the text-guided capabilities of current multimodal anomaly detection systems, and that a protocol of this kind is a prerequisite for models that can be reliably controlled through language for industrial deployment.","authors":["Stefano Samele","Eugenio Lomurno","Teodora Jovanovic","Sanjay Shivakumar Manohar","Alberto Crivellaro","Matteo Matteucci"],"published":"2026-06-01T09:50:30Z","updated":"2026-06-01T09:50:30Z","abstract_url":"https://arxiv.org/abs/2606.01992v1","html_url":"https://arxiv.org/html/2606.01992v1","pdf_url":"https://arxiv.org/pdf/2606.01992v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01955v1","title":"WALL-WM: Carving World Action Modeling at the Event Joints","abstract":"WALL-WM is a World Action Model that shifts video-action learning from chunk-centric optimization to event-grounded Vision-Language-Action pretraining, using semantically coherent action events as the atomic unit of learning. Existing WAMs commonly initialize from multimodal or video foundation models and then optimize fixed-length action chunks conditioned directly on the current observation and instruction. Although convenient, this chunk-centric formulation creates a fundamental granularity mismatch. Language describes semantic goals and events, vision evolves through continuous scene dynamics, and actions operate at control-level timescales; forcing all three into the same fixed-length prediction window turns VLA training into short-horizon correlation fitting. WALL-WM addresses this mismatch by organizing both supervision and data around semantic events. Specifically, it pairs event-grounded VLA pretraining with a data ecosystem built from event-level captions and cluster-balanced sampling, enabling scalable learning over diverse behaviors, scenes, and task structures. From the same event-pretrained backbone, WALL-WM supports two complementary inference modes. The event mode consumes next-event descriptions and enables variable-length execution chunks, while the unified mode uses a VLM with Staircase Decoding to condition conventional fixed-length chunk inference while preserving a gradient-continuous VLA path. Together with Muon-optimizer-based large-scale pretraining infrastructure, WALL-WM provides a practical scale-up recipe for general-purpose WAMs. Experiments show that WALL-WM generalizes broadly across language, scenes, and tasks, achieving state-of-the-art performance in large-scale real-world generalization evaluation.","authors":["Shalfun Li","Victor Yao","Charles Yang","Truth Qu","Regis Cheng","Ryan Yu","Howard Lu","Newton Von","Vincent Chen","Yohann Tang","Maeve Zhang","Ellie Ma","Gody Li","Sage Yang","Lorien Shu","J. W. Gao","Ethan Chen","Colin Ye","Yu Sun","Elise Mon","PS Zhang","Neo Li","Lily Li","James Wang","Ping Yang","Chris Pan","Lucy Liang","Hang Su","Roy Gan","Hao Wang","Qian Wang"],"published":"2026-06-01T09:14:51Z","updated":"2026-06-01T09:14:51Z","abstract_url":"https://arxiv.org/abs/2606.01955v1","html_url":"https://arxiv.org/html/2606.01955v1","pdf_url":"https://arxiv.org/pdf/2606.01955v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01950v1","title":"Learning Action-Conditional and Object-Centric Gaussian Splatting World Models for Rigid Objects","abstract":"World models enable intelligent agents to predict the consequences of their actions on the environment. In this paper, we propose Multi Rigid Object Gaussian World Model (MRO-GWM), a novel model that learns action-conditional dynamics of rigid objects in 3D. By representing the scene by object-centric Gaussians, we can represent arbitrary object shapes and multi-object scenes. We develop a novel spatio-temporal transformer architecture that predicts future rigid body motion from a history of object Gaussians and future actions. Objects are represented by their Gaussians in a canonical frame, which allows for describing object motion as rigid body transformation. Our model is trained on reconstructions from multiple viewpoints, which requires the model to handle partial observations of objects due to occlusions. We analyze prediction performance of our approach on synthetic datasets composed of typical household objects with multi-object dynamics and interactions by a robot end effector. We also evaluate our model in model-predictive control for non-prehensile manipulation in simulation.","authors":["Jens U. Kreber","Lukas Mack","Joerg Stueckler"],"published":"2026-06-01T09:12:07Z","updated":"2026-06-01T09:12:07Z","abstract_url":"https://arxiv.org/abs/2606.01950v1","html_url":"https://arxiv.org/html/2606.01950v1","pdf_url":"https://arxiv.org/pdf/2606.01950v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01947v1","title":"Parameter-Efficient Fine-Tuning of Large Pretrained Models for Instance Segmentation Tasks","abstract":"Research and applications in artificial intelligence have recently shifted with the rise of large pretrained models, which deliver state-of-the-art results across numerous tasks. However, the substantial increase in parameters introduces a need for parameter-efficient training strategies. Despite significant advancements, limited research has explored parameter-efficient fine-tuning (PEFT) methods in the context of transformer-based models for instance segmentation. Addressing this gap, this study investigates the effectiveness of PEFT methods, specifically adapters and Low-Rank Adaptation (LoRA), applied to two models across four benchmark datasets. Integrating sequentially arranged adapter modules and applying LoRA to deformable attention--explored here for the first time--achieves competitive performance while fine-tuning only about 1-6% of model parameters, a marked improvement over the 40-55% required in traditional fine-tuning. Key findings indicate that using 2-3 adapters per transformer block offers an optimal balance of performance and efficiency. Furthermore, LoRA, exhibits strong parameter efficiency when applied to deformable attention, and in certain cases surpasses adapter configurations. These results show that the impact of PEFT techniques varies based on dataset complexity and model architecture, underscoring the importance of context-specific tuning. Overall, this work demonstrates the potential of PEFT to enable scalable, customizable, and computationally efficient transfer learning for instance segmentation tasks.","authors":["Nermeen Abou Baker","David Rohrschneider","Uwe Handmann"],"published":"2026-06-01T09:09:32Z","updated":"2026-06-01T09:09:32Z","abstract_url":"https://arxiv.org/abs/2606.01947v1","html_url":"https://arxiv.org/html/2606.01947v1","pdf_url":"https://arxiv.org/pdf/2606.01947v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01945v1","title":"Beyond Low-Rank: Low-Rank Sparse Prompting via Spiking Neural Network and Prompt Factorization","abstract":"Visual Prompting (VP) has emerged as an efficient paradigm for adapting large-scale pre-trained vision models to downstream tasks by incorporating learnable prompts at the input level. However, existing VP methods typically employ dense pixel-level prompts, which often suffer from redundant perturbations, limited generalization and energy inefficiency. To overcome these limitations, we propose to integrate brain-inspired spiking learning into visual prompt learning tasks. As we know that spiking neuron can perform inexpensive information processing by transmitting the input data into discrete spike trains and return sparse outputs. Inspired by this, we propose \\textbf{Lo}w-\\textbf{R}ank visual \\textbf{S}pike \\textbf{P}rompting (LoRSP), a novel framework that learns dynamic low-rank sparse visual prompts naturally via a Spiking neuron learning mechanism. The core idea of LoRSP is to exploit the brain-inspired sparse firing mechanism of spiking neurons to generate pixel-level sparse prompt for each instance. To be specific, we first construct a series of prompt factors via low-rank factorization to capture distinct prompt subspaces. These prompt factors are then fed into an SNN architecture, which performs the integrate-and-fire process to emit spikes. As a result, our LoRSP generates a \\emph{sparse} visual prompt while maintaining the low-rank constraint. This design enables instance-specific selective prompting, leading to more compact and robust adaptation across diverse downstream tasks. Extensive experiments on five heterogeneous vision backbones and multiple benchmarks demonstrate that LoRSP achieves competitive performance while requiring fewer tunable parameters compared to existing VP methods.","authors":["Yumiao Zhao","Bo Jiang","Beibei Wang","Xixi Wan","Xiao Wang","Jin Tang"],"published":"2026-06-01T09:08:34Z","updated":"2026-06-01T09:08:34Z","abstract_url":"https://arxiv.org/abs/2606.01945v1","html_url":"https://arxiv.org/html/2606.01945v1","pdf_url":"https://arxiv.org/pdf/2606.01945v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01940v1","title":"SCAPO: Self-Supervised Category-Level Articulated Pose Estimation from a Single 3D Observation","abstract":"Existing methods for category-level object articulation from a single 3D observation often rely on dense supervision, multi-frame inputs, or CAD templates, and still struggle to disentangle geometry from articulation or to recover explicit joint parameters. We propose SCAPO, a self-supervised framework that estimates canonical geometry, rigid part segmentation, and joint pivots, axes, and articulation states from a single RGB-D observation without ground-truth labels or category-specific models. Our SCAPO first uses an SE(3)-equivariant vector-neuron autoencoder to factor out global pose and align diverse instances into a shared canonical space. On this aligned shape, a joint-aware blend-skinning module is then designed to model part motion. We learn this representation through cycle reconstruction between observed and canonical shapes and cross-space alignment with a learnable canonical template that decouples shared category geometry from instance-specific residual shape. Experiments on synthetic and real articulated-object datasets show that our SCAPO recovers consistent part structure and accurate articulation parameters and outperforms all self-supervised baselines.","authors":["Can Zhang","Gim Hee Lee"],"published":"2026-06-01T09:04:49Z","updated":"2026-06-01T09:04:49Z","abstract_url":"https://arxiv.org/abs/2606.01940v1","html_url":"https://arxiv.org/html/2606.01940v1","pdf_url":"https://arxiv.org/pdf/2606.01940v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-06-02T05:27:12+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":75,"new_or_recent_papers":[{"id":"2606.02580v1","title":"Thinking in Blender: Staged Executable Inverse Graphics with Vision-Language Models","abstract":"Inverse graphics is a longstanding and highly underconstrained problem that seeks to reconstruct images as editable 3D scenes which can be rendered, relit, and manipulated. In this work, we investigate whether pretrained vision-language models (VLMs) can perform executable inverse graphics directly from a single image by reconstructing a scene as an editable Blender program, without relying on specialized 2D or 3D foundation models, differentiable rendering, or multi-view supervision. We introduce Staged Executable Inverse Graphics (SEIG), an agentic framework that reconstructs a 3D scene from a single image by progressively refining scene factors including geometry, materials, composition, and lighting directly in executable Blender code space. We evaluate our framework across diverse scenes using a range of reconstruction metrics spanning pixel-level, perceptual, and semantic fidelity. Our experiments show that staged reconstruction substantially improves reconstruction fidelity, highlighting the importance of task decomposition for executable inverse graphics with general-purpose VLMs. Finally, we showcase various downstream applications enabled by the reconstructed editable Blender scenes.","authors":["Guangzhao He","Rundong Luo","Wei-Chiu Ma","Hadar Averbuch-Elor"],"published":"2026-06-01T17:59:53Z","updated":"2026-06-01T17:59:53Z","abstract_url":"https://arxiv.org/abs/2606.02580v1","html_url":"https://arxiv.org/html/2606.02580v1","pdf_url":"https://arxiv.org/pdf/2606.02580v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":50340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：Inverse graphics is a longstanding and highly underconstrained problem that seeks to reconstruct images as editable 3D scenes which can be rendered, relit, and manipulated. In this work, we investigate whether pretrained vision-language models (VLMs) can perf...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02578v1","title":"Mitigating Perceptual Judgment Bias in Multimodal LLM-as-a-Judge via Perceptual Perturbation and Reward Modeling","abstract":"Recent multimodal large language models have demonstrated strong reasoning ability, yet their reliability as automated evaluators remains limited by a critical weakness: when visual evidence conflicts with textual cues, MLLM judges tend to reward plausible narratives over perceptually correct answers. We identify and systematically analyze this phenomenon, which we term Perceptual Judgment Bias. Through controlled visual perturbations, existing multimodal judges frequently anchor on the response text instead of their own visual perception, leading to inconsistent and non-verifiable evaluations. To address this issue, we introduce the Perceptually Perturbed Judgment Dataset, which constructs minimally edited counterfactual responses that isolate perceptual errors and enable verifiable supervision. Building on this dataset, we develop a unified training framework that combines a structured GRPO-based reward with a batch-ranking objective, achieving coherent global ordering without explicit pairwise labels. Experiments across diverse MLLM-as-a-Judge benchmarks show that our approach substantially improves perceptual fidelity, ranking coherence, and alignment with human evaluation. Our results establish a scalable and generalizable pathway for training multimodal judges that are perceptually grounded, interpretable, and robust to visual-reasoning conflicts.","authors":["Seojeong Park","Jiho Choi","Junyong Kang","Seonho Lee","Jaeyo Shin","Hyunjung Shim"],"published":"2026-06-01T17:59:46Z","updated":"2026-06-01T17:59:46Z","abstract_url":"https://arxiv.org/abs/2606.02578v1","html_url":"https://arxiv.org/html/2606.02578v1","pdf_url":"https://arxiv.org/pdf/2606.02578v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":134958,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Recent multimodal large language models have demonstrated strong reasoning ability, yet their reliability as automated evaluators remains limited by a critical weakness: when visual evidence conflicts with textual cues, MLLM judges tend to reward plausible na...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02577v1","title":"RoboDream: Compositional World Models for Scalable Robot Data Synthesis","abstract":"Scaling robot learning requires large-scale, diverse demonstrations, yet real-world data collection via teleoperation remains prohibitively expensive and time-consuming. While video diffusion models offer a promising avenue for data scaling, existing generative approaches are often limited to superficial visual augmentation, or suffer from embodiment hallucinations that yield physically infeasible motions. We present a generalizable embodiment-centric world model that achieves scalable data generation by synthesizing photorealistic demonstrations with novel objects, in novel scenes, and from novel viewpoints. Our approach anchors generation to rendered robot motion while conditioning on explicit scene and object priors, effectively decoupling trajectory execution from environment synthesis. This formulation has the potential to unlock two powerful data scaling capabilities: (1) retrieval and rebirth, which repurposes existing trajectories into entirely new contexts without new motion data; and (2) prop-free teleoperation, where operators manipulate empty air and the model hallucinates the target objects and scene afterwards, eliminating reset time. We demonstrate with real-world experiments that our generated data consistently improves downstream policy performance and significantly reduces real-world data requirements across diverse manipulation tasks.","authors":["Junjie Ye","Rong Xue","Basile Van Hoorick","Runhao Li","Harshitha Rajaprakash","Pavel Tokmakov","Muhammad Zubair Irshad","Vitor Guizilini","Yue Wang"],"published":"2026-06-01T17:59:38Z","updated":"2026-06-01T17:59:38Z","abstract_url":"https://arxiv.org/abs/2606.02577v1","html_url":"https://arxiv.org/html/2606.02577v1","pdf_url":"https://arxiv.org/pdf/2606.02577v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"html","source_text_chars":43165,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, diffusion 相关；摘要显示其主要贡献为：Scaling robot learning requires large-scale, diverse demonstrations, yet real-world data collection via teleoperation remains prohibitively expensive and time-consuming. While video diffusion models offer a promising avenue for data scaling, existing generati...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02576v1","title":"ProtoAda: Prototype-Guided Adaptive Adapter Expansion and Geometric Consolidation for Multimodal Continual Instruction Tuning","abstract":"Multimodal Large Language Models (MLLMs) achieve strong performance through instruction tuning, but real-world deployment requires them to continually acquire new vision-language capabilities, making Multimodal Continual Instruction Tuning (MCIT) essential. To reduce inter-task interference and promote collaboration, recent methods often employ sparse architectures like Mixture of LoRA Experts with image-text similarity routing. However, tasks with distinct response structures could share highly similar visual-linguistic semantics and thus be wrongly routed to the same expert; image-text similarity alone is insufficient for reliable task assignment. For example, an expert in a grounding task requiring coordinate prediction may be biased toward producing short textual answers after learning semantically similar VQA tasks. This format-blind task assignment integrates heterogeneous response types into shared parameters, inducing gradient interference and ineffective expert collaboration. To address this problem, we propose ProtoAda, a prototype-guided adaptive tuning framework. ProtoAda introduces format-aware task prototypes to align task assignment and routing with both task semantics and output structure, and further consolidates format-compatible updates in a geometry-aware manner to effectively reuse and progressively refine existing parameters. Extensive experiments on multiple benchmarks demonstrate that ProtoAda achieves superior performance, especially on tasks whose answer structures are easily corrupted by sequential tuning.","authors":["Yu-Cheng Shi","Zhen-Hao Xie","Jun-Tao Tang","Da-Wei Zhou"],"published":"2026-06-01T17:59:13Z","updated":"2026-06-01T17:59:13Z","abstract_url":"https://arxiv.org/abs/2606.02576v1","html_url":"https://arxiv.org/html/2606.02576v1","pdf_url":"https://arxiv.org/pdf/2606.02576v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":71635,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) achieve strong performance through instruction tuning, but real-world deployment requires them to continually acquire new vision-language capabilities, making Multimodal Continual Instruction Tuning (MCIT) essential. T...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02575v1","title":"From Zero to Hero: Training-Free Custom Concept Spawning in World Models","abstract":"Autoregressive world models have emerged as a powerful paradigm for interactive video generation, allowing users to navigate dynamically generated environments through actions. These models are typically conditioned on a text prompt and/or a single reference frame, from which the entire world is generated. Yet the moment the user navigates beyond what is visible in that frame, the unseen regions are populated by the base model's priors, with no mechanism for the user to specify what should appear and where. This is a fundamental limitation for applications such as gaming, interactive storytelling, and simulation, where controllable scene composition is essential. We refer to this missing capability as concept spawning; introducing a user-specified visual concept into a world model, analogous to spawning in a game engine. We introduce SPAWN (Swapping Pinned Anchor with Windowed iNjection), a training-free method for concept spawning. SPAWN exploits a structural property of image-to-video backbones: the first slot of the context memory is pinned to the reference frame and acts as a foundational anchor for every generated chunk. By swapping this anchor with an external concept latent over a short injection window and letting the original anchor return, we cause the concept to propagate naturally through the rollout via the model's own memory. SPAWN supports concepts from fine-grained entities such as characters and props to large-scale elements such as buildings and landmarks, and accepts either a concept image or a text description as input. Experiments show that SPAWN integrates concepts with consistent lighting, scale, and perspective while preserving identity and temporal coherence, demonstrating that controllable concept spawning is achievable in existing autoregressive world models without any training.","authors":["Kiymet Akdemir","Pinar Yanardag"],"published":"2026-06-01T17:59:05Z","updated":"2026-06-01T17:59:05Z","abstract_url":"https://arxiv.org/abs/2606.02575v1","html_url":"https://arxiv.org/html/2606.02575v1","pdf_url":"https://arxiv.org/pdf/2606.02575v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":49764,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Autoregressive world models have emerged as a powerful paradigm for interactive video generation, allowing users to navigate dynamically generated environments through actions. These models are typically conditioned on a text prompt and/or a single reference...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:13+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02573v1","title":"HumanNOVA: Photorealistic, Universal and Rapid 3D Human Avatar Modeling from a Single Image","abstract":"In this paper, we present HumanNOVA, a photorealistic, universal, and rapid model for generating 3D human avatars from a single RGB image. Achieving both photorealism and generalization is challenging due to the scarcity of diverse, high-quality 3D human data. To address this, we build a scalable data generation pipeline that follows two strategies. The first one is to leverage existing rigged assets and animate them with extensive poses from daily life. The second strategy is to utilize existing multi-camera captures of humans and employ fitting to generate more diverse views for training. These two strategies enable us to scale up to 100k assets, significantly enhancing both the quantity and the diversity of data for robust model training. In terms of the architecture, HumanNOVA adopts a feed-forward, token-conditioned avatar modeling framework that allows fast inference in less than one second and requires no test-time optimization. Given an input image and an estimated simplified human mesh (SMPL) without detailed geometry or appearance, the model first encodes both inputs into compact token representations. These tokens then act as conditioning signals and are fused through cross-attention to construct a triplane-based 3D avatar representation. Extensive experiments on multiple benchmarks demonstrate the superiority of our approach, both quantitatively and qualitatively, as well as its robustness under diverse input image conditions. Project page at https://HumanNOVA.github.io .","authors":["Hezhen Hu","Wangbo Zhao","Lanqing Guo","Hanwen Jiang","Jonathan C. Liu","Zhiwen Fan","Kai Wang","Zhangyang Wang","Georgios Pavlakos"],"published":"2026-06-01T17:58:11Z","updated":"2026-06-01T17:58:11Z","abstract_url":"https://arxiv.org/abs/2606.02573v1","html_url":"https://arxiv.org/html/2606.02573v1","pdf_url":"https://arxiv.org/pdf/2606.02573v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":68856,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：In this paper, we present HumanNOVA, a photorealistic, universal, and rapid model for generating 3D human avatars from a single RGB image. Achieving both photorealism and generalization is challenging due to the scarcity of diverse, high-quality 3D human data...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02569v1","title":"AdaCodec: A Predictive Visual Code for Video MLLMs","abstract":"Video is temporally redundant: adjacent frames usually share most objects, background, and layout. Yet existing video multimodal large language models (video MLLMs) usually encode each sampled frame as an independent RGB image, causing visual tokens to repeat content already present in earlier frames. This suggests a more direct video interface: send a full reference frame only when the scene cannot be predicted well from prior context, and otherwise transmit a compact description of inter-frame changes. We call this interface a \\emph{predictive visual code}, and instantiate it for video MLLMs as \\textbf{AdaCodec}. AdaCodec spends full visual tokens on a reference frame only when its conditional predictive cost is high; otherwise, it encodes inter-frame changes, including motion and prediction residuals, as compact P-tokens. Across all eleven benchmarks, AdaCodec improves over the Qwen3-VL-8B per-frame RGB baseline at a matched visual-token budget. Even at $1/7$ the budget, AdaCodec with 32k tokens surpasses the 224k baseline on all long-video benchmarks; on five general-video benchmarks, it raises the average score while substantially cutting time-to-first-token from 9.26s to 1.62s.","authors":["Haowen Hou","Zhen Huang","Zheming Liang","Qingyi Si","Chenglin Li","Shuai Dong","Kele Shao","Ruilin Li","Dianyi Wang","Nan Duan","Jiaqi Wang"],"published":"2026-06-01T17:56:35Z","updated":"2026-06-01T17:56:35Z","abstract_url":"https://arxiv.org/abs/2606.02569v1","html_url":"https://arxiv.org/html/2606.02569v1","pdf_url":"https://arxiv.org/pdf/2606.02569v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":91068,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Video is temporally redundant: adjacent frames usually share most objects, background, and layout. Yet existing video multimodal large language models (video MLLMs) usually encode each sampled frame as an independent RGB image, causing visual tokens to repeat...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02565v1","title":"Policy-based Foveated Imaging and Perception","abstract":"Ultra-high-resolution image sensors offer the potential to capture fine spatial details critical for many visual perception tasks, but acquiring and processing all pixels at full resolution is often infeasible under realistic bandwidth, latency, and power constraints. Existing approaches address this challenge through acquisition strategies such as spatial or temporal downsampling, which irrevocably discard information before task relevance can be assessed. In this work, we introduce a real-time, predictive, and task-aware foveated imaging system that operates directly at image acquisition time. Leveraging emerging dual-stream sensor architectures, our method dynamically allocates limited pixel bandwidth to task-relevant regions of interest while maintaining a low-resolution global context. We formulate foveated acquisition as a sensor attention policy-learning problem, in which past observations guide actions that determine future measurements, closing the perception-acquisition loop. Through extensive simulation across multiple perception tasks, we demonstrate that our approach achieves high task performance under strict pixel budgets and significantly outperforms relevant baselines operating at the same bandwidth. We further validate our system on a 200-megapixel dual-stream sensor, capturing real-world videos under realistic bandwidth and latency constraints, demonstrating the practical feasibility of task-driven, acquisition-time foveated imaging.","authors":["Howard Xiao","Jan Ackermann","Boyang Deng","Gordon Wetzstein"],"published":"2026-06-01T17:55:05Z","updated":"2026-06-01T17:55:05Z","abstract_url":"https://arxiv.org/abs/2606.02565v1","html_url":"https://arxiv.org/html/2606.02565v1","pdf_url":"https://arxiv.org/pdf/2606.02565v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":79223,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Ultra-high-resolution image sensors offer the potential to capture fine spatial details critical for many visual perception tasks, but acquiring and processing all pixels at full resolution is often infeasible under realistic bandwidth, latency, and power con...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02564v1","title":"VLMs are Good Teachers for Video Reasoning via Adaptive Test-Time Optimization","abstract":"The recent \"Reasoning with Video\" paradigm utilizes Video Generation Models (VGMs) to generate temporally coherent visual trajectories to complete reasoning tasks. Although state-of-the-art VGMs excel at visual quality, they often struggle to understand and follow task-specific rules, leading to logical failures across diverse reasoning scenarios. Existing efforts try to utilize Vision-Language Models (VLMs) as problem pre-solvers to produce or refine textual guidance for the VGM. However, textual descriptions fail to capture intricate spatiotemporal details, and VGMs often struggle to faithfully execute fine-grained or long-tail instructions even with a valid plan. While VLMs struggle as solvers, they possess strong perception capabilities to evaluate process-constraint satisfaction and final-goal achievement. Leveraging this strength, we introduce a paradigm shift that transitions the role of VLMs to \"teachers\". Specifically, a VLM teacher extracts task-specific rules to formulate differentiable rewards, guiding a VGM Reasoner via test-time online optimization of a lightweight LoRA module. This strategy enables adaptive test-time optimization and extends the reasoning capabilities beyond the VGM's intrinsic boundaries. Evaluations on symbolic (VBVR-Bench) and general-purpose (RULER-Bench) video reasoning benchmarks show that the proposed method yields a 16.7-point average performance gain, outperforming the VLM-as-Solver paradigm (+0.4 points) and Best-of-N scaling (+2.2 points) by a large margin at comparable test-time cost. These findings reveal that integrating VLMs as test-time teachers offers a promising paradigm for achieving generalizable video reasoning. Project Page: https://VLM-as-Teacher.github.io/","authors":["Junhao Cheng","Liang Hou","Tianxiong Zhong","Xin Tao","Pengfei Wan","Kun Gai","Jing Liao"],"published":"2026-06-01T17:54:26Z","updated":"2026-06-01T17:54:26Z","abstract_url":"https://arxiv.org/abs/2606.02564v1","html_url":"https://arxiv.org/html/2606.02564v1","pdf_url":"https://arxiv.org/pdf/2606.02564v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":68161,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：The recent \"Reasoning with Video\" paradigm utilizes Video Generation Models (VGMs) to generate temporally coherent visual trajectories to complete reasoning tasks. Although state-of-the-art VGMs excel at visual quality, they often struggle to understand and f...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02553v1","title":"LongLive-RAG: A General Retrieval-Augmented Framework for Long Video Generation","abstract":"Autoregressive (AR) video diffusion enables variable-length synthesis, but long-horizon generation often suffers from accumulated errors and identity drift. For efficiency, existing methods commonly adopt sliding-window attention during generation. This creates an irreversible generation trajectory: once the active window accumulates appearance errors, subsequent generations can only condition on this degraded trajectory and drift further away. We address this limitation by formulating long video generation as a retrieval-augmented generation (RAG) problem. Rather than relying solely on the recent window, we treat previously generated latents as a dynamic, searchable history. We propose LongLive-RAG, a general retrieval framework for AR video generation. At each new block, LongLive-RAG uses a query embedding to retrieve relevant historical latents. This lightweight retrieval step adds only a small overhead relative to generation and lets the generator condition on non-local context instead of only the recent window. To make retrieval more discriminative, we introduce the Window Temporal Delta Loss that suppresses redundant local similarity and encourages embeddings to capture meaningful temporal changes. Together, these components help reduce error accumulation caused by sliding-window attention. Experiments across multiple AR backbones and generation lengths show improved long-video quality and the best average VBench-Long rank. To our knowledge, among open-ended AR long video generation methods, LongLive-RAG is the first to formulate self-generated latent history as content-addressable retrieval memory. Code is available at https://github.com/qixinhu11/LongLive-RAG.","authors":["Qixin Hu","Shuai Yang","Wei Huang","Song Han","Yukang Chen"],"published":"2026-06-01T17:50:49Z","updated":"2026-06-01T17:50:49Z","abstract_url":"https://arxiv.org/abs/2606.02553v1","html_url":"https://arxiv.org/html/2606.02553v1","pdf_url":"https://arxiv.org/pdf/2606.02553v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"html","source_text_chars":65372,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, diffusion 相关；摘要显示其主要贡献为：Autoregressive (AR) video diffusion enables variable-length synthesis, but long-horizon generation often suffers from accumulated errors and identity drift. For efficiency, existing methods commonly adopt sliding-window attention during generation. This creat...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02552v1","title":"Modeling Depth Ambiguity: A Mixture-Density Representation for Flying-Point-Free Depth Estimation","abstract":"Despite advances in depth estimation, flying points remain a persistent failure mode: near object boundaries, depth estimators often predict spurious 3D points in the empty space between foreground and background surfaces. We trace this artifact to a standard modeling choice: assigning each pixel a single depth hypothesis. At boundaries, a pixel can straddle a foreground and a background surface, so its true depth is ambiguous between the two. A model that predicts a single depth cannot keep both possibilities, so training instead pulls the prediction toward an intermediate depth that lies on neither surface. We address this with MDA, a mixture-density representation that lets the model predict multiple depth hypotheses and their associated probabilities for each pixel. Near boundaries, different hypotheses can align with different surfaces, and the decoded depth is selected from one of these hypotheses rather than placed in the empty space between them. Across different backbones, MDA substantially improves boundary reconstruction and largely removes flying-point artifacts even under severe input blur, while adding negligible runtime overhead. The same mixture-density framework naturally extends to transparent objects, where it predicts multiple depth layers at transparent pixels, and to sky regions, where a dedicated component separates the unbounded sky from finite-depth regions, producing flying-point-free skylines. Project Page: https://biansy000.github.io/mda-site/.","authors":["Siyuan Bian","Congrong Xu","Jun Gao"],"published":"2026-06-01T17:50:28Z","updated":"2026-06-01T17:50:28Z","abstract_url":"https://arxiv.org/abs/2606.02552v1","html_url":"https://arxiv.org/html/2606.02552v1","pdf_url":"https://arxiv.org/pdf/2606.02552v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":91281,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Despite advances in depth estimation, flying points remain a persistent failure mode: near object boundaries, depth estimators often predict spurious 3D points in the empty space between foreground and background surfaces. We trace this artifact to a standard...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02551v1","title":"AFUN: Towards an Affordance Foundation Model for Functionality Understanding","abstract":"Affordance understanding bridges visual perception and physical action, serving as an explainable interface for robot manipulation in open and unstructured real-world environments. Yet, building an affordance foundation model that not only understands where and how the interaction should happen, but also generalizes across diverse environments, objects, and tasks, remains a long-standing research challenge. Existing methods typically address only part of this challenge, either localizing task-relevant regions without specifying executable motion, or predicting motion but with limited scalability. In this paper, we present ourmodel, a step towards an affordance foundation model for functionality understanding. From a single RGB-D observation and a language task description, ourmodel predicts a task-conditional functional mask (where to interact) and a 3D post-contact motion curve (how to interact). To support open-world generalization, we build a large-scale standardized data pipeline that converts heterogeneous robot, human, simulation, and real-world scan data into a shared affordance schema with language, masks, and object-centric 3D motion labels. We evaluate ourmodel from three aspects: for affordance segmentation, ourmodel outperforms all baselines by a large margin across 8 test sets from 4 benchmarks, improving mean gIoU/cIoU by +23.9/+26.3; for contact-point prediction, it predicts substantially more accurate points, with a 12.7--61.3% hit-rate gain over the best baseline; and for 3D motion, it achieves the best performance on all three test sets. ourmodel can be deployed for real-world robot manipulation without finetuning for robot embodiment or using task-specific heuristics, demonstrating the ability to adapt to open-world affordance tasks. Project page: https://www.zhaoningwang.com/AFUN","authors":["Zhaoning Wang","Yi Zhong","Jiawei Fu","Henrik I. Christensen","Jun Gao"],"published":"2026-06-01T17:50:16Z","updated":"2026-06-01T17:50:16Z","abstract_url":"https://arxiv.org/abs/2606.02551v1","html_url":"https://arxiv.org/html/2606.02551v1","pdf_url":"https://arxiv.org/pdf/2606.02551v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":92760,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Affordance understanding bridges visual perception and physical action, serving as an explainable interface for robot manipulation in open and unstructured real-world environments. Yet, building an affordance foundation model that not only understands where a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02532v1","title":"Improving Combined Detection and Classification of TEM Defects via Mask-Conditioned Latent Diffusion Augmentation","abstract":"Analyzing microstructural defects in transmission electron microscopy (TEM) images, particularly in irradiated metal alloys, is often limited by the availability of high-quality, labeled data. To address this, we introduce a generative data augmentation approach using a mask-conditioned latent diffusion model (LDM) for synthesizing realistic TEM images with controllable, automatically labeled multi-class defect masks. Without requiring manual annotations for generation, our method enables the creation of synthetic image-mask pairs by sampling distributions learned from experimental masks. These generated data were used to augment small experimental datasets of varying sizes (10, 50, and 100 labeled experimental images) to train a Mask Regional Convolutional Neural Network (R-CNN) model for defect detection and classification. Our results show that generative augmentation yields small overall model performance improvements, with up to a 0.02 gain in the harmonic mean of detection and classification F1 scores. However, we also find that the relative contributions to detection and classification improvement depend on the specific train/test data split. These findings highlight the potential of targeted generative models to enhance deep learning performance in data-scarce microscopy-based image quantification tasks.","authors":["Ni Li","Nuohao Liu","Ryan Jacobs","Ajay Annamareddy","Maciej P. Polak","Kevin Field","Izabela Szlufarska","Dane Morgan"],"published":"2026-06-01T17:38:47Z","updated":"2026-06-01T17:38:47Z","abstract_url":"https://arxiv.org/abs/2606.02532v1","html_url":"https://arxiv.org/html/2606.02532v1","pdf_url":"https://arxiv.org/pdf/2606.02532v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":50380,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Analyzing microstructural defects in transmission electron microscopy (TEM) images, particularly in irradiated metal alloys, is often limited by the availability of high-quality, labeled data. To address this, we introduce a generative data augmentation appro...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02526v1","title":"Why Not Hyperparameter-Friendly Optimisation? A Monotonic Adaptive Norm Rescaling Approach For Long-Tailed Recognition","abstract":"Long-tailed recognition poses a significant challenge for deep learning. The two-stage decoupling paradigm, which separates representation learning from classifier retraining, offers a promising solution. During the classifier retraining stage, adaptive norm rescaling is a popular technique. It adjusts the per-class weight norms via parameter regularization, which inevitably introduces hyperparameters. However, many studies report that long-tailed recognition is sensitive to these hyperparameters, as their setup significantly impacts performance. In this paper, we first provide a class-conditional distribution perspective to support norm rescaling methods. Furthermore, we propose a simple but effective approach called Self-Adaptive Monotonic Normalization (SAMN). SAMN avoids the need for parameter regularization. It directly enforces monotonicity on per-class weight norms using the Pool Adjacent Violators Algorithm, making the method hyperparameter-friendly. SAMN is a universal strategy that integrates seamlessly with other methods for enhanced performance. Experiments on benchmark datasets demonstrate that our method significantly boosts long-tailed recognition performance, often achieving state-of-the-art results.","authors":["Shuo Zhang","Chenqi Li","Tingting Zhu"],"published":"2026-06-01T17:34:38Z","updated":"2026-06-01T17:34:38Z","abstract_url":"https://arxiv.org/abs/2606.02526v1","html_url":"https://arxiv.org/html/2606.02526v1","pdf_url":"https://arxiv.org/pdf/2606.02526v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64514,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Long-tailed recognition poses a significant challenge for deep learning. The two-stage decoupling paradigm, which separates representation learning from classifier retraining, offers a promising solution. During the classifier retraining stage, adaptive norm...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:14+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02523v1","title":"FigSIM: A Dataset for Fine-grained Suicide Severity and Figurative Language in Suicide Memes","abstract":"Suicide memes are memes used to express suicide-related thoughts or comment on suicide-related issues. Suicide memes are increasingly common on social media, yet remain poorly understood and potentially harmful. There is an urgent need to better understand their characteristics and to develop appropriate content moderation strategies that limits users' exposure to potentially harmful content. Currently, the absence of annotated datasets of suicide memes remains a key barrier to developing and evaluating automated moderation approaches. In this paper, we introduce FigSIM, the first dataset designed for fine-grained analysis of suicide memes. The dataset consists of 1049 memes, each annotated for (1) fine-grained suicide severity levels, (2) figurative phenomena (e.g., metaphors), and (3) suicide-related content (e.g., suicide method depiction). We benchmark 16 unimodal and multimodal models across three tasks: figurative language, suicide severity, and suicide-related content detection. Overall, FigSIM demonstrates that suicide memes pose unique challenges for both modeling and content moderation. Analysis revealed biases, such as underprediction of higher suicide severity levels, especially for figurative memes. The dataset (including splits used for analyses) is publicly available. Content Warning: This paper contains suicide-related content that may be triggering.","authors":["Liuliu Chen","Elise R. Carrotte","Brian E. Chapman","Jo Robinson","Mike Conway"],"published":"2026-06-01T17:32:29Z","updated":"2026-06-01T17:32:29Z","abstract_url":"https://arxiv.org/abs/2606.02523v1","html_url":"https://arxiv.org/html/2606.02523v1","pdf_url":"https://arxiv.org/pdf/2606.02523v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":76961,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Suicide memes are memes used to express suicide-related thoughts or comment on suicide-related issues. Suicide memes are increasingly common on social media, yet remain poorly understood and potentially harmful. There is an urgent need to better understand th...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02522v1","title":"Moment-Video: Diagnosing Temporal Fidelity of Video MLLMs on Momentary Visual Events","abstract":"Video multimodal large language models (MLLMs) have made rapid progress on general and long-form video understanding, yet their ability to preserve brief answer-critical visual evidence remains underexplored. Many practical questions are determined by momentary visual events: localized actions or state transitions that may last only a few frames. Such evidence can be skipped by sparse frame sampling, suppressed by visual-token compression, or diluted by coarse temporal aggregation, causing failures that language-side reasoning cannot reliably recover. We introduce Moment-Video, a benchmark for diagnosing the temporal fidelity of video MLLMs through momentary visual event understanding. Each question is grounded in a localized, visually observable, and sampling-sensitive event, requiring models to notice, count, describe, or reason about transient evidence rather than rely on persistent objects, global scene context, or language priors. Moment-Video contains 1,000 human-verified video-QA pairs across 7 domains and 25 fine-grained subcategories, covering four task types: Temporal Occurrence, Temporal Counting, Action Description, and Temporal Reasoning. We evaluate 33 proprietary and open-source MLLMs on Moment-Video. The best-performing model, Seed-2.0-Pro, achieves only 39.6% overall accuracy, while most open-source models remain below 25%, revealing a substantial gap in momentary visual event understanding. Diagnostic analyses show that denser frame sampling improves some models but does not eliminate the bottleneck, and longer videos introduce stronger temporal-localization challenges. These findings suggest that current video MLLMs still lack temporally faithful representations for capturing, preserving, and using brief but decisive visual evidence.","authors":["Xiaolin Liu","Yilun Zhu","Xiangyu Zhao","Xuehui Wang","Yan Li","Xin Li","Haoyu Cao","Xing Sun","Shaofeng Zhang","Xu Yang","Zhihang Zhong","Xue Yang"],"published":"2026-06-01T17:32:20Z","updated":"2026-06-01T17:32:20Z","abstract_url":"https://arxiv.org/abs/2606.02522v1","html_url":"https://arxiv.org/html/2606.02522v1","pdf_url":"https://arxiv.org/pdf/2606.02522v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"html","source_text_chars":82246,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, multimodal 相关；摘要显示其主要贡献为：Video multimodal large language models (MLLMs) have made rapid progress on general and long-form video understanding, yet their ability to preserve brief answer-critical visual evidence remains underexplored. Many practical questions are determined by momenta...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02510v1","title":"Not All Points Are Equal: Uncertainty-Aware 4D LiDAR Scene Synthesis","abstract":"Constructing faithful 4D worlds from LiDAR-acquired sequences is crucial for embodied AI, yet current generative frameworks apply uniform modeling capacity across all spatial regions. This ignores that perceptual difficulty varies dramatically within a single scan: distant surfaces, occluded boundaries, and small-scale objects carry far higher uncertainty than well-observed structures. We present U4D, a new framework that explicitly leverages spatial uncertainty to guide LiDAR scene generation in a \"hard-to-easy\" schedule. U4D derives per-point uncertainty maps via Shannon Entropy from a pretrained segmentor, then applies an unconditional diffusion stage to synthesize high-entropy areas with precise geometry, followed by a conditional completion stage that fills in the remaining regions using these structures as priors. A MoST (Mixture of Spatio-Temporal) block further maintains cross-frame coherence by dynamically balancing spatial detail and temporal continuity. Extensive experiments on nuScenes and SemanticKITTI demonstrate state-of-the-art scene fidelity, temporal consistency, and downstream performance.","authors":["Xiang Xu","Alan Liang","Youquan Liu","Xian Sun","Linfeng Li","Lingdong Kong","Ziwei Liu","Qingshan Liu"],"published":"2026-06-01T17:24:14Z","updated":"2026-06-01T17:24:14Z","abstract_url":"https://arxiv.org/abs/2606.02510v1","html_url":"https://arxiv.org/html/2606.02510v1","pdf_url":"https://arxiv.org/pdf/2606.02510v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":19205,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Constructing faithful 4D worlds from LiDAR-acquired sequences is crucial for embodied AI, yet current generative frameworks apply uniform modeling capacity across all spatial regions. This ignores that perceptual difficulty varies dramatically within a single...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02506v1","title":"Question-Aware Evidence Ledgers for Video Relational Reasoning","abstract":"The VRR-QA challenge evaluates visual relational reasoning in videos, where answers often depend on implicit spatial relations, event boundaries, target identity, and dialogue context rather than a single salient frame. We present a test-time reasoning pipeline built around a strong GPT-5.5 video QA solver and a set of question-aware evidence ledgers. The initial solver answers each question from a uniform video representation, while routed ledgers are prompted to make the required targets, count units, reference frames, and temporal or spatial scope explicit for counting, spatial, endpoint, viewpoint, and dialogue reasoning. External tools such as open-vocabulary detection, depth cues, pair crops, ASR, and scene-graph ledgers are used only as evidence sources. A conservative gate keeps the current answer unless independent evidence uniquely supports a different option. The final evidence-gated pipeline achieves 92.95% overall accuracy and 93.79% macro accuracy on the challenge test split.","authors":["Yilin Ou","Mengshi Qi","Huadong Ma"],"published":"2026-06-01T17:18:03Z","updated":"2026-06-01T17:18:03Z","abstract_url":"https://arxiv.org/abs/2606.02506v1","html_url":"https://arxiv.org/html/2606.02506v1","pdf_url":"https://arxiv.org/pdf/2606.02506v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":22265,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：The VRR-QA challenge evaluates visual relational reasoning in videos, where answers often depend on implicit spatial relations, event boundaries, target identity, and dialogue context rather than a single salient frame. We present a test-time reasoning pipeli...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02498v1","title":"GloResNet: A lightweight 3D CNN with global topological features for preterm brain injury prediction","abstract":"This study introduces an automated deep learning framework for predicting brain injury (BI) in preterm infants from T2-weighted MRI (dHCP dataset). We propose GloResNet, a lightweight 3D CNN based on ResNet-10, pretrained on MedicalNet to address data scarcity. A global manifold mapping strategy first resamples each 3D volume to 128x128x128 and then applies subject-wise z-score intensity normalization, thereby preserving global topology while standardizing appearance. Training integrates mixup, class weighting, and test-time augmentation for robustness. In 5-fold cross-validation, GloResNet achieved 75.18% average accuracy (peak 81.82%), with specificity 0.81 and sensitivity 0.76. Results demonstrate that a topology-aware lightweight CNN has the capability to effectively predict neonatal BI, offering a non-invasive screening tool. The source code of this paper can be obtained from the GitHub repository: https://github.com/ICL-SUST/GloResNet-Preterm-Brain","authors":["Boyu Yuan","Jiamiao Lu","Weichuan Zhang","Benqing Wu","Tuo Wang","Changshan Wang","Changming Sun","Liang Guo"],"published":"2026-06-01T17:04:43Z","updated":"2026-06-01T17:04:43Z","abstract_url":"https://arxiv.org/abs/2606.02498v1","html_url":"https://arxiv.org/html/2606.02498v1","pdf_url":"https://arxiv.org/pdf/2606.02498v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":70945,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：This study introduces an automated deep learning framework for predicting brain injury (BI) in preterm infants from T2-weighted MRI (dHCP dataset). We propose GloResNet, a lightweight 3D CNN based on ResNet-10, pretrained on MedicalNet to address data scarcit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02491v1","title":"MORPHOS: Autoregressive 4D Generation with Temporal Structured Latents","abstract":"We present MORPHOS, a novel autoregressive framework that generates dynamic 3D assets from videos across diverse representations, including meshes, 3D Gaussians, and radiance fields. Existing methods are typically limited to a single representation, struggle to model topological changes, or fail to maintain temporal consistency over long videos. To address these limitations, we introduce the Temporal Structured Latents (T-SLAT), a unified 4D representation that jointly encodes geometry and appearance along the temporal dimension. Leveraging T-SLAT, MORPHOS autoregressively generates dynamic 3D assets via causal attention, conditioning each frame on its preceding history to ensure temporal consistency while handling evolving topologies. We also propose a temporal-structural augmentation to mitigate error accumulation in autoregressive generation. MORPHOS achieves state-of-the-art performance in appearance and competitive results in geometry across multiple benchmarks, demonstrating superior generalization across various representations and robustness in long-horizon generation.","authors":["Minkyung Kwon","Jinhyeok Choi","Youngjin Shin","Jaeyeong Kim","JongMin Lee","Seungryong Kim"],"published":"2026-06-01T17:01:21Z","updated":"2026-06-01T17:01:21Z","abstract_url":"https://arxiv.org/abs/2606.02491v1","html_url":"https://arxiv.org/html/2606.02491v1","pdf_url":"https://arxiv.org/pdf/2606.02491v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"html","source_text_chars":67317,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation 相关；摘要显示其主要贡献为：We present MORPHOS, a novel autoregressive framework that generates dynamic 3D assets from videos across diverse representations, including meshes, 3D Gaussians, and radiance fields. Existing methods are typically limited to a single representation, struggle...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-02T05:27:15+00:00","status":"fallback"},"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02482v1","title":"X-Stream: Exploring MLLMs as Multiplexers for Multi-Stream Understanding","abstract":"While video streaming understanding has made significant strides, real-world applications, such as live sports broadcasting, autonomous driving, and multi-screen collaboration, inherently demand continuous, multi-stream interactions. However, existing benchmarks are confined to single-stream paradigms, leaving a critical gap in evaluating online, cross-stream reasoning. To bridge this, we introduce X-Stream, the first benchmark dedicated to multi-stream streaming understanding. Comprising 4,220 rigorously curated QA pairs across 932 videos, X-Stream evaluates 11 subtasks across multi-window, multi-view, and multi-device scenarios. Crucially, our dataset is constructed using a novel dual-verification pipeline that prevents over-reliance on a single stream. Furthermore, we pioneer the conceptualization of multi-modal large language models (MLLMs) as naive multiplexers, systematically evaluating their performance through the lens of Signal Multiplexing Theory. Our extensive online inference experiments reveal a stark reality: state-of-the-art MLLMs struggle significantly with concurrent streams, achieving only about 50% score and exhibiting poor proactive ability. Ultimately, X-Stream exposes the trade-off of current multiplexing schemes, providing both a practical evaluation protocol and empirical guidance for next-generation multi-stream agents.","authors":["Peiwen Sun","Xudong Lu","Huadai Liu","Yang Bo","Dongming Wu","Huankang Guan","Minghong Cai","Jinpeng Chen","Xintong Guo","Shuhan Li","Rui Liu","Xiangyu Yue"],"published":"2026-06-01T16:52:11Z","updated":"2026-06-01T16:52:11Z","abstract_url":"https://arxiv.org/abs/2606.02482v1","html_url":"https://arxiv.org/html/2606.02482v1","pdf_url":"https://arxiv.org/pdf/2606.02482v1.pdf","matched_keywords":["video","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02479v1","title":"Retrieve What's Missing: Coverage-Maximizing Retrieval for Consistent Long Video Generation","abstract":"Maintaining long-term geometric consistency remains challenging for long-horizon autoregressive video generation. Memory-augmented generative models address this by retrieving historical frames, but their effectiveness depends on two key design choices: what 3D-geometric evidence should represent past observations, and how memory frames should be selected from this evidence. Existing methods often rely on camera poses or field-of-view overlap, which are lightweight but too coarse to reason about pixel-wise visibility, or use explicit 3D reconstruction, which provides fine-grained evidence but is costly to maintain over long rollouts. We propose Coverage-Maximizing Retrieval-Augmented Generation (COVRAG), a depth-based memory retrieval framework that uses pretrained 3D priors to construct a target-view coverage map as lightweight 3D memory evidence. For frame selection, COVRAG maximizes residual coverage gain, iteratively retrieving frames that explain target-view regions not covered by the current context or previously selected memories. To improve scalability in long-video generation, we introduce sliding-window depth caching for efficient geometry estimation. Experiments on RealEstate10K and DL3DV10K show that COVRAG improves long-horizon geometric consistency while maintaining low latency compared to baselines.","authors":["Minseok Joo","Dogyun Park","Taehoon Lee","Kyujin Lee","Hyunwoo J. Kim"],"published":"2026-06-01T16:49:58Z","updated":"2026-06-01T16:49:58Z","abstract_url":"https://arxiv.org/abs/2606.02479v1","html_url":"https://arxiv.org/html/2606.02479v1","pdf_url":"https://arxiv.org/pdf/2606.02479v1.pdf","matched_keywords":["video","retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02463v1","title":"MASER: Modality-Adaptive Specialist Routing for Embodied 3D Spatial Intelligence","abstract":"In 3D environments, Embodied Agents answer spatially relevant questions through reasoning from a mixture of modalities including natural language, RGB images, point clouds, depth maps and camera poses. Existing Vision-Language models (VLMs) are fine-tuned over a single modality. This completely ignores the question semantics which may favor a different modality than the finetuned modality. To address this, we propose MASER (Modality-Adaptive SpEcialist Routing), a lightweight framework that trains five different modality adapters of a shared VLM backbone and learns a neural routing policy that selects the best adapter based on the question during inference. We encode each question with a frozen sentence transformer and pass the embedding through a small Multi-layer Perceptron (MLP) trained on oracle adapter-accuracy labels. We evaluate our methodology over the Open3D-VQA benchmark and our evaluations show that no single modality is universally optimal -- point-cloud answers are best in 51.5% of cases. MASER routes with 51.3% oracle agreement, outperforming a Random-Forest ablation (43.5%), with only a single adapter call per question.","authors":["Hilton Raj","Vishnuram AV"],"published":"2026-06-01T16:36:21Z","updated":"2026-06-01T16:36:21Z","abstract_url":"https://arxiv.org/abs/2606.02463v1","html_url":"https://arxiv.org/html/2606.02463v1","pdf_url":"https://arxiv.org/pdf/2606.02463v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02459v1","title":"Active Exploring like a Pigeon: Reinforcing Spatial Reasoning via Agentic Vision-Language Models","abstract":"Enabling Vision-Language Models (VLMs) to perform spatial reasoning remains challenging. Existing approaches treat VLMs as passive observers, which is difficult for real-world applications. Moreover, reinforcement learning methods rely on sparse rewards, limiting their effectiveness for complex reasoning tasks. Inspired by pigeons' building and exploiting cognitive maps for navigation, we propose a novel agentic pipeline for spatial reasoning. First, we introduce a new \\emph{dynamic cognitive map} parameterizing scene layout as object positions and orientations, serving as persistent memory for new observations. Second, we propose a novel \\emph{Spatial Assertion Codes (SAC)}, Python expressions programmatically describing spatial relationships. By collaborating with the dynamic cognitive map, SAC enables verification of intermediate reasoning steps, providing dense reward signals. We optimize the model via supervised and reinforcement finetuning. Experiments on the MindCube benchmark demonstrate state-of-the-art performance with \\emph{80.5\\%} overall accuracy, outperforming the best current method by \\emph{29.5} accuracy points (a relative improvement of \\emph{53.2\\%}) on the challenging \\textsc{Rotation} subset. Our code and data are open-sourced at https://github.com/dw-dengwei/active-spatial-reasoning.git.","authors":["Wei Deng","Xianlin Zhang","Mengshi Qi"],"published":"2026-06-01T16:30:56Z","updated":"2026-06-01T16:30:56Z","abstract_url":"https://arxiv.org/abs/2606.02459v1","html_url":"https://arxiv.org/html/2606.02459v1","pdf_url":"https://arxiv.org/pdf/2606.02459v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02453v1","title":"Initialization is Half the Battle: Generating Diverse Images from a Guidance Potential Posterior","abstract":"Despite the remarkable fidelity of generative models, they frequently suffer from mode collapse. Existing strategies for enhancing diversity predominantly focus on intervening during the generation trajectory. We identify a critical oversight that the standard Gaussian initialization often causes trajectories to collapse into dominant modes because it is agnostic to the guidance potential landscape. In this work, we formulate selecting the initial noise from a guidance potential posterior, which effectively re-weights the prior towards diversity-rich regions. To sample from this distribution efficiently, we introduce Diversity-inducing Initialization (DivIn), which leverages Langevin dynamics to actively navigate the initialization landscape, steering initial noise away from collapsing regions while anchoring them to the valid data manifold. Our method serves as an inference-time diversity enhancement compatible with both diffusion and flow matching models. Extensive experiments show that DivIn exhibits a superior performance in both class-to-image and text-to-image scenarios. Furthermore, we highlight that as DivIn is orthogonal to trajectory-based methods, combining them significantly expands the diversity-quality Pareto frontier beyond what either achieves in isolation.","authors":["Xiang Li","Dianbo Liu","Kenji Kawaguchi"],"published":"2026-06-01T16:25:10Z","updated":"2026-06-01T16:25:10Z","abstract_url":"https://arxiv.org/abs/2606.02453v1","html_url":"https://arxiv.org/html/2606.02453v1","pdf_url":"https://arxiv.org/pdf/2606.02453v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02450v1","title":"Reason-Then-Retrieve for CoVR-R with Structured Edit Prompts and Dense-Sparse Fusion","abstract":"CoVR-R studies reason-aware composed video retrieval: given a reference video and an edit instruction, the system must retrieve the target video that satisfies the edit. The main difficulty is that the target is not described directly; it must be inferred from fine-grained changes in object identity, action order, final state, hand interaction, and scene transition. We build a zero-shot reason-then-retrieve pipeline around Qwen3.5-27B. For each gallery video, the model generates a retrieval-oriented structured description and a dense embedding by pooling generated-token hidden states with token-dependent weights. For each query, the model first performs edit reasoning over the reference video and instruction, then generates a target-video description whose hidden states serve as the query embedding. We complement dense retrieval with a TF-IDF branch over the generated texts and fuse the two rankings with split-specific weights. On validation, the current best submission reaches 80.81 at R@1, 94.86 at R@5, 97.11 at R@10, and 98.59 at R@50. On the blind test split, it reaches 89.73 at R@1, 95.79 at R@5, 96.63 at R@10, and 97.98 at R@50.","authors":["DongQing Liu","MengShi Qi","HongWei Ji"],"published":"2026-06-01T16:21:01Z","updated":"2026-06-01T16:21:01Z","abstract_url":"https://arxiv.org/abs/2606.02450v1","html_url":"https://arxiv.org/html/2606.02450v1","pdf_url":"https://arxiv.org/pdf/2606.02450v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02449v1","title":"HLL: Can Agents Cross Humanity's Last Line of Verification?","abstract":"Multimodal agents are increasingly expected to operate interfaces on behalf of users, raising a central deployment question: can they truly substitute for humans in workflows that services deliberately protect against automation? CAPTCHA verification makes this question concrete. It is not merely a visual puzzle, but a human-verification boundary placed before account creation, content access, form submission, and other protected actions. We introduce \\textbf{Humanity's Last Line of Verification (HLL)}, a controlled benchmark that uses interactive CAPTCHA verification to evaluate whether agents can cross this boundary through grounded, human-like interaction rather than recognition alone. HLL covers diverse CAPTCHA interactions and exposes agents to controlled realism stressors, including cluttered webpages, harder task variants, and trace-conditioned validation of the solving process. We evaluate eight frontier multimodal agents in a closed-loop GUI environment. The results show that current agents remain brittle at this human-substitution boundary: performance varies sharply across verification types, degrades under realistic interface conditions, and drops further when correct answers must be supported by valid action traces. By exposing gaps in localization, action calibration, state tracking, and process consistency, HLL provides a concrete testbed for measuring how close multimodal agents are to acting as human substitutes in protected real-world workflows. Our code is available at https://github.com/XinhaoS0101/HLL","authors":["Xinhao Song","Su Su","Sirui Song","Hongliang Wu","Wen Shen","Zhihua Wei","Gongshen Liu","Linfeng Zhang","Dongrui Liu"],"published":"2026-06-01T16:20:45Z","updated":"2026-06-01T16:20:45Z","abstract_url":"https://arxiv.org/abs/2606.02449v1","html_url":"https://arxiv.org/html/2606.02449v1","pdf_url":"https://arxiv.org/pdf/2606.02449v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02443v1","title":"PaSBench-Video: A Streaming Video Benchmark for Proactive Safety Warning","abstract":"Between the first visible sign of danger and the moment an accident occurs, there is often a window where intervention remains possible. Video-capable multimodal large language models (MLLMs) could serve as always-on safety monitors that issue warnings during this window. Yet current benchmarks do not test this ability: they rely on static inputs, ignore timing precision, and omit false-positive measurement on safe scenes. We present PaSBench-Video, a 740-video benchmark with 481 risk and 259 no-risk videos across four domains: driving, healthcare, daily life, and industrial production. Risk videos are annotated with frame-level risk onset and accident boundaries. A model must observe the video causally and produce a warning that is both temporally calibrated and content-correct. Testing 13 MLLMs, we find that no model exceeds 20.0% on our strictest metric, and recall is tightly coupled with false-positive rate, with Pearson correlation 0.64: higher detection comes only at the cost of triggering warnings on the majority of safe clips. Performance splits sharply by domain: models achieve moderate recall at low false-positive rates in daily life, where risks are inherently anomalous, yet fire indiscriminately in driving, where routine and hazardous scenes look alike. These results indicate that current models rely on scene-level activity cues rather than reasoning about emerging harm.","authors":["Yusong Zhao","Yuejin Xie","Youliang Yuan","Junjie Hu","Jitian Guo","Yujiu Yang","Pinjia He"],"published":"2026-06-01T16:14:01Z","updated":"2026-06-01T16:14:01Z","abstract_url":"https://arxiv.org/abs/2606.02443v1","html_url":"https://arxiv.org/html/2606.02443v1","pdf_url":"https://arxiv.org/pdf/2606.02443v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02441v1","title":"Spatial-Temporal Decoupled Reference Conditioning for Identity-Preserving Text-to-Video Generation","abstract":"Identity-preserving video generation (IPVG) aims to synthesize high-fidelity videos that follow text prompts while faithfully preserving a reference identity. Despite recent progress, existing IPVG methods still struggle to balance high-level semantic control and low-level identity fidelity. To bridge this gap, we propose ST-DRC, an effective Spatial-Temporal Decoupled Reference Conditioning framework for identity-preserving text-to-video generation. At the framework level, ST-DRC performs latent in-context feature injection by encoding the reference image with the video VAE and concatenating it with noisy video latents, enabling rich low-level identity details to be accessed without additional adapters. To separate identity-aware reference retrieval from appearance copying, we introduce TASS-RoPE, a Temporal-Adjacent Spatial-Shifted RoPE scheme that places reference tokens near the video sequence in time but shifts them in space, allowing reference information to flow through spatio-temporal attention while suppressing pixel-level copy-paste shortcuts. To further prevent shortcut learning and strengthen the otherwise diluted identity supervision in the diffusion objective, we combine appearance-invariant reference augmentation with face-guided identity objectives, encouraging the model to preserve identity under variations in color, pose, and layout. At inference time, we introduce a three-stream reference classifier-free guidance strategy that independently controls text adherence and reference fidelity. Experiments demonstrate that ST-DRC achieves strong identity preservation, prompt alignment, temporal consistency, and video quality with a lightweight design built on LTX-2.3. Our method ranks among the top submissions in the facial identity-preserving video generation track, validating the effectiveness of spatial-temporal decoupled reference conditioning.","authors":["Yuheng Chen","Teng Hu","Yuji Wang","Qingdong He","Lizhuang Ma","Jiangning Zhang"],"published":"2026-06-01T16:12:18Z","updated":"2026-06-01T16:12:18Z","abstract_url":"https://arxiv.org/abs/2606.02441v1","html_url":"https://arxiv.org/html/2606.02441v1","pdf_url":"https://arxiv.org/pdf/2606.02441v1.pdf","matched_keywords":["video","retrieval","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02436v1","title":"Geometry-Aware Implicit Memory for Video World Models","abstract":"Video world models aim to simulate controllable visual environments, but long-horizon rollouts depend on what the model remembers after observations leave its native context window. Explicit memories retain frames or online 3D reconstructions, which can suffer from heuristic retrieval errors, redundant appearance storage, or reconstruction artifacts. Implicit memories compress history into a compact state, but existing designs are not explicitly constrained to encode cross-view scene geometry. We propose GIM-World, a geometry-aware implicit memory framework for video world models. A lightweight transformer encoder compresses variable-length history into fixed-size memory tokens, a camera-queryable geometry head distills 3D scene structure from a frozen foundation model into the memory during training, and an information-guided pruning rule keeps encoding cost bounded as history grows. The geometry teacher is discarded at inference, leaving a lightweight memory module. Experiments on MIND show that GIM-World better preserves long-horizon geometric and visual consistency than both explicit- and implicit-memory baselines.","authors":["Zhengxuan Wei","Xu Guo","Xinghui Li","Xunzhi Xiang","Min Wei","Yiran Zhu","Qiulin Wang","Xintao Wang","Pengfei Wan","Xiangwang Hou","Qi Fan"],"published":"2026-06-01T16:08:43Z","updated":"2026-06-01T16:08:43Z","abstract_url":"https://arxiv.org/abs/2606.02436v1","html_url":"https://arxiv.org/html/2606.02436v1","pdf_url":"https://arxiv.org/pdf/2606.02436v1.pdf","matched_keywords":["video","retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02406v1","title":"Edge Prediction for Roof Wireframe Reconstruction with Transformers","abstract":"This paper presents a competitive solution to the S23DR Challenge 2026, which aims to reconstruct 3D house roof wireframe models from sparse SfM point clouds and ground-level semantic segmentations and depth maps. Our proposed method utilizes an end-to-end Transformer encoder-decoder architecture inspired by DETR. To effectively process the geometric and semantic data, the sparse SfM point cloud input is dynamically subsampled based on semantic priority and augmented with Gestalt and ADE20k class features. To further increase segmentation context, we fuse the point features with additional Gestalt feature encodings which are obtained by projecting the points into latent feature maps produced by a frozen autoencoder. Learned query embeddings are then decoded directly into 3D wireframe edges via cross-attention mechanisms. Evaluated on the \"HoHo 22k\" dataset, our approach significantly outperforms both handcrafted and learned baselines, achieving a Hybrid Structure Score (HSS) of 0.6476 and securing the second-highest position on the challenge's private leaderboard.","authors":["Gustav Hanning","Ludvig Dillén","Jonathan Astermark","Johanna Lidholm","Viktor Larsson"],"published":"2026-06-01T15:51:30Z","updated":"2026-06-01T15:51:30Z","abstract_url":"https://arxiv.org/abs/2606.02406v1","html_url":"https://arxiv.org/html/2606.02406v1","pdf_url":"https://arxiv.org/pdf/2606.02406v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02402v1","title":"Explainable Forensics of Manipulated Segments in Untrimmed Long Videos","abstract":"The rapid advancement of AI-driven video generation has transformed content creation, while simultaneously increasing the risk of misinformation through localized manipulations in long-form videos. Existing video forensic methods predominantly operate on short, independent clips, and thus fail to capture realistic scenarios where AI-generated content is sparsely embedded within otherwise authentic footage. To bridge this gap, we formulate the task of Temporal AI-Generated Segment Localization and Explanation, which targets authenticity detection, temporal localization, and interpretable analysis of manipulated segments in untrimmed long videos. We further introduce TASLE, a large-scale benchmark comprising 12,472 untrimmed videos with diverse manipulation patterns and rich annotation signals, including temporal boundaries, authenticity labels, and segment-level rationales. In addition, we propose MSLoc, a coarse-to-fine forensic baseline that combines a boundary-sensitive proposal generation module for efficient long-video scanning with an MLLM-based refinement module for precise boundary localization and interpretable reasoning. Experiments validate the effectiveness of the proposed baseline, highlighting the importance of segment-level explainable forensics for long-form AI-generated video analysis. Our dataset and code are publicly available at https://debby-0527.github.io/TASLE.","authors":["Yue Feng","Jingjing Li","Qijia Lu","Wei Ji","Jingrou Zhang","Fei Shen","Xiao Li","Yizhen Jia","Qiang Chen","Limin Wang","Wentong Li","Jie Qin"],"published":"2026-06-01T15:48:38Z","updated":"2026-06-01T15:48:38Z","abstract_url":"https://arxiv.org/abs/2606.02402v1","html_url":"https://arxiv.org/html/2606.02402v1","pdf_url":"https://arxiv.org/pdf/2606.02402v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02366v1","title":"PRIMA: Boosting Animal Mesh Recovery with Biological Priors and Test-Time Adaptation","abstract":"We present PRIMA (*PRI*ors for *M*esh *A*daptation), a framework for robust 3D quadruped mesh recovery under severe species and pose imbalance. Existing animal reconstruction methods often regress toward mean shapes and poses due to limited 3D supervision and long-tailed species distributions, resulting in poor generalization to underrepresented animals and rare articulations. PRIMA addresses this challenge through three key contributions. First, we incorporate BioCLIP embeddings as biological priors to inject semantic and morphological knowledge into the reconstruction process, enabling more accurate and generalizable shape prediction across diverse quadrupeds. Second, we introduce a test-time adaptation (TTA) strategy that refines SMAL predictions using 2D reprojection constraints together with auxiliary keypoint guidance, improving pose and shape estimation while enabling the generation of high-quality pseudo-3D annotations from existing 2D datasets. Third, leveraging this TTA framework, we construct Quadruped3D, a large-scale pseudo-3D dataset that covers diverse species and pose variations to systematically improve model performance. Extensive experiments on Animal3D, CtrlAni3D, Quadruped2D, and Animal Kingdom demonstrate that PRIMA achieves state-of-the-art results, with particularly strong improvements on underrepresented species and challenging poses. Our results highlight the importance of biological priors and adaptation-driven data expansion for scalable and generalizable animal mesh recovery. Code is available at https://github.com/AdaptiveMotorControlLab/PRIMA.","authors":["Xiaohang Yu","Ti Wang","Mackenzie Weygandt Mathis"],"published":"2026-06-01T15:13:47Z","updated":"2026-06-01T15:13:47Z","abstract_url":"https://arxiv.org/abs/2606.02366v1","html_url":"https://arxiv.org/html/2606.02366v1","pdf_url":"https://arxiv.org/pdf/2606.02366v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02357v1","title":"Do Multimodal Agents Really Benefit from Tool Use? A Systematic Study of Capability Gains","abstract":"Tool-augmented multimodal agents show strong benchmark gains, often taken as evidence that agents have learned to use tools. We argue that this interpretation can be premature: a tool-call trace alone does not show whether the tool supplied answer-critical information. We study two representative ``thinking with images'' agents, Thyme and DeepEyesV2, across real-world understanding, OCR, chart understanding, and mathematical reasoning. Each agent is compared with its Tool-Free counterpart and with a Pure-Text Reasoner trained from the same source pool without tool-calling trajectories. Tool access yields little consistent aggregate improvement, does not reliably reduce generated-token cost, and leaves only a small tool-only solved set: 93% of DeepEyesV2's tool-solved problems and 96% of Thyme's are also solved by at least one non-tool setting. Mechanism ablations further show that the full tool-use loop does not consistently outperform either the tool-call format or the returned execution result alone. In the settings we study, the analyzed agents appear to learn tool-calling patterns more reliably than tool-contributed capabilities, suggesting that evaluation should distinguish tool availability from whether tools actually expand what agents can solve.","authors":["Garvin Guo","Donglei Yu","Yu Chen","Xiang Wang","Shuai Li","Xinpei Zhao","Huaxing Liu","Qinghao Wang","Minpeng Liao"],"published":"2026-06-01T15:04:25Z","updated":"2026-06-01T15:04:25Z","abstract_url":"https://arxiv.org/abs/2606.02357v1","html_url":"https://arxiv.org/html/2606.02357v1","pdf_url":"https://arxiv.org/pdf/2606.02357v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02352v1","title":"Multi-modal Video Representation Alignment for Robust Self-supervised Driver Distraction Detection","abstract":"Robust self-supervised learning of multi-modal video representations is critical for real-world applications such as driver distraction detection, where multiple sensors provide complementary but noisy signals. Conventional contrastive objectives, such as InfoNCE, assume all negatives are equally informative and all positives are reliable. However, this assumption is frequently violated in multi-modal data due to viewpoint changes, occlusions, or semantic overlap across modalities. In this work, we propose a novel framework for multi-modal global alignment that addresses these challenges by jointly modeling faulty negatives and unreliable or faulty positives. We introduce soft targets derived from cycle-consistency scores to relax the hard-negative assumption, and a weighting mechanism based on similarity distributions to mitigate the impact of noisy or faulty positives. Our approach extends traditional pairwise alignment to a principled global multi-modal setting, aggregating alignment information across all modality pairs. We evaluate our method on the Drive&Act dataset, demonstrating that it consistently outperforms both pairwise and existing global alignment baselines across RGB, IR, Depth, and Skeleton modalities. Cross-view ablation studies further show strong generalization to unseen camera perspectives, highlighting the robustness of our representations. Overall, our framework provides a scalable and effective solution for self-supervised global multi-modal representation learning, enabling reliable driver distraction detection and pioneering in real-world multi-modal video understanding. Our code will be published on GitHub.","authors":["David J. Lerch","Livien Majer","Zeyun Zhong","Manuel Martin","Frederik Diederichs","Rainer Stiefelhagen"],"published":"2026-06-01T15:01:17Z","updated":"2026-06-01T15:01:17Z","abstract_url":"https://arxiv.org/abs/2606.02352v1","html_url":"https://arxiv.org/html/2606.02352v1","pdf_url":"https://arxiv.org/pdf/2606.02352v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02350v1","title":"TROPHIES: Temporal Reconstruction of Places, Humans, and Cameras from Multi-view Videos","abstract":"Reconstructing humans and their surrounding environments in a globally consistent 4D space is essential for comprehensive perception. However, prior works typically assume single-view inputs or decouple humans, scenes, and cameras, making them unable to recover coherent geometry, stable motion, and physically aligned trajectories. These limitations motivate us to introduce a new task: unified human-scene-camera reconstruction from multi-view videos, which aims to jointly estimate dynamic humans, static scenes, and camera poses in one global coordinate frame. We propose TROPHIES--Temporal Reconstruction of Places, Humans, and Cameras from Multi-view Videos-a unified framework tailored for this task. TROPHIES features a Human Branch that models humans through temporal and spatial reasoning, and a Scene Branch that reconstructs static geometry with human-aware attention. A global alignment and optimization module couples both branches by enforcing scale consistency, contact priors, and cross-view temporal coherence. Experiments on EgoHuman and EgoExo4D demonstrate that TROPHIES achieves globally aligned, physically plausible 4D reconstructions and consistently outperforms existing paradigms in both global fidelity and human-scene consistency.","authors":["Jinpeng Liu","Yukang Xu","Yutong Li","Xingyu Liu"],"published":"2026-06-01T15:00:18Z","updated":"2026-06-01T15:00:18Z","abstract_url":"https://arxiv.org/abs/2606.02350v1","html_url":"https://arxiv.org/html/2606.02350v1","pdf_url":"https://arxiv.org/pdf/2606.02350v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02346v1","title":"VEDAL: Variational Error-Driven Asynchronous Learning for 3D Gaussian Splatting Pruning","abstract":"3D Gaussian Splatting (3DGS) achieves remarkable novel view synthesis quality with real-time rendering, yet suffers from excessive memory consumption due to millions of Gaussian primitives. Existing pruning methods rely on heuristic importance scores or synchronous batch updates, leading to suboptimal compression and training instability. We propose VEDAL, a principled framework that formulates Gaussian pruning as variational free energy minimization. Our approach introduces (1) a prediction-error gating mechanism that asynchronously activates pruning based on per-Gaussian reconstruction uncertainty, and (2) a variational uncertainty head that models pruning decisions as latent variables with learnable priors. The free energy objective naturally balances reconstruction fidelity against model complexity through an information-theoretic lens. Extensive experiments on Mip-NeRF 360, Tanks&Temples, and Deep Blending demonstrate that VEDAL achieves 5.2x compression with only 0.31 dB PSNR drop, outperforming PUP 3D-GS by +0.05 dB at a higher compression ratio and LightGaussian by +0.35 dB at comparable quality, while maintaining real-time rendering at 185 FPS.","authors":["Aoduo Li","Jiancheng Li","Huan Ye","Hongjian Xu","Shiting Wu","Xiujun Zhang","Zimeng Li","Xuhang Chen"],"published":"2026-06-01T14:56:50Z","updated":"2026-06-01T14:56:50Z","abstract_url":"https://arxiv.org/abs/2606.02346v1","html_url":"https://arxiv.org/html/2606.02346v1","pdf_url":"https://arxiv.org/pdf/2606.02346v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02342v1","title":"Detecting Pen-In-Air States from Video: A Proof-of-Concept Toward Complementary Handwriting Analysis","abstract":"Dynamic aspects of handwriting are critical for assessing developmental disorders such as dysgraphia and are typically captured using digitizing tablets. However, tablet-based sensing restricts analysis of Pen-Up behavior to a short proximity range above the writing surface, potentially missing high-lift in-air movements. As a proof of concept, we investigate whether top-view video can provide a complementary source of information for inferring pen-contact states without relying on tablet proximity sensing. We propose an interpretable hybrid pipeline combining pen-tip tracking using a YOLO-based detector with kinematic feature extraction and machine learning classification. A pilot dataset of diverse handwriting videos was manually annotated at the frame level and evaluation used a Leave-One-Video-Out (LOVO) protocol. The method achieved reliable event-level detection of Pen-Up segments, with an F_2 score up to 0.805, consistent with the emphasis on recall in a screening-oriented setting. These results support the feasibility of video-based Pen-Up detection as a low-cost and non-intrusive complement to digitizing tablets, and provide a foundation for future large-scale studies.","authors":["Lauren Sismeiro","Remy Plastre","Binbin Xu","Frederic Puyjarinet","Gerard Dray"],"published":"2026-06-01T14:50:27Z","updated":"2026-06-01T14:50:27Z","abstract_url":"https://arxiv.org/abs/2606.02342v1","html_url":"https://arxiv.org/html/2606.02342v1","pdf_url":"https://arxiv.org/pdf/2606.02342v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02339v1","title":"Entropy Minimization without Model Collapse: Mitigating Prediction Bias in Medical Imaging","abstract":"Entropy minimization (EM) is the dominant objective for test-time adaptation, yet its failure mode, model collapse, remains poorly understood. In this work, we show that distribution shifts can cause feature clusters corresponding to distinct classes in the model's representation space to merge, while the decision boundary remains fixed. This induces a systematic skew in the predicted class distribution, referred to as prediction bias. Prediction bias refers to a shift in the predicted class distribution, with some classes overrepresented and others suppressed. We show that entropy minimization amplifies this prediction bias by tightening the existing clusters, reinforcing the incorrect groupings until all predictions collapse to a trivial solution. Next, to demonstrate the significance of prediction bias and mitigate it, we further propose Distribution Shift Bias Reduction (DSBR), a bias-correcting objective that specifically targets this failure mode by equalizing the contribution of each predicted class to the unsupervised entropy minimization loss. To study this failure mode, we design suitable adaptation settings using four medical-imaging datasets and additionally evaluate on ImageNet-C. We find that DSBR consistently stabilizes test-time adaptation, prevents model collapse, and matches or outperforms state-of-the-art methods. Moreover, DSBR operates solely at test-time.","authors":["Tim Nielen","Sameer Ambekar","Johannes Kiechle","Daniel M. Lang","Julia A. Schnabel"],"published":"2026-06-01T14:48:16Z","updated":"2026-06-01T14:48:16Z","abstract_url":"https://arxiv.org/abs/2606.02339v1","html_url":"https://arxiv.org/html/2606.02339v1","pdf_url":"https://arxiv.org/pdf/2606.02339v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02331v1","title":"Hallucination-Aware Diffusion Sampling for Inverse Problems via Robust Prior Updates","abstract":"Diffusion-based inverse problem solvers can produce realistic reconstructions, but realism alone does not ensure that the recovered details are supported by the measurement. We study this failure as measurement-conditioned hallucination: visually meaningful content that is either implausible or inconsistent with the measured instance. Our analysis separates Bayes-rule-based diffusion inverse solvers into a prior update and a measurement-conditioning step, showing that hallucinated content can enter through the prior-side proposal before the measurement correction is applied. Motivated by this view, we propose Robust Prior Update (RPU), a solver-level module that probes the local stability of the diffusion prior update, re-anchors the resulting displacement at the current iterate, and leaves the measurement update unchanged. We instantiate RPU in DPS and evaluate it on FFHQ and ImageNet inverse problems using automatic metrics and human faithfulness studies. On FFHQ, RPU improves PSNR and LPIPS over DPS across box inpainting, Gaussian deblurring, and motion deblurring. In human judgments, RPU receives 91.9% of blind non-tie majority preferences and 91.1% of ground-truth-assisted non-tie preferences on FFHQ box inpainting, while the ImageNet Gaussian reader study is tie-heavy but favors RPU among non-tie cases. These results support a targeted claim: robustifying the prior update can improve instance faithfulness in diffusion inverse solvers, especially when the prior shapes weakly constrained content.","authors":["Pengfei Jin","Yiqi Tian","Kailong Fan","Bingjie Qi","Quanzheng Li"],"published":"2026-06-01T14:41:46Z","updated":"2026-06-01T14:41:46Z","abstract_url":"https://arxiv.org/abs/2606.02331v1","html_url":"https://arxiv.org/html/2606.02331v1","pdf_url":"https://arxiv.org/pdf/2606.02331v1.pdf","matched_keywords":["instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02321v1","title":"Training-Free Composed Video Retrieval via Visual Representation-Guided Video-LLM Reasoning","abstract":"Recent advances in large vision-language models have expanded video retrieval from simple text-based search to more flexible scenarios, where users may specify the desired result through both visual examples and textual instructions. In the CVPR 2026 Reason-Aware Composed Video Retrieval Challenge, the system is required to retrieve a target video according to a reference video and a modification instruction. To address this task, we develop Visual Representation-Guided Video-LLM Reasoning for Training-Free Composed Video Retrieval. Our framework first uses frozen DINOv3 models to obtain a compact set of visually relevant candidates, and then applies large vision-language models to evaluate whether each candidate satisfies the modification instruction. A final reasoning-based refinement is further performed on the top candidates to improve the first-ranked prediction. Without training, our system achieves 48.78 Recall@1 and 51.48 Recall@5 on the test set. Future work may further improve retrieval accuracy through stronger video-LLMs and detailed integration between visual representations and language reasoning.","authors":["Yang Liu","Qianqian Xu","Peisong Wen","Siran Dai","Qingming Huang"],"published":"2026-06-01T14:35:23Z","updated":"2026-06-01T14:35:23Z","abstract_url":"https://arxiv.org/abs/2606.02321v1","html_url":"https://arxiv.org/html/2606.02321v1","pdf_url":"https://arxiv.org/pdf/2606.02321v1.pdf","matched_keywords":["video","retrieval","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02310v1","title":"Deep Learning for Remote Sensing to Improve Flood Inundation Mapping","abstract":"Flooding is the most pervasive natural disaster worldwide. Timely and accurate flood inundation mapping are essential for informing disaster risk management. Optical satellite missions provide high-resolution, multispectral observations critical for flood detection and inundation mapping. However, their operational utility is severely constrained by cloud cover during extreme precipitation events. Conventional cloud-removal techniques based on temporal compositing or interpolation often fail to capture inundation dynamics. In this study, we introduce a cloud-removal framework for flood imagery based on Denoising Diffusion Probabilistic Models, leveraging the Masked Diffusion Transformer architecture. The proposed approach exploits self-attention mechanisms to capture wider spatial context and employs masked token modeling to explicitly learn the reconstruction of cloud-obscured regions. Trained on multispectral Sentinel-2B flood scenes with realistic cloud patterns, the model generates cloud-free image realizations that preserve both visual fidelity and hydrological consistency. Reconstruction performance is evaluated using standard image quality metrics alongside flood-specific hydrological measures, demonstrating improved continuity of water bodies and preservation of spectral signatures critical for water detection indices. The results indicate that diffusion-based generative modeling offers a robust and physically consistent alternative for cloud removal in optical flood monitoring, enabling more reliable, continuous observations to support disaster risk management and flood-related decision making.","authors":["Yogesh Bhattarai","Vijay Chaudhary","Wai Lim Kim","Sanjib Sharma"],"published":"2026-06-01T14:28:48Z","updated":"2026-06-01T14:28:48Z","abstract_url":"https://arxiv.org/abs/2606.02310v1","html_url":"https://arxiv.org/html/2606.02310v1","pdf_url":"https://arxiv.org/pdf/2606.02310v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02303v1","title":"Cross-Domain Dead Tree Detection via Knowledge Distillation in Aerial Imagery","abstract":"Detecting dead trees in aerial imagery is vital for assessing forest health, especially as tree mortality increases globally due to climate change, but domain variability and scarce labeled data often limit model generalization. This study advances the TreeMort-1T-UNet (Tree Mortality 1-Task U-Net) model, initially trained on Finnish aerial imagery (source domain), by applying knowledge distillation (KD) to adapt it to various target domains, including Polish, German, and Estonian datasets representing diverse forest types. We assess four KD variants: Basic, Self, Feature-level, and Ensemble, against a fine-tuning baseline, using Mean Tree IoU, Instance F1-score, Instance Precision, and Mean Centroid Error as key metrics, alongside representational analyses (e.g., cosine similarity, CKA, SSIM, t-SNE, and linear probing) for domain invariance. Feature-level KD outperforms others, yielding a Mean Tree IoU of 0.106, Instance F1-score of 0.63, Instance Precision of 0.55, and Mean Centroid Error of 3.039 on the Polish dataset, with robust precision across other target domains (e.g., 0.15 on Finnish, 0.67 on Polish, 0.60 on German, 0.59 on Estonian). It excels in low-data scenarios with fewer false positives and shows superior representational invariance (e.g., higher deep-layer CKA/SSIM, better domain mixing in t-SNE, and linear probing AUC of 0.95), making it ideal for precision-critical forestry applications. Additional ablation studies confirm that key components like feature alignment enhance its performance balance across metrics. Our findings demonstrate KD's potential to enhance transfer learning in remote sensing, offering a scalable, domain-robust tool for ecological monitoring and sustainable forest management.","authors":["Anis Ur Rahman","Mete Ahishali","Einari Heinaro","Samuli Junttila"],"published":"2026-06-01T14:24:20Z","updated":"2026-06-01T14:24:20Z","abstract_url":"https://arxiv.org/abs/2606.02303v1","html_url":"https://arxiv.org/html/2606.02303v1","pdf_url":"https://arxiv.org/pdf/2606.02303v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02301v1","title":"Quantitative Movement Testing: Measuring Patient Movements from a Single Smartphone Video","abstract":"Chronic pain diminishes quality of life by decreasing functional ability, yet objectively measuring this functional impact remains challenging in real-world settings. While optical motion capture provides high precision for assessing altered movement quality, it is costly and restricted to laboratory environments. We aimed to develop and validate Quantitative Movement Testing (QMT), a computer vision pipeline extracting 3D kinematic biomarkers from standard monocular smartphone video, balancing clinical accessibility with biomechanical accuracy. We validated the QMT pipeline, utilising deep learning-based 3D pose-estimation, against gold-standard optical motion capture in healthy controls (N=13). Following leave-one-subject-out calibration to correct systematic bias, we deployed QMT in two prospective clinical cohorts to assess real-world utility: a pre- and post-intervention trial for fibromyalgia patients, and a 30-day longitudinal at-home monitoring study of chronic sciatica patients and healthy controls. In laboratory validation, QMT extracted clinical kinematic metrics with high agreement to optical motion capture, yielding strong correlations (r > 0.85) and low mean absolute errors. QMT demonstrated high test-retest reliability (r > 0.86) in fibromyalgia patients and successfully tracked day-to-day movement fluctuations in chronic sciatica. While real-world home settings introduced higher measurement variance than lab settings, QMT found group-level differences between healthy controls and sciatica patients based entirely on remote recordings. Monocular 3D pose estimation offers a scalable alternative to traditional assessments. QMT provides an objective, accessible biomarker for tracking disease progression and treatment response in clinical trials, though further research is needed to optimise reliability in home environments.","authors":["Pranav Mahajan","Amanda Wall","Eleonora Maria Camerone","Julie Stebbins","Eoin Kelleher","Shuangyi Tong","Annina Schmid","Katja Wiech","Anushka Irani","Ben Seymour"],"published":"2026-06-01T14:23:17Z","updated":"2026-06-01T14:23:17Z","abstract_url":"https://arxiv.org/abs/2606.02301v1","html_url":"https://arxiv.org/html/2606.02301v1","pdf_url":"https://arxiv.org/pdf/2606.02301v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02292v1","title":"Neural Acquisition & Representation of Subsurface Scattering","abstract":"We present a method to acquire and estimate the sub-surface scattering properties of light transport at a highly detailed level by learning the pixel footprint response at each point on the object surface. The reconstruction leverages 3D scanning techniques as input to a U-Net CNN. A stereo projector-camera setup using phase-shifted profilometry (PSP) patterns efficiently captures the data for a variety of scattering objects. Reconstructing dense pixel footprints allows for relighting with arbitrary high-resolution projector patterns. The final output is a relit color image. Qualitative and quantitative comparison against illuminated real-world captured images demonstrate that the predicted footprints are almost identical to the actual responses. The same model is trained for multiple views across multiple objects such that the learned representations can be used to generalize to unseen sub-surface scattering materials as well.","authors":["Arjun Majumdar","Raphael Braun","Hendrik Lensch"],"published":"2026-06-01T14:14:38Z","updated":"2026-06-01T14:14:38Z","abstract_url":"https://arxiv.org/abs/2606.02292v1","html_url":"https://arxiv.org/html/2606.02292v1","pdf_url":"https://arxiv.org/pdf/2606.02292v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02276v1","title":"Cross-modal linkage risk in clinical vision-language models","abstract":"Vision-language models (VLMs) trained on paired chest radiographs and radiology reports learn a shared embedding space that can preserve instance-level image-report correspondence. This poses a privacy risk in settings where radiographs and reports are deliberately kept separate after acquisition, such as image-only data sharing or access-controlled reports, because a de-identified image may be re-linked to its original narrative report through cosine similarity alone. We formalized this as image-to-report retrieval and used public paired cohorts, in which the true pairing is known by design, as ground-truth benchmarks to audit the risk rather than as the privacy scenario. Evaluating VLMs of increasing clinical specialization on 406,241 paired examples from 126,804 patients across MIMIC-CXR (43,793 held-out pairs) and external CheXpert Plus (29,296 pairs), we found that re-linkage rose systematically with specialization: the strongest VLM retrieved the correct report at 15 times chance at a candidate pool of N = 100, 50 times chance at N = 10,000, and well above chance at full-database scale. The signal persisted under pathology-matched hard negatives that removed disease-label shortcuts, indicating correspondence beyond broad diagnostic categories. To reduce it without retraining, we froze both encoders and applied differentially private optimization only to the projection heads defining the alignment layer (epsilon = 0.34, delta = 6x10-6). This reduced Recall@1 by 61.8% at N = 10,000 on MIMIC-CXR and transferred to CheXpert Plus without retraining, while image-side utility was largely preserved: macro AUROC for linear-probe classification across 14 labels shifted only from 79.63% to 79.43%. Targeted DP finetuning of the shared alignment layer can substantially reduce cross-modal re-linkage without materially degrading the image representations that make these models clinically useful.","authors":["Soroosh Tayebi Arasteh","Mahshad Lotfinia","Sven Nebelung","Daniel Truhn"],"published":"2026-06-01T14:01:46Z","updated":"2026-06-01T14:01:46Z","abstract_url":"https://arxiv.org/abs/2606.02276v1","html_url":"https://arxiv.org/html/2606.02276v1","pdf_url":"https://arxiv.org/pdf/2606.02276v1.pdf","matched_keywords":["retrieval","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02268v1","title":"From Extrinsic to Intrinsic: Geodesic-Guided Representation Learning for 3D Geometric Data","abstract":"Geometric analysis fundamentally distinguishes between \\textit{extrinsic} and \\textit{intrinsic} perspectives. The dominant paradigm in current 3D representation learning relies on either extrinsic spatial structures or high-level semantics, struggling to capture the essence of shape identity and underlying manifold topology. To bridge this gap, we introduce a novel 3D representation learning paradigm, namely \\textbf{PRISM}, for \\textbf{P}re-training, which learns isometric embeddings by \\textbf{R}ecovering the \\textbf{I}ntrinsic \\textbf{S}urface geodesic \\textbf{M}etric. PRISM incorporates a topology-enforcing objective that explicitly constrains the structure of latent space, alongside a specialized two-stage training recipe mitigating sample imbalance inherent in the distribution of geodesic distances. Experiments demonstrate that our approach shows satisfactory accuracy, robustness, and high efficiency in geodesic distance prediction and achieves superior performance across diverse downstream tasks, including shape recognition, surface parameterization, and non-rigid correspondence. The code will be publicly available at https://github.com/AidenZhao/PRISM.","authors":["Yuming Zhao","Junhui Hou","Qijian Zhang","Jia Qin","Ying He"],"published":"2026-06-01T13:54:26Z","updated":"2026-06-01T13:54:26Z","abstract_url":"https://arxiv.org/abs/2606.02268v1","html_url":"https://arxiv.org/html/2606.02268v1","pdf_url":"https://arxiv.org/pdf/2606.02268v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02242v1","title":"Towards Resolving Optimization Conflicts Between Image- and Text-Based Person Re-Identification","abstract":"The joint optimization of image-based (I2I) and text-based (T2I) person re-identification (ReID) is hindered by modality discrepancies and conflicting training objectives, leading to suboptimal shared representations. While I2I ReID focuses on identity-level invariance across images of the same person, T2I ReID is driven by instance-specific textual descriptions tied to unique visual traits. This paper explores the fundamental difference between two ReID tasks and their optimization processes for effective training. Since I2I and T2I ReID are often studied separately, the loss functions optimized for one retrieval setting may negatively affect the representation quality required by the other. Motivated by these findings, we propose a decoupled two-stage training pipeline for learning a shared representation across image and text modalities. The pipeline is based on a single vision encoder that supports both I2I and T2I retrieval while avoiding cross-task interference during training. We provide extensive experiments across multiple configurations, varying domain mixing procedures, learning strategies, and task objectives. We observed that I2I ReID pre-training positively impacts the generalization ability to T2I data. Besides, we find that incorporating textual supervision during the vision encoder training stage enhances both I2I and T2I performance. We believe our insights provide a meaningful step toward unified ReID systems and cross-modal retrieval overall.","authors":["Karina Kvanchiani","Timur Mamedov"],"published":"2026-06-01T13:37:55Z","updated":"2026-06-01T13:37:55Z","abstract_url":"https://arxiv.org/abs/2606.02242v1","html_url":"https://arxiv.org/html/2606.02242v1","pdf_url":"https://arxiv.org/pdf/2606.02242v1.pdf","matched_keywords":["retrieval","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02221v1","title":"CORE-MTL: Rethinking Gradient Balancing via Causal Orthogonal Representations","abstract":"Multi-task learning (MTL) aims to construct a joint model for multiple tasks by sharing a common representation across domains. To achieve this goal, existing optimization-centric methods either balance task gradients or modify the shared architecture. However, as these approaches remain agnostic to the content of the shared representation, they fail to disentangle task-relevant structure from spurious context, leading to negative transfer and poor generalization. To overcome this limitation, we propose Causal Orthogonal Representations for Multi-Task Learning (CORE-MTL), a causally motivated representation-centric framework that encourages a structured semantic-residual factorization of the shared representation, concentrating task-relevant structure in the semantic stream while relegating nuisance variation to the residual stream. We instantiate this framework in the visual domain by leveraging physical priors for structured scenes and statistical constraints for attributes. Theoretically, our method enjoys a tighter out-of-distribution generalization bound than optimization-centric methods and reduces task gradient interference without explicit gradient projection or reweighting. Empirically, CORE-MTL consistently outperforms existing methods on visual multi-task benchmarks in both in-distribution and out-of-distribution settings. Code is publicly available at https://github.com/Hope-Rita/CORE-MTL.","authors":["Chengfeng Wu","Tao Zou","Yanru Wu","Jingge Wang"],"published":"2026-06-01T13:20:58Z","updated":"2026-06-01T13:20:58Z","abstract_url":"https://arxiv.org/abs/2606.02221v1","html_url":"https://arxiv.org/html/2606.02221v1","pdf_url":"https://arxiv.org/pdf/2606.02221v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02219v1","title":"Symmetry-Aware 9D Pose Estimation with Sim(3)-Consistent Feature and Spherical Inception Convolution","abstract":"Object pose estimation is a fundamental problem for an agent system to perceive or manipulate objects in images or videos. However, current instance-level methods struggle with generalization to unseen objects. Category-level methods seek to address this, but remain constrained by the complexities of learning in the non-linear Sim(3) space and intra-class variations. To address these challenges, We propose an effective method for category-level object pose estimation with two key innovations: (1) A translation/size estimator, featuring a semantic-guided symmetry-aware module that leverages robust generalization capabilities of a large vision model (LVM) to infer symmetry points, resulting in accurate translation and size without shape priors. This result serves as a precomputed cue for rotation estimation, thereby reducing the difficulty of learning in the non-linear Sim(3) space and laying a robust foundation for tackling the inherently more challenging rotation estimation. (2) A feature fusion module, based on our proposed spherical large-kernel inception convolution, fuses semantic features from the LVM with systematically computed geometric features to extract essential pose features from intra-class variations by modeling long-range dependencies without excessive computational cost. Built on these innovations, we achieve SOTA on benchmarks and real-world scenes, while developing a robust robotic picking system capable of handling diverse objects. Our code will be available at the project page: {\\hypersetup{urlcolor=blue}https://panfei-cheng.github.io/SSH-Pose}.","authors":["Panfei Cheng","Hongshan Yu","Wenrui Chen","Xiaojun Tang","Jian Liu","Naveed Akhtar"],"published":"2026-06-01T13:20:04Z","updated":"2026-06-01T13:20:04Z","abstract_url":"https://arxiv.org/abs/2606.02219v1","html_url":"https://arxiv.org/html/2606.02219v1","pdf_url":"https://arxiv.org/pdf/2606.02219v1.pdf","matched_keywords":["video","agent","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02178v1","title":"Order within Chaos: Capturing Intrinsic Energy Anomalies for AI-Manipulated Image Forgery Localization","abstract":"Recent advancements in generative AI have led to image editing models capable of producing realistic forgeries that evade traditional image forgery localization methods, as these approaches depend on physical noise absent in synthetic data. To address this challenge, we theoretically demonstrate that the diffusion process inherently suppresses local high-frequency variance, creating a statistical energy gap that is distinguishable from the natural entropy of optical imaging. Guided by this insight, we propose FLAME, a unified framework that utilizes a LAD map to capture these intrinsic anomalies, coupled with a parameter-efficient adapter for SAM to achieve precise, pixel-level forgery localization. Furthermore, to bridge the lag between forensic benchmarks and evolving generative models, we introduce EditStream, an automated pipeline for continuous, instruction-based training data synthesis. Extensive experiments demonstrate that FLAME establishes a new state-of-the-art, significantly outperforming previous methods on AI-generated forgery datasets while effectively generalizing to unseen generative architectures. Our code is available at https://github.com/phoenixnir/FLAME.","authors":["Yiming Wang","Baiqi Wu","Qingming Li","Jiahao Chen","Tong Zhang","Shouling Ji"],"published":"2026-06-01T12:36:04Z","updated":"2026-06-01T12:36:04Z","abstract_url":"https://arxiv.org/abs/2606.02178v1","html_url":"https://arxiv.org/html/2606.02178v1","pdf_url":"https://arxiv.org/pdf/2606.02178v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02172v1","title":"Closing the Alignment-Maturity Gap in Federated Prototype Learning","abstract":"Learning discriminative visual representations from distributed, heterogeneous data is a fundamental challenge in Federated Learning (FL). Prototype-based methods address statistical heterogeneity by sharing class-level representations across clients but create a distance-dependent gradient pressure that is particularly severe during early training rounds: alignment pressure applied to immature global prototypes, aggregated from noisy local representations, generates large gradients that suppress the emergence of local discriminative structure. The result is a poorly organized embedding space and degraded recognition performance, particularly under severe non-IID conditions. We propose FedSAP, a framework that stabilises federated representation learning through two complementary mechanisms: a deterministic alignment curriculum that delays global alignment until local representations become stable and a geometry-driven proxy separation loss that enforces inter-class structure on the unit hypersphere using the existing prototype bank without introducing additional parameters or communication overhead. Together, these mechanisms produce compact, well-separated class clusters without altering the underlying communication protocol between federation's participants. Experiments across three benchmarks and varying degrees of heterogeneity show gains of up to 4 percentage points over the prototype-based baselines evaluated, with improvements most pronounced under high heterogeneity. The representational nature of our framework further enables a straightforward extension to semi-supervised settings, where unlabelled data is incorporated with minimal modification, underscoring the generality of scheduled alignment as a design principle.","authors":["Mario Casado-Diez","Alejandro Dopico-Castro","Verónica Bolón-Canedo","Bertha Guijarro-Berdiñas"],"published":"2026-06-01T12:30:53Z","updated":"2026-06-01T12:30:53Z","abstract_url":"https://arxiv.org/abs/2606.02172v1","html_url":"https://arxiv.org/html/2606.02172v1","pdf_url":"https://arxiv.org/pdf/2606.02172v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02162v1","title":"Multimodal Approaches for Visually-Rich Document Type Classification: A Comparative Analysis","abstract":"Document type classification in visually rich documents remains challenging, as relevant information is distributed across textual, visual, and layout modalities. To capture this complexity, current approaches rely on diverse multimodal modeling strategies, resulting in heterogeneous architectures that complicate systematic comparison. This variability is also reflected in existing comparative studies, which often rely on heterogeneous evaluation setups, further complicating systematic comparison and making it difficult to assess progress. To address these limitations, this work provides a structured analysis of multimodal design strategies across transformer- and LLM-based architectures, combined with a controlled empirical comparison within a unified experimental framework. Specifically, four representative models (LayoutLMv3, Donut, Qwen3-VL-32B-Instruct, and Qwen3-32B) are evaluated on the RVL-CDIP benchmark to systematically analyze the contributions of text, image, and layout information for document type classification, with a particular focus on contrasting OCR-dependent and OCR-free approaches. The results show that specialized multimodal Transformers outperform LLM-based approaches on visually rich and layout-intensive documents. Image information contributes most strongly to reliable classification, while OCR-derived text provides useful but secondary support. These findings highlight that multimodal processing remains essential for documents with pronounced layout structure. Overall, the study provides a systematic basis for comparing multimodal architectures and offers practical guidance for selecting effective feature combinations and model designs for document type classification.","authors":["Catyana Heyne","Jürgen Frikel","Filippo Riccio"],"published":"2026-06-01T12:24:26Z","updated":"2026-06-01T12:24:26Z","abstract_url":"https://arxiv.org/abs/2606.02162v1","html_url":"https://arxiv.org/html/2606.02162v1","pdf_url":"https://arxiv.org/pdf/2606.02162v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02161v1","title":"InfoMerge: Information-aware Token Compression for Efficient Video Large Language Models","abstract":"Video Large Language Models (Video-LLMs) achieve strong performance in video understanding, but their excessive visual tokens bring substantial computational overhead. Existing training-free compression methods improve inference efficiency by reducing visual tokens, yet they often rely on local adjacent-frame similarity for temporal redundancy estimation or allocate token budgets mainly according to segment length. Such designs are sensitive to frame-level noise and fail to capture the non-uniform information distribution of real-world videos. To address these challenges, we propose InfoMerge, a training-free visual token compression method that improves token utilization through robust redundancy estimation and content-aware budget allocation. Specifically, we propose the Temporal Fingerprint Difference: a segment-level second-order temporal redundancy estimation strategy, which models the temporal similarity structure of tokens at the same spatial positions within each segment. We further introduce Content-Aware Budget Allocation (CABA), which dynamically allocates segment-level token budgets based on segment uniqueness and spectral-entropy-based representational richness. By reducing repeated preservation of redundant static regions and allocating more tokens to informative segments, InfoMerge makes better use of the limited token budget while maintaining strong performance. Extensive experiments show that InfoMerge achieves strong efficiency--accuracy trade-offs across multiple benchmarks and backbones, with more pronounced advantages under aggressive compression. On LLaVA-OneVision-7B, InfoMerge retains 98.8\\% of the original average performance while reducing 85\\% of visual tokens and achieving a 4.24-fold speedup in the prefill stage.","authors":["Xinxin Liu","Shiwei Gan","Xiao Liu","Yafeng Yin","Lei Xie","Sanglu Lu"],"published":"2026-06-01T12:24:24Z","updated":"2026-06-01T12:24:24Z","abstract_url":"https://arxiv.org/abs/2606.02161v1","html_url":"https://arxiv.org/html/2606.02161v1","pdf_url":"https://arxiv.org/pdf/2606.02161v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02156v1","title":"Predicting the risk of colorectal anastomotic leak based on preoperative mapping of the blood supply of the bowel","abstract":"Anastomotic leak remains one of the most serious complications following colorectal cancer surgery, substantially affecting patient outcomes, recovery trajectories, and healthcare costs. Despite advances in imaging technology, current preoperative assessment relies only on clinical assessment, a process that is subjective, error-prone, and highly dependent on individual expertise. To date, no validated CT-based method exists to predict anastomotic leak risk prior to surgery. This protocol paper outlines a comprehensive framework for developing and validating an AI-driven system for preoperative risk assessment using pre- and post-contrast CT imaging. The study describes the stages of data collection, ethical handling, and preprocessing of patient data in accordance with GDPR, image preprocessing, and the exploration of deep learning architectures designed to generate clinically interpretable outputs. Two integrated tools constitute the main deliverables of this workflow: 1) a risk assessment module, which quantifies the likelihood of leakage by analyzing vascular and tissue features in CT scans, and 2) a Content-Based Medical Image Retrieval (CBMIR) module, which identifies and displays similar historical cases to support evidence-based surgical decision making. The protocol paper requires close collaboration between hospitals and universities; this protocol demonstrates that such a system is technically feasible and clinically implementable within existing healthcare infrastructures. By following the proposed methodological stages and regulatory principles, other institutions can reproduce this workflow to develop analogous decision-support tools. Ultimately, this interdisciplinary framework aims to enhance surgical planning, reduce leak incidence, and contribute to a broader paradigm shift toward explainable, data-driven precision surgery.","authors":["Zahra Tabatabaei","Jon Sporring","Mark Bremholm Ellebæk","Alaa El-Hussuna"],"published":"2026-06-01T12:20:43Z","updated":"2026-06-01T12:20:43Z","abstract_url":"https://arxiv.org/abs/2606.02156v1","html_url":"https://arxiv.org/html/2606.02156v1","pdf_url":"https://arxiv.org/pdf/2606.02156v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02153v1","title":"Ultra Diffusion Poser: Diffusion-Based Human Motion Tracking From Sparse Inertial Sensors and Ranging-Based Between-Sensor Distances","abstract":"Methods using inertial measurement units (IMUs) provide a wearable alternative to camera-based motion capture. To mitigate drift from inertial signals, recent sparse inertial pose estimators integrate inter-sensor distances measured by ultra-wideband (UWB) ranging. So far, UWB distances have only been used as an additional input feature, ignoring the physical constraints they impose on sensor positions. However, these distances can also be used to reconstruct the underlying 3D sensor layout, which in turn provides more informative input for pose reconstruction. We propose Ultra Diffusion Poser, a diffusion model that explicitly models these geometric constraints. It includes a Spatial Layout Module that analytically reconstructs the 3D sensor positions from UWB measurements. These sensor positions are used alongside IMU signals and UWB distances as a conditioning signal during diffusion. Still, network predictions can violate inter-sensor distance measurements. To address this, we introduce UWB-Diffusion Guidance, which encourages alignment between predicted poses and measured distances during diffusion sampling. Together, these contributions enable our model to achieve state-of-the-art performance, reducing joint position error by up to 22% over prior work.","authors":["Dominik Hollidt","Tommaso Bendinelli","Christian Holz"],"published":"2026-06-01T12:20:31Z","updated":"2026-06-01T12:20:31Z","abstract_url":"https://arxiv.org/abs/2606.02153v1","html_url":"https://arxiv.org/html/2606.02153v1","pdf_url":"https://arxiv.org/pdf/2606.02153v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02129v1","title":"Equilibrated Diffusion: Frequency-aware Textual Embedding for Equilibrated Image Customization","abstract":"Image customization learns target subjects from reference concept images and generates conditioned images per text prompts, mainly modifying styles or backgrounds. Prevailing methods adopt fine-tuning to pack diverse concept attributes into a unified latent embedding, yet entangled attributes hinder elimination of irrelevant disturbances from style and background. To address this issue, we propose Equilibrated Diffusion, a frequency-driven approach that disentangles tangled concept features for balanced customization and consistent text-visual matching. Unlike conventional methods learning full concepts with shared embeddings and unified tuning, our work utilizes the inherent link between image frequency components and semantics: low frequencies represent subject content and high frequencies correspond to styles. We decompose concepts in frequency space and optimize each embedding independently. This separate optimization enables the denoiser to capture style detached from subject identity and generalize better to unseen stylistic prompts. Merging multi-frequency embeddings preserves the model's original spatial customization ability. We further deploy mask-guided diffusion to restrict irrelevant background changes and boost text alignment. Residual Reference Attention (RRA) is inserted into spatial attention to retain subject structure and identity consistency. Experiments prove Equilibrated Diffusion exceeds mainstream baselines on subject fidelity and text adherence, verifying our method's superiority.","authors":["Liyuan Ma","Xueji Fang","Guo-Jun Qi"],"published":"2026-06-01T11:57:10Z","updated":"2026-06-01T11:57:10Z","abstract_url":"https://arxiv.org/abs/2606.02129v1","html_url":"https://arxiv.org/html/2606.02129v1","pdf_url":"https://arxiv.org/pdf/2606.02129v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02120v1","title":"Understanding-Enhanced Model Collaboration for Long-Tailed Egocentric Mistake Detection","abstract":"In this report, we address the problem of determining whether a user performs an action incorrectly from egocentric video data. To this end, we propose an Understanding-Enhanced Model Collaboration Method (UE-MCM) that combines efficient coarse-grained video understanding with accurate fine-grained action reasoning. Specifically, UE-MCM contains a small model branch and a large model branch. The large model branch focuses on whether the fine-grained action itself is executed incorrectly, while the small model branch jointly takes the coarse-grained video and fine-grained segment as input to identify actions that may be locally correct but inconsistent with the overall workflow. The small model branch is built on a CLIP4CLIP video encoder initialized from a CLIP model enhanced by Diffusion Contrastive Reconstruction, and the large model branch uses the Qwen3-VL Embedding model to extract high-capacity representations from fine-grained action segments. The small-branch prediction and the large-branch prediction are then adaptively fused by a lightweight collaboration gate. To handle the long-tailed distribution of mistake instances, we optimize the classifiers with complementary objectives, including reweighted cross-entropy, AUC-oriented learning, and label-aware adjustment. The resulting system balances speed and accuracy, making it effective for detecting subtle, rare, and ambiguous mistakes in egocentric instructional videos.","authors":["Boyu Han","Qianqian Xu","Shilong Bao","Zhiyong Yang","Ruochen Cui","Qingming Huang"],"published":"2026-06-01T11:50:16Z","updated":"2026-06-01T11:50:16Z","abstract_url":"https://arxiv.org/abs/2606.02120v1","html_url":"https://arxiv.org/html/2606.02120v1","pdf_url":"https://arxiv.org/pdf/2606.02120v1.pdf","matched_keywords":["video","representation","instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02111v1","title":"Jailbreaking Multimodal Large Language Models using Multi-Clip Video","abstract":"As multimodal large language models (MLLMs) have advanced to process video inputs, concerns have emerged about their potential for malicious misuse. Prior jailbreak studies have shown that safety alignment in MLLMs can be bypassed through visual inputs, yet it remains unclear which properties of video inputs induce this vulnerability. To address this gap, we introduce Multi-Clip Video (MCV) SafetyBench, a dataset of 2,920 videos designed to evaluate how the diversity of video inputs affects the vulnerability of MLLMs. Each video consists of multiple short clips depicting diverse contexts related to a harmful query. Experiments on eight representative video MLLMs show that attack success consistently increases with the number of clips. Our results further indicate that the video modality is (1) more vulnerable than the image modality, (2) more vulnerable to dynamic videos than to static videos, and (3) more vulnerable when videos contain more diverse contexts. Building on these findings, we propose a defense strategy that leverages the relative robustness of the image modality.","authors":["Choongwon Kang","Seungjong Sun","Hyunmin Jun","Jang Hyun Kim"],"published":"2026-06-01T11:43:53Z","updated":"2026-06-01T11:43:53Z","abstract_url":"https://arxiv.org/abs/2606.02111v1","html_url":"https://arxiv.org/html/2606.02111v1","pdf_url":"https://arxiv.org/pdf/2606.02111v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02105v1","title":"Multimodal Action Diffusion for Robust End-to-End Autonomous Driving","abstract":"End-to-End Autonomous Driving (E2E-AD) systems have largely converged on predicting intermediate trajectory waypoints, delegating final control to hand-crafted controllers with GPS access. Direct control-signal prediction (outputting throttle, steer and brake in an end-to-end fashion) remains underexplored, and critically, the role of action multimodality in such systems is not well understood. We argue that moving beyond deterministic, single-action outputs is not merely a modelling choice, but a key driver of driving performance, representational quality, and training stability. To validate this, we introduce the Action Diffusion Transformer (ADT), an anchor-free diffusion transformer trained with a MSE objective that natively models the multimodal distribution of plausible driving actions. Rather than committing to a single deterministic command, ADT generates K action candidates and selects the most suitable one at inference via Nearest Neighbour Matching (NNM). Beyond strong benchmark numbers, we show that action multimodality yields measurable benefits in learned representations and behavioral consistency, effects that deterministic architectures cannot replicate. ADT surpasses previous state-of-the-art on the challenging closed-loop Bench2Drive benchmark while achieving ten times lower latency, demonstrating that expressive, multimodal action modelling is both practically efficient and conceptually essential for robust end-to-end driving.","authors":["Jorge Daniel Rodríguez-Vidal","Diego Porres","Gabriel Villalonga Pineda","Antonio M. López Peña"],"published":"2026-06-01T11:35:35Z","updated":"2026-06-01T11:35:35Z","abstract_url":"https://arxiv.org/abs/2606.02105v1","html_url":"https://arxiv.org/html/2606.02105v1","pdf_url":"https://arxiv.org/pdf/2606.02105v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02096v1","title":"WebSpline: Structure-Informed Splines for Real-Time 3D Gaussians from Monocular Videos","abstract":"Dynamic scene reconstruction from monocular videos remains highly challenging, as existing methods often struggle to balance global structural coherence and local fine-grained details under limited multi-view cues. To address this challenge, we propose WebSpline, a novel dynamic 3D Gaussian framework that enables structurally coherent and high-fidelity reconstruction from monocular videos with fast rendering. The core of WebSpline is the Structure-Informed Spline (SIS) representation, which models each dynamic Gaussian trajectory using a learnable cubic Hermite spline whose motion is structurally organized with an auxiliary Structural Proxy Graph (SPG). The proposed framework is optimized in two stages: (i) in the first stage, the SPG is initialized from 2D point tracks and refined with temporal rigidity regularization to establish structural coherence for moving objects across the sequence; and (ii) in the second stage, the SIS representation is initialized from the refined SPG and optimized under both spatial and structural neighborhood constraints. At inference, Gaussian motion is obtained solely by evaluating the learned SIS, enabling fast rendering. Extensive experiments on the challenging monocular dynamic scene benchmarks, iPhone and NVIDIA, demonstrate that our WebSpline achieves state-of-the-art rendering quality while rendering over 10 times faster than WorldTree, the second-best method on the iPhone dataset.","authors":["Jongmin Park","Jeonghwan Yun","Minh-Quan Viet Bui","Munchurl Kim"],"published":"2026-06-01T11:28:17Z","updated":"2026-06-01T11:28:17Z","abstract_url":"https://arxiv.org/abs/2606.02096v1","html_url":"https://arxiv.org/html/2606.02096v1","pdf_url":"https://arxiv.org/pdf/2606.02096v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02090v1","title":"FocusDiT: Masking Queries in Diffusion Transformers for Fine-grained Image Generation","abstract":"Diffusion transformer (DiT) has been widely adopted in the generative diffusion field, advancing the denoising of query tokens through attention and Feed-Forward (\\text{FFN}) layers. FFN actually acts as the key-value vocabulary for decoding visual contents where the value embeds the visual semantical knowledge. We present that focusing on critical query tokens corresponding to more complex details and encouraging the model to improve these tokens is essential for fine-grained visual generation. To this end, we propose FocusDiT, which applies a Masking scheme to focus on critical query tokens that are exclusively fed into FFN. The masked queries can retrieve visual tokens from the FFN vocabularies, and use them to decode their visual details. Extensive text-to-image experiments validate the effectiveness of token masking in enhancing generative performance.","authors":["Xueji Fang","Liyuan Ma","Jianhao Zeng","Jinjin Cao","Mingyuan Zhou","Guo-Jun Qi"],"published":"2026-06-01T11:18:11Z","updated":"2026-06-01T11:18:11Z","abstract_url":"https://arxiv.org/abs/2606.02090v1","html_url":"https://arxiv.org/html/2606.02090v1","pdf_url":"https://arxiv.org/pdf/2606.02090v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02080v1","title":"Agentic-J: An AI Agent for Biological Microscopy Image Analysis","abstract":"Biological image analysis increasingly demands integration across heterogeneous tools, programming environments, and domain knowledge that few researchers can command simultaneously. We present Agentic-J, a containerised, multi-agent AI assistant, primarily for ImageJ/Fiji that enables biologists to specify analysis tasks in natural language, from nuclei segmentation and cell tracking to multi-condition quantification. The agent generates executable scripts organised into a documented project structure, so every analysis decision is traceable and the workflow can be reproduced or shared. The specialised sub-agents handle plugin management, code generation, debugging, quality assurance, and statistical reporting. In this paper we introduce the system's design, demonstrate real biological microscopy image analysis workflows, and detailed the technical implementation.","authors":["Lukas Johanns","Marilin Moor","Davide Panzeri","Yu Zhou","Xinyi Chen","Nora F. K. Pauly","Zixuan Pan","Matthias Gunzer","Andreas Müller","Yiyu Shi","Hedi Peterson","Jianxu Chen"],"published":"2026-06-01T11:10:28Z","updated":"2026-06-01T11:10:28Z","abstract_url":"https://arxiv.org/abs/2606.02080v1","html_url":"https://arxiv.org/html/2606.02080v1","pdf_url":"https://arxiv.org/pdf/2606.02080v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02068v1","title":"Fast and Lightweight Novel View Synthesis with Differentiable Multiplane Image","abstract":"Recently, novel view synthesis has witnessed remarkable progress, with mainstream methods such as Neural Radiance Fields (NeRF) and 3D Gaussian Splatting (3DGS) delivering impressive results. However, these approaches often struggle to balance rendering speed and model size, and their optimization-based training can be highly time-consuming. Furthermore, they typically rely on dense observations, often failing to produce satisfactory results under sparse-view conditions. Although feed-forward reconstruction significantly reduces the optimization time of 3DGS, its pixel-aligned formulation generates millions of Gaussians from a single image, severely limiting its practical deployment on mobile devices. To address these limitations, we revisit the Multiplane Image(MPI) representation, which represents scenes using a compact set of planar layers for efficient novel view synthesis. Leveraging recent advances in visual foundation models, we utilize predicted point maps for reliable geometric initialization, followed by differentiable optimization. To address the issues of holes and artifacts in sparsely initialized MPI, we introduce one-step diffusion, which participates in both the differentiable optimization of MPI and the postprocessing of rendering results. Compared with a representative GS-based method, our approach is 30.7% faster and uses only 14.8% of its model size, while achieving competitive synthesis quality on front-view scenarios","authors":["Kaidi Zhang","Guanxu Zhu"],"published":"2026-06-01T10:57:53Z","updated":"2026-06-01T10:57:53Z","abstract_url":"https://arxiv.org/abs/2606.02068v1","html_url":"https://arxiv.org/html/2606.02068v1","pdf_url":"https://arxiv.org/pdf/2606.02068v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02058v1","title":"TIDES: Time-Derivative Event Simulation via Deformable Reconstruction","abstract":"Event cameras emit asynchronous events in response to environmental appearance changes. The scarcity of real-world event datasets makes simulation essential. However, most simulators infer event timestamps from frame sequences, forcing many threshold crossings to share a small set of discrete times; a failure mode we term timestamp batching that worsens under fast motion and occlusion. We present TIDES, a continuous-time event simulator built on dynamic Gaussian splatting. Because TIDES operates on an explicit 3D scene representation with learnt geometry and motion, it can derive per-pixel intensity dynamics directly from the scene, rather than by differencing rendered frames. This enables accurate threshold-crossing prediction, including multiple crossings per rendering step, without temporal upsampling or frame interpolation. The same 3D scene model reveals where objects partially occlude one another; TIDES uses this to guide adaptive time stepping, concentrating computation only in regions where occlusion dynamics make simple models of brightness change unreliable. Finally, we model finite sensor bandwidth using a tile-level arbiter whose throughput, jitter, and event drops reproduce realistic sensor artifacts. Across paired RGB-event benchmarks, TIDES attains state-of-the-art event-stream fidelity. We also show that events simulated by TIDES transfer more effectively to real downstream tasks than competitors'.","authors":["Christopher Thirgood","Dipon Kumar Ghosh","Simon Hadfield"],"published":"2026-06-01T10:49:13Z","updated":"2026-06-01T10:49:13Z","abstract_url":"https://arxiv.org/abs/2606.02058v1","html_url":"https://arxiv.org/html/2606.02058v1","pdf_url":"https://arxiv.org/pdf/2606.02058v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02042v1","title":"Normality-Preserving Continual Industrial Anomaly Detection via Orthogonal LoRA Banks","abstract":"Continual industrial anomaly detection with diffusion models suffers from historical normality prior drift and catastrophic forgetting. Existing continual diffusion methods preserve previous knowledge through replay or constrained optimization, but they lack an explicit mechanism for isolating and protecting category-specific normality priors during sequential adaptation. Although low-rank adaptation provides modular residual updates, standard LoRA neither freezes historical normality subspaces nor prevents new adapters from interfering with previous ones. To address this issue, we propose a normality-preserving continual anomaly detection framework based on two modules: History Frozen Orthogonal LoRA Bank (HF-OLB) and Hierarchical Novelty Adaptive Bank Growth module (HNABG). HF-OLB freezes both the pre-trained U-Net backbone and the learned LoRA banks, and constrains new task-specific normality residuals to the orthogonal complement of historical LoRA subspaces. HNABG further allocates layer-dependent residual capacity and expands the bank only when the residual normality novelty exceeds the expressive capacity of existing banks. Extensive experiments on MVTec and VisA demonstrate the effectiveness of the proposed method. On the challenging VisA 2x6 setting, our method achieves 83.6/91.8 image and pixel level A-AUROC with 3.8/3.9 FM, improving pixel level A-AUROC over the state of the art by 3.2 points while reducing pixel level FM by 1.3. These results show that our method effectively preserves historical normality priors in long horizon continual category sequences.","authors":["Weibai Fang","Haijun Che","Feiyang Ren","Qiancheng Lao"],"published":"2026-06-01T10:30:42Z","updated":"2026-06-01T10:30:42Z","abstract_url":"https://arxiv.org/abs/2606.02042v1","html_url":"https://arxiv.org/html/2606.02042v1","pdf_url":"https://arxiv.org/pdf/2606.02042v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02031v1","title":"OpenWebRL: Demystifying Online Multi-turn Reinforcement Learning for Visual Web Agents","abstract":"Building capable visual web agents requires long-horizon reasoning, precise grounding, and robust interaction with dynamic real-world websites. Despite rapid progress, the strongest systems remain largely proprietary, while open agents still depend heavily on supervised post-training over large collections of curated web trajectories. This dependence creates a major scalability bottleneck: high-quality demonstrations are expensive to collect, and static datasets offer limited coverage of the diverse, ever-changing open web. Although online RL has shown promise for text-based agents, its potential for training visual web agents directly on live websites remains largely underexplored. In this paper, we introduce OpenWebRL, an open framework for training visual web agents with online multi-turn RL on real websites. OpenWebRL covers the full training pipeline, including scalable live-browser infrastructure, supervised initialization, multimodal context management, trajectory-level success judging, and efficient multi-turn policy optimization. Using this framework, we train OpenWebRL-4B, which establishes a new open-source state of the art on challenging live-web benchmarks. With only 0.4K initialization trajectories and 2.2K open-ended RL training tasks, OpenWebRL-4B achieves 67.0% success on Online-Mind2Web and 64.0% on DeepShop, outperforming prior open agents of similar or larger scale and remaining competitive with proprietary systems including OpenAI CUA and Gemini CUA. Beyond strong benchmark performance, we systematically study the key design choices that make online RL effective for visual web agents, and analyze how RL improves agentic reasoning. Overall, our work offers a practical path toward building more capable, reproducible, and cost-efficient open web agents. We will release our training data, models, and code to support future research.","authors":["Rui Yang","Qianhui Wu","Yuxi Chen","Hao Bai","Wenlin Yao","Hao Cheng","Baolin Peng","Huan Zhang","Tong Zhang","Jianfeng Gao"],"published":"2026-06-01T10:20:10Z","updated":"2026-06-01T10:20:10Z","abstract_url":"https://arxiv.org/abs/2606.02031v1","html_url":"https://arxiv.org/html/2606.02031v1","pdf_url":"https://arxiv.org/pdf/2606.02031v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02021v1","title":"PerBite: A Curated Diagnostic Workflow for Bite-Aware Food Volume Estimation","abstract":"Can a visually plausible food mesh be trusted to estimate the volume of consumed food? \\method investigates this question using selected paired before- and after-consumption states from the MetaFood CVPR 2026 Continuous 3D Reconstruction While Eating Challenge. The submitted workflow follows a curated reconstruction protocol: SAM~3 segments the food and plate regions; Hunyuan3D/SAM~3D generates a dimensionless food mesh; the plate diameter provides the metric scale; the plate geometry is removed in Blender; and the remaining mesh is hole-filled, made watertight, and integrated to estimate volume. MoGe-2 is used only as an auxiliary cue for initial dish-diameter estimation when direct plate measurement is uncertain; it is not the primary scale source for the reported challenge result. \\method ranks first, with an average Chamfer distance of 8.31 across 34 meshes using rigid ICP without scale correction. On 17 before- and after-pairs, it achieves 33.87\\% state-level volume MAPE and zero monotonicity violations, while consumed-volume MAPE remains 53.74\\%. The results show that surface reconstruction, metric scale, controlled mesh cleanup, watertight volume integration, and physical depletion consistency should be evaluated separately for dietary assessment. Source code and evaluation scripts will be available at \\href{https://github.com/GCVCG/PerBite-CVPR-MetaFood-2026}{github.com/GCVCG/PerBite-CVPR-MetaFood-2026}.","authors":["Ahmad AlMughrabi","Farid Al-Areqi","David Fernández Gómez","Umair Haroon","Marc Bolaños","Ricardo Marques","Petia Radeva"],"published":"2026-06-01T10:11:15Z","updated":"2026-06-01T10:11:15Z","abstract_url":"https://arxiv.org/abs/2606.02021v1","html_url":"https://arxiv.org/html/2606.02021v1","pdf_url":"https://arxiv.org/pdf/2606.02021v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.02000v1","title":"Towards 3D-Aware Video Diffusion Models: Render-Free Human Motion Control with Mesh Tokenization","abstract":"Diffusion models have shown remarkable success in video generation. However, whether such models are truly aware of the 3D structure underlying visual observations, rather than simply reproducing plausible 2D projections, remains an open question. In this work, we investigate this question through human motion control, a task that requires precise modelling of 3D human geometry, motion, camera viewpoint, and scene context. Unlike prior methods that rely on rendered 2D motion guidance videos, we propose a render-free framework that conditions video generation directly on compressed 3D human mesh tokens. This representation preserves full 3D geometric information while enabling a unified token-based generation pipeline that processes video tokens jointly with motion tokens in a DiT-based architecture. This design requires the model to reason jointly about appearance, 3D structure, and camera viewpoint during video generation. Experimental results demonstrate strong performance on human motion control benchmarks, while reducing artifacts induced by view-dependent 2D guidance and trajectory-pose mismatches during editing. These findings suggest that video diffusion models, when equipped with mesh tokenization, can better capture complex 3D human structures and their interactions with the surrounding environment.","authors":["Jingyun Liang","Min Wei","Shikai Li","Yizeng Han","Hangjie Yuan","Lei Sun","Weihua Chen","Fan Wang"],"published":"2026-06-01T09:56:48Z","updated":"2026-06-01T09:56:48Z","abstract_url":"https://arxiv.org/abs/2606.02000v1","html_url":"https://arxiv.org/html/2606.02000v1","pdf_url":"https://arxiv.org/pdf/2606.02000v1.pdf","matched_keywords":["video","3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01992v1","title":"A Structured Benchmark for Text-Guided Anomaly Detection: When Language Stops Conditioning the Decision","abstract":"Industrial anomaly detection has historically been a unimodal task. Recent multimodal vision-language models have produced systems that admit textual input alongside the image and are presented as enabling text-guided zero- and few-shot inspection. Yet these methods are evaluated with protocols inherited from unimodal benchmarks that hold the textual condition constant and therefore cannot measure whether language conditions the decision; whether reported gains reflect text guidance or strong pretrained visual features remains open. We introduce Text-Guided Anomaly Detection (TGAD), a structured benchmark that progressively increases the functional role of language across three scenarios: a controlled prompt-sensitivity setting on MVTec AD; a component-tagged extension of MVTec AD that requires the model to restrict its assessment to an instructed part; and the new Assembled Panel Dataset (APD), a realistic industrial setting that requires both defect-type and component-location knowledge. We evaluate one representative model per paradigm: generative large vision-language, training-free discriminative, and embedding-adaptive discriminative. In all three, the textual interface conditions the decision only superficially: prompt content is absorbed unless the object noun is removed (the generative model's I-AUROC drops from 97.4 to 82.6); component-level instructions do not constrain the decision once defects outside the instructed part are admitted as normal (from 90.3 to 66.3); and when both combine on APD, image-level discrimination collapses below the MVTec level, in one case below chance (71.2, 50.5, 31.5). These results suggest that standard benchmarks overstate the text-guided capabilities of current multimodal anomaly detection systems, and that a protocol of this kind is a prerequisite for models that can be reliably controlled through language for industrial deployment.","authors":["Stefano Samele","Eugenio Lomurno","Teodora Jovanovic","Sanjay Shivakumar Manohar","Alberto Crivellaro","Matteo Matteucci"],"published":"2026-06-01T09:50:30Z","updated":"2026-06-01T09:50:30Z","abstract_url":"https://arxiv.org/abs/2606.01992v1","html_url":"https://arxiv.org/html/2606.01992v1","pdf_url":"https://arxiv.org/pdf/2606.01992v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01955v1","title":"WALL-WM: Carving World Action Modeling at the Event Joints","abstract":"WALL-WM is a World Action Model that shifts video-action learning from chunk-centric optimization to event-grounded Vision-Language-Action pretraining, using semantically coherent action events as the atomic unit of learning. Existing WAMs commonly initialize from multimodal or video foundation models and then optimize fixed-length action chunks conditioned directly on the current observation and instruction. Although convenient, this chunk-centric formulation creates a fundamental granularity mismatch. Language describes semantic goals and events, vision evolves through continuous scene dynamics, and actions operate at control-level timescales; forcing all three into the same fixed-length prediction window turns VLA training into short-horizon correlation fitting. WALL-WM addresses this mismatch by organizing both supervision and data around semantic events. Specifically, it pairs event-grounded VLA pretraining with a data ecosystem built from event-level captions and cluster-balanced sampling, enabling scalable learning over diverse behaviors, scenes, and task structures. From the same event-pretrained backbone, WALL-WM supports two complementary inference modes. The event mode consumes next-event descriptions and enables variable-length execution chunks, while the unified mode uses a VLM with Staircase Decoding to condition conventional fixed-length chunk inference while preserving a gradient-continuous VLA path. Together with Muon-optimizer-based large-scale pretraining infrastructure, WALL-WM provides a practical scale-up recipe for general-purpose WAMs. Experiments show that WALL-WM generalizes broadly across language, scenes, and tasks, achieving state-of-the-art performance in large-scale real-world generalization evaluation.","authors":["Shalfun Li","Victor Yao","Charles Yang","Truth Qu","Regis Cheng","Ryan Yu","Howard Lu","Newton Von","Vincent Chen","Yohann Tang","Maeve Zhang","Ellie Ma","Gody Li","Sage Yang","Lorien Shu","J. W. Gao","Ethan Chen","Colin Ye","Yu Sun","Elise Mon","PS Zhang","Neo Li","Lily Li","James Wang","Ping Yang","Chris Pan","Lucy Liang","Hang Su","Roy Gan","Hao Wang","Qian Wang"],"published":"2026-06-01T09:14:51Z","updated":"2026-06-01T09:14:51Z","abstract_url":"https://arxiv.org/abs/2606.01955v1","html_url":"https://arxiv.org/html/2606.01955v1","pdf_url":"https://arxiv.org/pdf/2606.01955v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01950v1","title":"Learning Action-Conditional and Object-Centric Gaussian Splatting World Models for Rigid Objects","abstract":"World models enable intelligent agents to predict the consequences of their actions on the environment. In this paper, we propose Multi Rigid Object Gaussian World Model (MRO-GWM), a novel model that learns action-conditional dynamics of rigid objects in 3D. By representing the scene by object-centric Gaussians, we can represent arbitrary object shapes and multi-object scenes. We develop a novel spatio-temporal transformer architecture that predicts future rigid body motion from a history of object Gaussians and future actions. Objects are represented by their Gaussians in a canonical frame, which allows for describing object motion as rigid body transformation. Our model is trained on reconstructions from multiple viewpoints, which requires the model to handle partial observations of objects due to occlusions. We analyze prediction performance of our approach on synthetic datasets composed of typical household objects with multi-object dynamics and interactions by a robot end effector. We also evaluate our model in model-predictive control for non-prehensile manipulation in simulation.","authors":["Jens U. Kreber","Lukas Mack","Joerg Stueckler"],"published":"2026-06-01T09:12:07Z","updated":"2026-06-01T09:12:07Z","abstract_url":"https://arxiv.org/abs/2606.01950v1","html_url":"https://arxiv.org/html/2606.01950v1","pdf_url":"https://arxiv.org/pdf/2606.01950v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01947v1","title":"Parameter-Efficient Fine-Tuning of Large Pretrained Models for Instance Segmentation Tasks","abstract":"Research and applications in artificial intelligence have recently shifted with the rise of large pretrained models, which deliver state-of-the-art results across numerous tasks. However, the substantial increase in parameters introduces a need for parameter-efficient training strategies. Despite significant advancements, limited research has explored parameter-efficient fine-tuning (PEFT) methods in the context of transformer-based models for instance segmentation. Addressing this gap, this study investigates the effectiveness of PEFT methods, specifically adapters and Low-Rank Adaptation (LoRA), applied to two models across four benchmark datasets. Integrating sequentially arranged adapter modules and applying LoRA to deformable attention--explored here for the first time--achieves competitive performance while fine-tuning only about 1-6% of model parameters, a marked improvement over the 40-55% required in traditional fine-tuning. Key findings indicate that using 2-3 adapters per transformer block offers an optimal balance of performance and efficiency. Furthermore, LoRA, exhibits strong parameter efficiency when applied to deformable attention, and in certain cases surpasses adapter configurations. These results show that the impact of PEFT techniques varies based on dataset complexity and model architecture, underscoring the importance of context-specific tuning. Overall, this work demonstrates the potential of PEFT to enable scalable, customizable, and computationally efficient transfer learning for instance segmentation tasks.","authors":["Nermeen Abou Baker","David Rohrschneider","Uwe Handmann"],"published":"2026-06-01T09:09:32Z","updated":"2026-06-01T09:09:32Z","abstract_url":"https://arxiv.org/abs/2606.01947v1","html_url":"https://arxiv.org/html/2606.01947v1","pdf_url":"https://arxiv.org/pdf/2606.01947v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01945v1","title":"Beyond Low-Rank: Low-Rank Sparse Prompting via Spiking Neural Network and Prompt Factorization","abstract":"Visual Prompting (VP) has emerged as an efficient paradigm for adapting large-scale pre-trained vision models to downstream tasks by incorporating learnable prompts at the input level. However, existing VP methods typically employ dense pixel-level prompts, which often suffer from redundant perturbations, limited generalization and energy inefficiency. To overcome these limitations, we propose to integrate brain-inspired spiking learning into visual prompt learning tasks. As we know that spiking neuron can perform inexpensive information processing by transmitting the input data into discrete spike trains and return sparse outputs. Inspired by this, we propose \\textbf{Lo}w-\\textbf{R}ank visual \\textbf{S}pike \\textbf{P}rompting (LoRSP), a novel framework that learns dynamic low-rank sparse visual prompts naturally via a Spiking neuron learning mechanism. The core idea of LoRSP is to exploit the brain-inspired sparse firing mechanism of spiking neurons to generate pixel-level sparse prompt for each instance. To be specific, we first construct a series of prompt factors via low-rank factorization to capture distinct prompt subspaces. These prompt factors are then fed into an SNN architecture, which performs the integrate-and-fire process to emit spikes. As a result, our LoRSP generates a \\emph{sparse} visual prompt while maintaining the low-rank constraint. This design enables instance-specific selective prompting, leading to more compact and robust adaptation across diverse downstream tasks. Extensive experiments on five heterogeneous vision backbones and multiple benchmarks demonstrate that LoRSP achieves competitive performance while requiring fewer tunable parameters compared to existing VP methods.","authors":["Yumiao Zhao","Bo Jiang","Beibei Wang","Xixi Wan","Xiao Wang","Jin Tang"],"published":"2026-06-01T09:08:34Z","updated":"2026-06-01T09:08:34Z","abstract_url":"https://arxiv.org/abs/2606.01945v1","html_url":"https://arxiv.org/html/2606.01945v1","pdf_url":"https://arxiv.org/pdf/2606.01945v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"},{"id":"2606.01940v1","title":"SCAPO: Self-Supervised Category-Level Articulated Pose Estimation from a Single 3D Observation","abstract":"Existing methods for category-level object articulation from a single 3D observation often rely on dense supervision, multi-frame inputs, or CAD templates, and still struggle to disentangle geometry from articulation or to recover explicit joint parameters. We propose SCAPO, a self-supervised framework that estimates canonical geometry, rigid part segmentation, and joint pivots, axes, and articulation states from a single RGB-D observation without ground-truth labels or category-specific models. Our SCAPO first uses an SE(3)-equivariant vector-neuron autoencoder to factor out global pose and align diverse instances into a shared canonical space. On this aligned shape, a joint-aware blend-skinning module is then designed to model part motion. We learn this representation through cycle reconstruction between observed and canonical shapes and cross-space alignment with a learnable canonical template that decouples shared category geometry from instance-specific residual shape. Experiments on synthetic and real articulated-object datasets show that our SCAPO recovers consistent part structure and accurate articulation parameters and outperforms all self-supervised baselines.","authors":["Can Zhang","Gim Hee Lee"],"published":"2026-06-01T09:04:49Z","updated":"2026-06-01T09:04:49Z","abstract_url":"https://arxiv.org/abs/2606.01940v1","html_url":"https://arxiv.org/html/2606.01940v1","pdf_url":"https://arxiv.org/pdf/2606.01940v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-02T05:27:12+00:00","last_seen_at":"2026-06-02T05:27:12+00:00"}],"tracked_paper_count":75,"storage_mode":"latest_overwrite"}};
